// 조선초상화 이미지 경로 헬퍼 — joseon (1)~(66).png 일괄 매핑
// id 1~60 = joseon (1~60).png, "E1"~"E6" = joseon (61~66).png
function joseonImg(id:number|string):string{
  if(typeof id==="string"&&/^E[1-6]$/.test(id)){
    return`/joseon-portraits/joseon (${60+parseInt(id.slice(1))}).png`;
  }
  const n=typeof id==="number"?id:parseInt(String(id));
  if(!isNaN(n)&&n>=1&&n<=60)return`/joseon-portraits/joseon (${n}).png`;
  return`/joseon-portraits/joseon (1).png`; // fallback
}
