// 전생운세: 생년월일 → 오행 → 유형 매칭 (AI 없이 로컬 연산)
function getPastLifeType(name:string,year:number,month:number,day:number,hour?:number){
  // v806(Phase2): 가짜 Date-diff 일간 → 정확한 단일 엔진 일간(한자)으로 교체
  const ilgan=computeSaju(`${year}-${month}-${day}`,hour!=null?String(hour):null).ilganHj;
  // 일간 → 오행
  const mapping=PAST_LIFE.ganji_mapping as Record<string,string>;
  const ohaeng=mapping[ilgan]||"木";
  // 오행 → type_ids
  const system=PAST_LIFE.ohaeng_system as Record<string,number[]>;
  const typeIds=system[ohaeng]||[1,2,3,4,5];
  // 이름 음절 수 + 시간으로 최종 1개 선택
  const nameLen=name.replace(/\s/g,"").length||1;
  const hourVal=hour||0;
  const idx=(nameLen+hourVal+day)%typeIds.length;
  const typeId=typeIds[idx];
  const result=(PAST_LIFE.types as any[]).find(t=>t.id===typeId)||(PAST_LIFE.types as any[])[0];
  return {...result,ilgan,ohaeng};
}
