// 오늘의 타로: 날짜 기반 고정 카드 (매일 바뀜)
const _todayTarotIdx = ((_d:Date)=>{const seed=_d.getFullYear()*10000+(_d.getMonth()+1)*100+_d.getDate();return seed%78;})(new Date());
const _todayTarot = TAROT_78[_todayTarotIdx];

const _d=new Date();const _dayNames=["일요일","월요일","화요일","수요일","목요일","금요일","토요일"];

// 날짜 시드 RNG (수호기운, 로또 등 매일 자정 갱신용)
// 주의: _d 는 모듈 로드 시점 고정값. 매일 갱신을 원하면 _todaySeedNow()/_dayPickNow() 사용
const _todaySeed=_d.getFullYear()*10000+(_d.getMonth()+1)*100+_d.getDate();
function _todaySeedNow(){const d=new Date();return d.getFullYear()*10000+(d.getMonth()+1)*100+d.getDate();}
// v373: 시드 mixing 강화 — 날짜 +1 차이로도 결과가 충분히 달라지도록 golden-ratio 곱 + warmup
// (이전 버그: 매일 같은 음식·동물이 뽑히던 문제 — _todaySeed+salt 차이가 1뿐이라 LCG 첫 출력이 거의 동일했음)
function _mixSeed(seed:number,salt:number):number{
  // 황금비 상수로 곱하면 비트 분산이 좋아짐
  let s=((seed^0x9E3779B1)*(salt+1|0))>>>0;
  s=((s*0x85EBCA77)^(s>>>13))>>>0;
  s=((s*0xC2B2AE3D)^(s>>>16))>>>0;
  return s||1;
}
function _dayRng(salt:number=0){
  let s=_mixSeed(_todaySeed,salt);
  // warmup
  for(let i=0;i<5;i++)s=(s*1664525+1013904223)>>>0;
  return()=>{s=(s*1664525+1013904223)>>>0;return s/0x100000000;};
}
function _dayRngNow(salt:number=0){
  let s=_mixSeed(_todaySeedNow(),salt);
  for(let i=0;i<5;i++)s=(s*1664525+1013904223)>>>0;
  return()=>{s=(s*1664525+1013904223)>>>0;return s/0x100000000;};
}
function _dayPick<T>(arr:T[],salt:number):T{const r=_dayRng(salt);return arr[Math.floor(r()*arr.length)];}
function _dayPickNow<T>(arr:T[],salt:number):T{const r=_dayRngNow(salt);return arr[Math.floor(r()*arr.length)];}
function _computeTodayLucky(){
  const c=_dayPickNow(_LUCKY_COLOR_POOL,1);
  const a=_dayPickNow(_LUCKY_ANIMAL_POOL,6);
  return{
    color:c.name,colorHex:c.hex,
    number:_dayPickNow(_LUCKY_NUMBER_POOL,2),
    direction:_dayPickNow(_LUCKY_DIR_POOL,3),
    time:_dayPickNow(_LUCKY_TIME_POOL,4),
    food:_dayPickNow(_LUCKY_FOOD_POOL,5),
    animal:a.n,animalEmoji:a.e,
    energy:_dayPickNow(_LUCKY_ENERGY_POOL,7),
  };
}
