// 매일 자정 자동 갱신되는 수호 기운 스트립
function DailyGuardianStrip(){
  const[lk,setLk]=useState(()=>_computeTodayLucky());
  useEffect(()=>{
    // v257: 마운트 시 강제 재컴퓨트 (SSR/CSR seed 미스매치 + SW 캐시된 빌드 우회)
    setLk(_computeTodayLucky());
    let curSeed=_todaySeedNow();
    const t=setInterval(()=>{
      const ns=_todaySeedNow();
      if(ns!==curSeed){
        curSeed=ns;
        setLk(_computeTodayLucky());
      }
    },60_000); // 1분마다 날짜 변동 체크
    // 페이지 다시 활성화될 때(탭 전환·복귀)도 갱신
    const onVis=()=>{if(!document.hidden){const ns=_todaySeedNow();if(ns!==curSeed){curSeed=ns;setLk(_computeTodayLucky());}else{setLk(_computeTodayLucky());}}};
    document.addEventListener("visibilitychange",onVis);
    return()=>{clearInterval(t);document.removeEventListener("visibilitychange",onVis);};
  },[]);
  return(
    <div style={{marginBottom:9}}>
      <div style={{fontSize:11,fontWeight:700,color:"var(--mist)",marginBottom:8}}>✦ 오늘의 수호 기운</div>
      <div className="drag-scroll" style={{display:"flex",gap:8,overflowX:"auto",scrollbarWidth:"none",paddingRight:32,paddingBottom:2}}>
        {[
          {icon:null, colorChip:true, label:"수호색",  val:lk.color},
          {icon:"🧭", label:"수호 방향", val:lk.direction},
          {icon:"🔢", label:"수호 숫자", val:`${lk.number}`},
          {icon:"🕐", label:"수호 시간", val:lk.time},
          {icon:"🍲", label:"수호 음식", val:lk.food},
          {icon:lk.animalEmoji||"🐯", label:"수호 동물", val:lk.animal},
        ].map((s,i)=>(
          <div key={i} style={{flexShrink:0,background:"var(--ink3)",borderRadius:12,padding:"9px 11px",textAlign:"center",border:"1px solid rgba(255,255,255,0.05)",minWidth:68}}>
            <div style={{height:22,display:"flex",alignItems:"center",justifyContent:"center",marginBottom:3}}>
              {s.colorChip
                ?<div style={{width:18,height:18,borderRadius:5,background:lk.colorHex,border:"1px solid rgba(255,255,255,0.2)"}}/>
                :<span style={{fontSize:16}}>{s.icon}</span>
              }
            </div>
            <div style={{fontSize:9,color:"var(--mist)",marginBottom:3}}>{s.label}</div>
            <div style={{fontSize:11,fontWeight:700}}>{s.val}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// 로또 6개 (날짜 시드, 매일 갱신)
const _TODAY_LOTTO=(()=>{
  const r=_dayRng(99);
  const pool=Array.from({length:45},(_,i)=>i+1);
  const out:number[]=[];
  while(out.length<6){const i=Math.floor(r()*pool.length);out.push(pool.splice(i,1)[0]);}
  return out.sort((a,b)=>a-b);
})();

