// ━━━ 사주 계산 (12수호신 · 천기리포트용) ━━━
const _CG_OHANG=["목","목","화","화","토","토","금","금","수","수"];
const _JJ_OHANG=["수","토","목","목","토","화","화","토","금","금","토","수"];
const _CG_YANG=[0,2,4,6,8];
const _CHEONGAN_KR=["갑","을","병","정","무","기","경","신","임","계"];
// v806(Phase2): 정확한 단일 엔진(절기·입춘)으로 위임. 반환 모양(숫자 인덱스)은 구버전과 동일 → 다운스트림 무수정
function _getSaju(year:number,month:number,day:number,hour?:number|null){
  return legacyPillars(year,month,day,hour??null);
}
function _getOhang(saju:any){
  const s:any={목:0,화:0,토:0,금:0,수:0};
  const ps=[saju.year,saju.month,saju.day];if(saju.hour)ps.push(saju.hour);
  ps.forEach((p:any)=>{s[_CG_OHANG[p.cg]]+=2;s[_JJ_OHANG[p.jj]]+=3;});return s;
}
function _getStarSign(month:number,day:number){
  const signs=[
    {name:"염소",start:[1,1],end:[1,19],element:"토"},{name:"물병",start:[1,20],end:[2,18],element:"공기"},
    {name:"물고기",start:[2,19],end:[3,20],element:"수"},{name:"양",start:[3,21],end:[4,19],element:"화"},
    {name:"황소",start:[4,20],end:[5,20],element:"토"},{name:"쌍둥이",start:[5,21],end:[6,20],element:"공기"},
    {name:"게",start:[6,21],end:[7,22],element:"수"},{name:"사자",start:[7,23],end:[8,22],element:"화"},
    {name:"처녀",start:[8,23],end:[9,22],element:"토"},{name:"천칭",start:[9,23],end:[10,22],element:"공기"},
    {name:"전갈",start:[10,23],end:[11,21],element:"수"},{name:"사수",start:[11,22],end:[12,21],element:"화"},
    {name:"염소",start:[12,22],end:[12,31],element:"토"},
  ];
  for(const s of signs){const[sm,sd]=s.start,[em,ed]=s.end;if((month===sm&&day>=sd)||(month===em&&day<=ed))return s;}
  return signs[0];
}
