// 수호신 사주 기반 도출
function _getGuardian(year:number,month:number,day:number,hour?:number|null){
  const saju=_getSaju(year,month,day,hour??null);
  const oh=_getOhang(saju);
  const star=_getStarSign(month,day);
  const ilOh=_CG_OHANG[saju.ilgan];
  const isYang=_CG_YANG.includes(saju.ilgan);
  const sorted=Object.entries(oh).sort((a:any,b:any)=>b[1]-a[1]);
  const dominant=sorted[0][0],second=sorted[1][0];
  const scores:any={};Object.keys(GUARDIANS_DATA).forEach(k=>scores[k]=0);
  const ilganMap:any={목:["청룡","기린","백학"],화:["봉황","주작","금오","천마"],토:["해태","기린"],금:["백호","흑호","현무"],수:["현무","옥토"]};
  (ilganMap[ilOh]||[]).forEach((g:string)=>{if(scores[g]!==undefined)scores[g]+=3;});
  const ohMap:any={목:["청룡","기린","백학"],화:["봉황","주작","금오","천마"],토:["해태","기린"],금:["백호","흑호","현무"],수:["현무","옥토"]};
  (ohMap[dominant]||[]).forEach((g:string)=>{if(scores[g]!==undefined)scores[g]+=2;});
  (ohMap[second]||[]).forEach((g:string)=>{if(scores[g]!==undefined)scores[g]+=1;});
  const starMap:any={"화":["봉황","주작","청룡","금오","천마"],"수":["현무","옥토"],"토":["백호","해태","백학"],"공기":["기린","청룡","봉황","천마"]};
  (starMap[star.element]||[]).forEach((g:string)=>{if(scores[g]!==undefined)scores[g]+=2;});
  if(isYang){["봉황","청룡","백호","주작","금오"].forEach(g=>{if(scores[g]!==undefined)scores[g]+=1;});}
  else{["현무","흑호","옥토","해태","백학"].forEach(g=>{if(scores[g]!==undefined)scores[g]+=1;});}
  const resultName=Object.entries(scores).sort((a:any,b:any)=>b[1]-a[1])[0][0];
  return{guardian:GUARDIANS_DATA[resultName],saju,oh,star,ilOh,isYang,ilganName:_CHEONGAN_KR[saju.ilgan],scores};
}
// 천기리포트용: 콘텐츠 오행 기반 수호신 도출
const _GUARDIAN_OHANG_MAP:any={
  봉황:{화:3,목:2,토:0,금:0,수:0},용:{목:3,수:2,화:1,토:0,금:0},백호:{금:3,토:1,목:0,화:0,수:0},
  현무:{수:3,금:2,토:1,목:0,화:0},기린:{목:3,토:2,화:1,금:0,수:0},주작:{화:3,목:1,토:0,금:0,수:0},
  청룡:{목:3,화:2,수:1,토:0,금:0},백학:{목:2,금:2,토:1,화:1,수:0},흑호:{금:2,수:2,목:0,화:0,토:1},
  금오:{화:2,금:2,토:1,목:0,수:0},옥토:{수:2,금:2,목:1,토:0,화:0},해태:{토:3,금:2,수:1,목:0,화:0},
};
const _STAR_OHANG:any={양:"화",사자:"화",사수:"화",쌍둥이:"목",천칭:"목",물병:"목",게:"수",전갈:"수",물고기:"수",황소:"금",처녀:"금",염소:"금"};
function _getGuardianFromReport(userHistory:any[],birthYear?:number,birthMonth?:number,birthDay?:number){
  // 콘텐츠별 오행 가중치
  const CONTENT_WEIGHTS:any={saju:3,gijildo:2,gwansang:1,love:1,palmistry:1,name:1};
  const totalOhang:any={목:0,화:0,토:0,금:0,수:0};
  // 사주 기반 오행 추가 (가장 중요)
  if(birthYear&&birthMonth&&birthDay){
    const saju=_getSaju(birthYear,birthMonth,birthDay);
    const oh=_getOhang(saju);
    Object.entries(oh).forEach(([k,v]:any)=>{totalOhang[k]+=v*0.5;});
  }
  // 별자리 오행
  if(birthMonth&&birthDay){
    const star=_getStarSign(birthMonth,birthDay);
    const sOh=_STAR_OHANG[star.name];
    if(sOh)totalOhang[sOh]+=2;
  }
  // 이용 콘텐츠 오행 (기록에 ohang이 있으면 반영)
  userHistory.forEach((h:any)=>{
    const oh=h.resultType?.ohang||h.ctx?.ohaeng||h.ctx?.ohang;
    if(!oh||!totalOhang.hasOwnProperty(oh))return;
    const w=CONTENT_WEIGHTS[h.svcId]||1;
    totalOhang[oh]+=w;
  });
  const guardianScores:any={};
  Object.entries(_GUARDIAN_OHANG_MAP).forEach(([guardian,affinity]:any)=>{
    let score=0;
    Object.entries(totalOhang).forEach(([oh,userScore]:any)=>{score+=userScore*(affinity[oh]||0);});
    guardianScores[guardian]=score;
  });
  const sorted=Object.entries(guardianScores).sort((a:any,b:any)=>b[1]-a[1]);
  return{guardian:sorted[0][0],guardianData:GUARDIANS_DATA[sorted[0][0]],scores:guardianScores,totalOhang,top3:sorted.slice(0,3).map(([name,score])=>({name,score}))};
}
// TWELVE_TYPES (하위 호환용: 기존 그리드·배지 등에서 사용)
const TWELVE_TYPES = Object.values(GUARDIANS_DATA).map((g:any)=>({id:g.name,icon:g.emoji,card:g.card,hanja:g.hanja,desc:g.desc,tags:[g.element,g.subtitle],color:g.color}));

