// 빠른접근 특수 탭 (가격 필터)
const QUICK_TABS = ["5,800원↓","9,800원↓","내 맞춤","프리미엄","시즌한정","전체보기"];
const QUICK_EMOJI:Record<string,string> = {"5,800원↓":"🏷️","9,800원↓":"🏷️","내 맞춤":"✨","프리미엄":"💎","시즌한정":"🎋","전체보기":"🔍"};
// 일반 카테고리
const GOODS_CATS_TYPE = ["12수호신","띠별","별자리","혈액형","기질도","수비학","전생유형"];
const GOODS_CATS_ENERGY = ["집안 정화","미니 부적","오행 보완","기운 회복","기운 보강","향·인센스"];
const GOODS_CATS_THEME = ["한국 뮷즈","외국 부적","운세·점사","럭키템","커플·연애","반려동물","손금·점키트"];
const GOODS_CATS_LIFE = ["집안 수호신","이사·개업","종교·영성","탄생·수호","천기 주얼리","천기 굿즈"];
const GOODS_CATS = [...GOODS_CATS_TYPE,...GOODS_CATS_ENERGY,...GOODS_CATS_THEME,...GOODS_CATS_LIFE];
const CAT_EMOJI:Record<string,string> = {"12수호신":"🐉","띠별":"🐯","별자리":"⭐","혈액형":"🩸","기질도":"☯️","수비학":"🔢","전생유형":"🎴","집안 정화":"🧹","미니 부적":"🧧","오행 보완":"🔥","기운 회복":"✨","기운 보강":"💪","향·인센스":"🕯️","한국 뮷즈":"🇰🇷","외국 부적":"🌍","운세·점사":"🔮","럭키템":"🍀","커플·연애":"💌","반려동물":"🐾","손금·점키트":"🪄","집안 수호신":"🏠","이사·개업":"🏡","종교·영성":"🪷","탄생·수호":"🌱","천기 주얼리":"💍","천기 굿즈":"👗"};

// 콘텐츠 결과 → 굿즈 필터링 로직
const GOODS_ENGINE = {
  // 관상 계열 → 기운회복 + 오행(화) + 미니부적
  gwansang_zal:   (ctx) => GOODS_DB.filter(g => g.cat==="기운 회복" || (g.cat==="오행 보완") || (g.cat==="미니 부적")),
  gwansang_full:  (ctx) => GOODS_DB.filter(g => g.cat==="기운 회복" || (g.cat==="오행 보완") || g.tags?.includes("재물")),
  // 사주 계열 → 오행보완 + 수비학
  saju:           (ctx) => GOODS_DB.filter(g => (g.cat==="오행 보완") || g.cat==="수비학" || g.cat==="기운 보강"),
  saju_monthly:   (ctx) => GOODS_DB.filter(g => (g.cat==="오행 보완") || g.cat==="시즌"),
  // 연애 계열 → 애정 부적 + 연애향초
  love:           (ctx) => GOODS_DB.filter(g => g.tags?.includes("연애") || g.tags?.includes("애정") || g.tags?.includes("분위기")),
  // 별자리 → 별자리 전용 + 수호석 기반
  zodiac:         (ctx) => GOODS_DB.filter(g => (g.cat==="별자리") || g.cat==="기운 보강"),
  // 12영수형 → 영수형 전용 + 오행
  ytype:          (ctx) => GOODS_DB.filter(g => (g.cat==="12수호신") || (g.cat==="오행 보완")),
  // 띠별 → 띠별 수호 + 오행
  ddi:            (ctx) => GOODS_DB.filter(g => (g.cat==="띠별") || (g.cat==="오행 보완")),
  // 혈액형 → 혈액형별
  blood:          (ctx) => GOODS_DB.filter(g => (g.cat==="혈액형") || g.cat==="향인센스"),
  // 꿈 해몽 → 키워드별 부적 + 기운회복
  dream:          (ctx) => GOODS_DB.filter(g => g.cat==="미니 부적" || g.cat==="기운 회복"),
  // 타로 → 타로카드 + 수정
  today_tarot:    (ctx) => GOODS_DB.filter(g => g.cat==="운세점사" || g.cat==="기운 보강"),
  tarot_love:     (ctx) => GOODS_DB.filter(g => g.tags?.includes("연애") || g.cat==="운세점사"),
  tarot_health:   (ctx) => GOODS_DB.filter(g => g.cat==="기운 회복" || g.cat==="향인센스"),
  tarot_career:   (ctx) => GOODS_DB.filter(g => g.cat==="기운 보강" || g.cat==="수비학"),
  tarot_life:     (ctx) => GOODS_DB.filter(g => g.cat==="운세점사" || g.cat==="기운 보강"),
  // 수비학 → 운명수 컬러 아이템
  numerology:     (ctx) => GOODS_DB.filter(g => (g.cat==="수비학") || g.cat==="오행 보완"),
  // 신년운세 → 시즌 개운 키트
  newyear:        (ctx) => GOODS_DB.filter(g => g.cat==="기운 회복"),
  // 파동성명학 → 부족 오행 아이템
  pawdong:        (ctx) => GOODS_DB.filter(g => (g.cat==="오행 보완") || g.cat==="기운 보강"),
  // 로또 → 행운 강화
  lotto:          (ctx) => GOODS_DB.filter(g => g.tags?.includes("재물") || g.tags?.includes("행운") || g.cat==="수비학"),
  // 전생 → 기운회복 + 보강
  past_life:      (ctx) => GOODS_DB.filter(g => g.cat==="기운 회복" || g.cat==="기운 보강"),
  // 기본 fallback
  default:        (ctx) => GOODS_DB.filter(g => g.rec || g.cat==="기운 회복").slice(0,6),
};

function getGoodsRec(svcId, ctx={}) {
  const fn = GOODS_ENGINE[svcId] || GOODS_ENGINE.default;
  return fn(ctx).slice(0, 5);
}

// 유저 이용 기록 기반 맞춤 추천
function getPersonalizedGoods(history) {
  if(!history || history.length===0) return GOODS_DB.filter(g=>g.rec).slice(0,8);
  const ohaengSet = new Set(history.map(h=>h.ctx?.ohaeng).filter(Boolean));
  const ytypeSet  = new Set(history.map(h=>h.ctx?.ytype).filter(Boolean));
  const ddiSet    = new Set(history.map(h=>h.ctx?.ddi).filter(Boolean));
  const bloodSet  = new Set(history.map(h=>h.ctx?.blood).filter(Boolean));
  const zodiacSet = new Set(history.map(h=>h.ctx?.zodiac).filter(Boolean));

  const scored = GOODS_DB.map(g => {
    let score = 0;
    if(g.cat==="오행 보완") score += 10;
    if(g.cat==="12수호신") score += 9;
    if(g.cat==="띠별") score += 8;
    if(g.cat==="혈액형") score += 7;
    if(g.cat==="별자리") score += 7;
    if(g.rec) score += 3;
    return {...g, _score: score};
  });
  return scored.sort((a,b)=>b._score-a._score).slice(0,10);
}

function Dots(){return<div className="dots"><div className="dot"/><div className="dot"/><div className="dot"/></div>;}

// ─── 📚 도감(전체 풀이북) — 재사용 가능한 generic 모달 ──────────────────────────────
// 사용처: 관상짤·내관상보기·아기관상·댕댕·냥냥·조선초상화·12수호신 등
// types[]: [{id, name, emoji, image?, tag?, group?, ...}]
// groups[]: [{key, label, color}] — group 별 분류 (없으면 단일 그리드)
// curId: 사용자 매칭된 타입 (✦ 표시)
// bestId/worstId: 찰떡/상극 타입 (선택). 배열로 여러 개 가능 (예: [7,9])
function CollectionBookModal({onClose,title,subtitle,icon,types,groups,curId,bestId,worstId,getImage,getTag,getKeyword,brand,meLabel,imageShape,children,bestLabel,worstLabel}:any){
  const ML=meLabel||"내 타입";
  const _BL=bestLabel||"💚 찰떡";
  const _WL=worstLabel||"⚡ 상극";
  // 도감 카드 이미지 모양 — 기본은 동그라미(캐릭터 일러스트용), 조선초상화처럼 정사각 템플릿 그림은 "square"
  const _bigShape=imageShape==="square"?"12px":"50%";
  const _smShape=imageShape==="square"?"8px":"50%";
  const findT=(id:any)=>types.find((t:any)=>t.id===id||String(t.id)===String(id));
  const cur=findT(curId);
  // bestId/worstId — 단일 ID 또는 배열 모두 지원
  const bestIds=Array.isArray(bestId)?bestId:(bestId!=null?[bestId]:[]);
  const worstIds=Array.isArray(worstId)?worstId:(worstId!=null?[worstId]:[]);
  const bests=bestIds.map(findT).filter(Boolean);
  const worsts=worstIds.map(findT).filter(Boolean);
  const best=bests[0]; // 헤더 mini 카드는 첫번째만 (공간 제약)
  const worst=worsts[0];
  return <div className="ov"><div className="md" style={{maxHeight:"92vh",overflow:"auto"}}><div className="hd"/>
    <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={onClose} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
    <div style={{background:"#FDFCF8",borderRadius:18,padding:"10px 16px 10px",marginBottom:14,boxShadow:"0 8px 28px rgba(0,0,0,0.3)",border:"2px solid rgba(201,167,78,0.35)",color:"#333"}}>
      <div style={{fontSize:9,color:"#aaa",fontWeight:600,letterSpacing:0.3,textAlign:"center",paddingBottom:10,marginBottom:14,marginLeft:-16,marginRight:-16,paddingLeft:16,paddingRight:16,borderBottom:"1px solid #f0f0f0"}}>🔮 천기(天機) 오리지널 | {brand||title}</div>
      <div style={{textAlign:"center",fontSize:54,marginBottom:6}}>{icon||"📚"}</div>
      <div style={{textAlign:"center",fontSize:22,fontWeight:900,color:"#1A1A1A",fontFamily:"'Noto Serif KR','Batang',serif",marginBottom:4,lineHeight:1.4}}>{title}</div>
      {subtitle&&<div style={{textAlign:"center",fontSize:12,color:"#7A5C00",marginBottom:14,fontWeight:600}}>{subtitle}</div>}

      {/* 내 타입 + 찰떡/상극 하이라이트 */}
      {cur&&(
        <div style={{background:"linear-gradient(135deg,#fffbe9,#fff5d6)",border:"2px solid rgba(201,167,78,0.45)",borderRadius:14,padding:"14px",marginBottom:14}}>
          <div style={{fontSize:10,color:"#7A5C00",fontWeight:800,letterSpacing:2,textAlign:"center",marginBottom:10}}>✦ {ML}: {cur.name||cur.title_ko||cur.persona} ✦</div>
          <div style={{display:"flex",gap:12,alignItems:"center",marginBottom:(best||worst)?12:0}}>
            <div style={{width:84,height:84,borderRadius:_bigShape,overflow:"hidden",border:"3px double rgba(201,167,78,0.55)",boxShadow:"0 4px 12px rgba(201,167,78,0.25)",background:"#fff",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",position:"relative"}}>
              {getImage&&getImage(cur)?<img src={getImage(cur)} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.currentTarget.style.display="none";}}/>:<span style={{fontSize:36}}>{cur.emoji||cur.icon||"🌟"}</span>}
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:14,fontWeight:900,color:"#1A1A1A",marginBottom:4,fontFamily:"'Noto Serif KR','Batang',serif"}}>{cur.emoji||cur.icon} {cur.name||cur.title_ko||cur.persona}</div>
              {getTag&&getTag(cur)&&<div style={{fontSize:11,color:"#C4922A",fontWeight:700,marginBottom:3}}>{getTag(cur)}</div>}
              {getKeyword&&getKeyword(cur)&&<div style={{fontSize:10,color:"#666",lineHeight:1.5,wordBreak:"keep-all"}}>{getKeyword(cur)}</div>}
            </div>
          </div>
          {/* 찰떡 + 상극 mini 카드 — 일러스트 우선 (이모지 fallback) */}
          {(best||worst)&&(
            <div style={{display:"grid",gridTemplateColumns:best&&worst?"1fr 1fr":"1fr",gap:6,paddingTop:10,borderTop:"1px dashed rgba(201,167,78,0.3)"}}>
              {best&&(
                <div style={{background:"#eff8f1",border:"1.5px solid #86efac",borderRadius:10,padding:"10px",textAlign:"center"}}>
                  <div style={{fontSize:9,color:"#16a34a",fontWeight:800,letterSpacing:1.5,marginBottom:4}}>{_BL}</div>
                  <div style={{width:48,height:48,borderRadius:_smShape,overflow:"hidden",background:"#fff",border:"1px solid rgba(22,163,74,0.25)",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 4px"}}>
                    {getImage&&getImage(best)?<img src={getImage(best)} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.currentTarget.style.display="none";}}/>:<span style={{fontSize:22}}>{best.emoji||best.icon||"🌟"}</span>}
                  </div>
                  <div style={{fontSize:11,fontWeight:700,color:"#1e3a2a",lineHeight:1.3,marginBottom:4}}>{best.name||best.title_ko||best.persona}</div>
                  {/* v669: 해시태그/키워드 박스화 — 찰떡은 그린 톤 (PastLifeFullModal과 동일 패턴) */}
                  {getTag&&getTag(best)&&<div style={{display:"inline-block",padding:"2px 8px",background:"rgba(34,197,94,0.12)",border:"1px solid rgba(34,197,94,0.3)",borderRadius:10,fontSize:9,color:"#16a34a",fontWeight:700,marginTop:2,wordBreak:"keep-all"}}>{getTag(best)}</div>}
                  {getKeyword&&getKeyword(best)&&<div style={{padding:"4px 8px",background:"rgba(0,0,0,0.04)",border:"1px solid rgba(0,0,0,0.06)",borderRadius:8,fontSize:9,color:"#555",lineHeight:1.45,marginTop:4,wordBreak:"keep-all"}}>{getKeyword(best)}</div>}
                </div>
              )}
              {worst&&(
                <div style={{background:"#fef2f2",border:"1.5px solid #fcb6b6",borderRadius:10,padding:"10px",textAlign:"center"}}>
                  <div style={{fontSize:9,color:"#dc2626",fontWeight:800,letterSpacing:1.5,marginBottom:4}}>{_WL}</div>
                  <div style={{width:48,height:48,borderRadius:_smShape,overflow:"hidden",background:"#fff",border:"1px solid rgba(220,38,38,0.25)",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 4px"}}>
                    {getImage&&getImage(worst)?<img src={getImage(worst)} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.currentTarget.style.display="none";}}/>:<span style={{fontSize:22}}>{worst.emoji||worst.icon||"🌟"}</span>}
                  </div>
                  <div style={{fontSize:11,fontWeight:700,color:"#7c1d1d",lineHeight:1.3,marginBottom:4}}>{worst.name||worst.title_ko||worst.persona}</div>
                  {/* v669: 해시태그/키워드 박스화 — 라이벌은 레드 톤 */}
                  {getTag&&getTag(worst)&&<div style={{display:"inline-block",padding:"2px 8px",background:"rgba(220,38,38,0.1)",border:"1px solid rgba(220,38,38,0.3)",borderRadius:10,fontSize:9,color:"#dc2626",fontWeight:700,marginTop:2,wordBreak:"keep-all"}}>{getTag(worst)}</div>}
                  {getKeyword&&getKeyword(worst)&&<div style={{padding:"4px 8px",background:"rgba(0,0,0,0.04)",border:"1px solid rgba(0,0,0,0.06)",borderRadius:8,fontSize:9,color:"#555",lineHeight:1.45,marginTop:4,wordBreak:"keep-all"}}>{getKeyword(worst)}</div>}
                </div>
              )}
            </div>
          )}
          <div style={{fontSize:10,color:"#7A5C00",marginTop:10,textAlign:"center",lineHeight:1.6}}>아래 전체 목록에서 ✦ 표시가 {ML}이에요</div>
        </div>
      )}

      {/* 커스텀 추가 섹션 (예: 아기관상 찰떡/주의 친구 텍스트) */}
      {children}

      {/* 그룹별 또는 단일 그리드 */}
      {groups&&groups.length>0?groups.map((g:any)=>{
        const filtered=types.filter((t:any)=>t.group===g.key||t[g.field||"category"]===g.key||t.ohaeng===g.key||t.oh===g.key||t.gender===g.key);
        if(filtered.length===0)return null;
        return(
          <div key={g.key} style={{marginBottom:14,paddingTop:12,borderTop:"1px dashed rgba(0,0,0,0.1)"}}>
            <div style={{fontSize:13,fontWeight:800,color:g.color||"#7A5C00",marginBottom:8,letterSpacing:1}}>✦ {g.label}</div>
            {filtered.map((t:any)=>{
              // v333: curId 배열 지원 — 타로 spread 다중 강조
              const isMe=Array.isArray(curId)?curId.some((id:any)=>id===t.id||String(id)===String(t.id)):(t.id===curId||String(t.id)===String(curId));
              const isBest=bestIds.some(id=>id===t.id||String(id)===String(t.id));
              const isWorst=worstIds.some(id=>id===t.id||String(id)===String(t.id));
              const accent=isMe?(g.color||"#C4922A"):isBest?"#16a34a":isWorst?"#dc2626":"transparent";
              return <div key={t.id} style={{display:"flex",gap:12,alignItems:"center",padding:"10px 12px",marginBottom:12,background:isMe?"rgba(201,167,78,0.12)":isBest?"rgba(22,163,74,0.05)":isWorst?"rgba(220,38,38,0.05)":"#F9F7F2",border:isMe||isBest||isWorst?`2px solid ${accent}`:"1px solid transparent",borderRadius:10}}>
                <div style={{width:48,height:48,borderRadius:_smShape,overflow:"hidden",border:isMe?`2px solid ${accent}`:"1px solid rgba(0,0,0,0.06)",background:"#fff",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>
                  {getImage&&getImage(t)?<img src={getImage(t)} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.currentTarget.style.display="none";}}/>:<span style={{fontSize:22}}>{t.emoji||t.icon||"🌟"}</span>}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:12,fontWeight:700,color:"#111",marginBottom:4}}>{t.emoji||t.icon} {t.name||t.title_ko||t.persona}{isMe&&<span style={{color:accent,marginLeft:6,fontSize:10,fontWeight:900}}>✦ {ML}</span>}{isBest&&<span style={{color:"#16a34a",marginLeft:6,fontSize:10,fontWeight:900}}>{_BL}</span>}{isWorst&&<span style={{color:"#dc2626",marginLeft:6,fontSize:10,fontWeight:900}}>{_WL}</span>}</div>
                  {/* v669: 도감 리스트 — 해시태그/키워드 박스화 (찰떡=그린, 라이벌=레드, 기본=골드) */}
                  {getTag&&getTag(t)&&<div style={{display:"inline-block",padding:"2px 8px",background:isBest?"rgba(34,197,94,0.12)":isWorst?"rgba(220,38,38,0.1)":"rgba(122,92,0,0.08)",border:`1px solid ${isBest?"rgba(34,197,94,0.3)":isWorst?"rgba(220,38,38,0.3)":"rgba(122,92,0,0.2)"}`,borderRadius:10,fontSize:9,color:isBest?"#16a34a":isWorst?"#dc2626":"#7A5C00",fontWeight:700,marginTop:2,wordBreak:"keep-all"}}>{getTag(t)}</div>}
                  {getKeyword&&getKeyword(t)&&<div style={{padding:"4px 8px",background:"rgba(0,0,0,0.04)",border:"1px solid rgba(0,0,0,0.06)",borderRadius:8,fontSize:9,color:"#555",lineHeight:1.45,marginTop:4,wordBreak:"keep-all"}}>{getKeyword(t)}</div>}
                </div>
              </div>;
            })}
          </div>
        );
      }):(
        <div style={{paddingTop:12,borderTop:"1px dashed rgba(0,0,0,0.1)"}}>
          {types.map((t:any)=>{
            // v333: curId 배열 지원 — 타로 spread 다중 강조
            const isMe=Array.isArray(curId)?curId.some((id:any)=>id===t.id||String(id)===String(t.id)):(t.id===curId||String(t.id)===String(curId));
            const isBest=bestIds.some(id=>id===t.id||String(id)===String(t.id));
            const isWorst=worstIds.some(id=>id===t.id||String(id)===String(t.id));
            const accent=isMe?"#C4922A":isBest?"#16a34a":isWorst?"#dc2626":"transparent";
            return <div key={t.id} style={{display:"flex",gap:12,alignItems:"center",padding:"10px 12px",marginBottom:12,background:isMe?"rgba(201,167,78,0.12)":isBest?"rgba(22,163,74,0.05)":isWorst?"rgba(220,38,38,0.05)":"#F9F7F2",border:isMe||isBest||isWorst?`2px solid ${accent}`:"1px solid transparent",borderRadius:10}}>
              <div style={{width:48,height:48,borderRadius:"50%",overflow:"hidden",border:isMe?`2px solid ${accent}`:"1px solid rgba(0,0,0,0.06)",background:"#fff",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>
                {getImage&&getImage(t)?<img src={getImage(t)} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.currentTarget.style.display="none";}}/>:<span style={{fontSize:22}}>{t.emoji||t.icon||"🌟"}</span>}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:12,fontWeight:700,color:"#111",marginBottom:4}}>{t.emoji||t.icon} {t.name||t.title_ko||t.persona}{isMe&&<span style={{color:accent,marginLeft:6,fontSize:10,fontWeight:900}}>✦ {ML}</span>}{isBest&&<span style={{color:"#16a34a",marginLeft:6,fontSize:10,fontWeight:900}}>{_BL}</span>}{isWorst&&<span style={{color:"#dc2626",marginLeft:6,fontSize:10,fontWeight:900}}>{_WL}</span>}</div>
                {/* v669: 도감 단일 그리드 — 해시태그/키워드 박스화 */}
                {getTag&&getTag(t)&&<div style={{display:"inline-block",padding:"2px 8px",background:isBest?"rgba(34,197,94,0.12)":isWorst?"rgba(220,38,38,0.1)":"rgba(122,92,0,0.08)",border:`1px solid ${isBest?"rgba(34,197,94,0.3)":isWorst?"rgba(220,38,38,0.3)":"rgba(122,92,0,0.2)"}`,borderRadius:10,fontSize:9,color:isBest?"#16a34a":isWorst?"#dc2626":"#7A5C00",fontWeight:700,marginTop:2,wordBreak:"keep-all"}}>{getTag(t)}</div>}
                {getKeyword&&getKeyword(t)&&<div style={{padding:"4px 8px",background:"rgba(0,0,0,0.04)",border:"1px solid rgba(0,0,0,0.06)",borderRadius:8,fontSize:9,color:"#555",lineHeight:1.45,marginTop:4,wordBreak:"keep-all"}}>{getKeyword(t)}</div>}
              </div>
            </div>;
          })}
        </div>
      )}
    </div>
    <button className="btn btn-p" onClick={onClose}>확인</button>
  </div></div>;
}

