const FUN_LOADING_MSGS=[...LOADING_SAJU,...LOADING_FACE];
function FunLoader({duration=4000,onDone,type="saju"}:{duration?:number,onDone:()=>void,type?:"saju"|"face"}){
  const msgs=type==="face"?LOADING_FACE:LOADING_SAJU;
  const[pct,setPct]=useState(0);
  const[msgIdx,setMsgIdx]=useState(0);
  useEffect(()=>{
    const start=Date.now();
    const timer=setInterval(()=>{
      const elapsed=Date.now()-start;
      const p=Math.min(100,Math.round((elapsed/duration)*100));
      setPct(p);
      if(p>=100){clearInterval(timer);setTimeout(onDone,300);}
    },50);
    const msgTimer=setInterval(()=>setMsgIdx(i=>(i+1)%msgs.length),2500);
    return()=>{clearInterval(timer);clearInterval(msgTimer);};
  },[duration,onDone,msgs]);
  return(
    <div style={{textAlign:"center",padding:"30px 0"}}>
      <div style={{fontSize:40,marginBottom:16,animation:"pulse 1.5s infinite"}}>🔮</div>
      <div style={{fontSize:13,fontWeight:700,color:"var(--gold)",marginBottom:12}}>운명을 읽고 있어요...</div>
      {/* 프로그레스 바 */}
      <div style={{background:"var(--ink3)",borderRadius:20,height:8,margin:"0 20px 14px",overflow:"hidden"}}>
        <div style={{height:"100%",borderRadius:20,background:"linear-gradient(90deg,var(--gold),var(--gold3))",width:`${pct}%`,transition:"width 0.3s"}}/>
      </div>
      <div style={{fontSize:12,color:"var(--gold)",fontWeight:700,marginBottom:16}}>{pct}%</div>
      {/* 재미 멘트 */}
      <div style={{fontSize:12,color:"var(--mist)",lineHeight:1.6,minHeight:40,padding:"0 10px"}}>{msgs[msgIdx]}</div>
      {pct>=85&&duration>=10000&&<div style={{fontSize:11,color:"rgba(212,175,55,0.65)",marginTop:8,lineHeight:1.6}}>🌐 AI 서버가 혼잡해서 조금 더 걸리고 있어요 — 잠시만 기다려주세요</div>}
      <LoadingHint/>
    </div>
  );
}

