const EMOTION_QS=[
  {id:"love",label:"지금, 마음의 온도는 몇 도쯤 되나요? 🌡️",options:[
    "🧊 꽁꽁 얼어붙은 한겨울 (솔로/관심 없음)",
    "🌱 봄바람을 기다리는 중 (솔로/썸이나 인연을 원함)",
    "🌸 핑크빛 벚꽃이 만개한 봄 (달달한 연애 중)",
    "🍂 안정적이고 따뜻한 가을 햇살 (결혼/오랜 연인)",
    "⛈️ 거센 비바람이 지나간 자리 (이별 직후/상처 회복 중)",
    "직접 입력"]},
  {id:"job",label:"당신의 낮을 가장 뜨겁게 채우고 있는 일은\n무엇인가요? ☀️",options:[
    "🌱 내일을 위해 씨앗을 심는 중 (학생/취준생/시험 준비)",
    "🐹 매일 치열하게 쳇바퀴를 굴리는 중 (직장인)",
    "🚀 내 이름표를 걸고 정글을 개척하는 중 (자영업/사업/프리랜서)",
    "🏠 세상을 돌보는 위대한 일상 (주부/육아)",
    "🌅 잠시 날개를 접고 숨 고르는 중 (휴식/은퇴)",
    "직접 입력"]},
  {id:"worry",label:"오늘 밤, 당신을 가장 뒤척이게 만드는\n단 하나의 생각은? 🌙",options:[
    "💸 통장 잔고를 볼 때마다 느껴지는 막막함",
    "🤔 지금 하는 일이 내 길이 맞나 싶은 회의감",
    "😵 마음처럼 풀리지 않는 사람과의 관계",
    "🌀 내 인생, 언제쯤 뻥 뚫릴까 하는 답답함",
    "😌 딱히 없어요, 그냥 궁금해서!",
    "직접 입력"]},
];
function EmotionStep({onDone}:{onDone:(answers:any)=>void}){
  const[step,setStep]=useState(0);
  const[answers,setAnswers]=useState<any>({});
  const[custom,setCustom]=useState("");
  const q=EMOTION_QS[step];
  function select(opt:string){
    if(opt==="직접 입력")return;
    const next={...answers,[q.id]:opt};
    setAnswers(next);
    if(step<EMOTION_QS.length-1){setStep(step+1);setCustom("");}
    else onDone(next);
  }
  function submitCustom(){
    if(!custom.trim())return;
    const next={...answers,[q.id]:custom};
    setAnswers(next);
    if(step<EMOTION_QS.length-1){setStep(step+1);setCustom("");}
    else onDone(next);
  }
  return(
    <div>
      <div style={{fontSize:11,color:"var(--mist)",marginBottom:4}}>더 정확한 분석을 위해 ({step+1}/{EMOTION_QS.length})</div>
      <div style={{fontSize:14,fontWeight:700,marginBottom:14,lineHeight:1.5}}>{q.label}</div>
      <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:10}}>
        {q.options.map(opt=>(
          <button key={opt} onClick={()=>select(opt)} style={{padding:"11px 14px",borderRadius:12,border:"1px solid rgba(255,255,255,0.06)",background:opt==="직접 입력"?"transparent":"var(--ink3)",color:opt==="직접 입력"?"var(--mist)":"var(--white)",fontFamily:"inherit",fontSize:12,fontWeight:600,cursor:"pointer",textAlign:"left"}}>{opt}</button>
        ))}
      </div>
      {/* 직접 입력 */}
      <div style={{display:"flex",gap:6}}>
        <input className="inp" placeholder="직접 입력..." value={custom} onChange={e=>setCustom(e.target.value)} style={{flex:1,marginBottom:0}}/>
        <button onClick={submitCustom} style={{padding:"8px 14px",borderRadius:10,border:"none",background:"var(--gold)",color:"var(--ink)",fontFamily:"inherit",fontSize:11,fontWeight:700,cursor:"pointer",flexShrink:0}}>확인</button>
      </div>
      <button onClick={()=>onDone(answers)} style={{width:"100%",marginTop:10,background:"none",border:"none",color:"var(--mist)",fontSize:11,cursor:"pointer",fontFamily:"inherit",padding:6}}>건너뛰고 바로 분석 →</button>
    </div>
  );
}

// 공유 배지 레벨 정의
// v392: 라벨에서 이모지 제거 — icon 필드 따로 있어서 중복 표시되던 거 fix
const SHARE_LEVELS = [
  {label:"기본",icon:"👤",min:0,max:0,reward:"공유를 시작해보세요!"},
  {label:"공유자",icon:"🔗",min:1,max:4,reward:"쿠폰 즉시 지급"},
  {label:"전파자",icon:"📢",min:5,max:9,reward:"디지털 부적 선택"},
  {label:"홍보대사",icon:"🏆",min:10,max:19,reward:"키링 실물 발송"},
  {label:"인플루언서",icon:"🌟",min:20,max:999,reward:"명패 실물 발송"},
];

function getShareLevel(cnt){
  return SHARE_LEVELS.find(l=>cnt>=l.min&&cnt<=l.max)||SHARE_LEVELS[0];
}

// 알림센터 — 모든 보상/이벤트를 모아보기 (localStorage chungi_notifications)
type ChungiNotif={id:string,type:"reward"|"invite"|"share"|"system",emoji:string,title:string,desc:string,date:number,read:boolean};
function addNotification(n:Omit<ChungiNotif,"id"|"date"|"read">){
  try{
    const list:ChungiNotif[]=JSON.parse(localStorage.getItem("chungi_notifications")||"[]");
    list.unshift({...n,id:`N${Date.now()}_${Math.random().toString(36).substring(2,6)}`,date:Date.now(),read:false});
    // 최대 50개 유지
    localStorage.setItem("chungi_notifications",JSON.stringify(list.slice(0,50)));
    // 다른 컴포넌트에 알림 (벨 아이콘 갱신용)
    window.dispatchEvent(new CustomEvent("chungi-notif"));
    // 보상 알림 토글이 켜져있으면 햅틱 피드백
    haptic("reward");
  }catch{}
}

// 햅틱 피드백 — Vibration API (모바일만 동작, 데스크톱은 무시)
function haptic(type:"tap"|"reward"|"success"|"error"="tap"){
  try{
    if(typeof navigator==="undefined"||!navigator.vibrate)return;
    // 사용자가 보상 알림 끄면 햅틱도 OFF
    if(type==="reward"&&localStorage.getItem("chungi_noti_reward")==="0")return;
    const patterns:Record<string,number|number[]>={
      tap:10,
      reward:[20,40,80],
      success:[30,60,30],
      error:[60,30,60],
    };
    navigator.vibrate(patterns[type]);
  }catch{}
}

// v386: 공유 마일스톤 자동 쿠폰 발급 제거 — 함수만 남기고 빈 처리 (호출처 만일을 위해)
async function incrementShareCount(){/* 비활성화: 마일스톤 쿠폰 정책 폐지 */}

function ShareRow({onShare}:{onShare?:()=>void}){
  function getInviteUrl(){
    let code="";
    try{
      code=localStorage.getItem("chungi_referral_code")||"";
      if(!code){code="CG"+Math.random().toString(36).substring(2,6).toUpperCase();localStorage.setItem("chungi_referral_code",code);}
    }catch{}
    return `https://chungi.kr/?ref=${code}`;
  }
  // v384: 공유 카운팅은 친구가 실제 초대코드로 가입할 때만 (chungi_invited_count) — 클릭/복사로는 +1 안 함
  async function shareKakao(){
    const inviteUrl=getInviteUrl();
    const jsKey=process.env.NEXT_PUBLIC_KAKAO_JS_KEY||'';
    // SDK 최대 1.5초 대기 + init 시도
    for(let i=0;i<15;i++){
      const K=(typeof window!=='undefined'&&(window as any).Kakao)||null;
      if(K){
        if(!K.isInitialized()&&jsKey){try{K.init(jsKey);}catch{}}
        if(K.isInitialized())break;
      }
      await new Promise(r=>setTimeout(r,100));
    }
    try{
      const K=(window as any).Kakao;
      if(K?.isInitialized?.()){
        K.Share.sendDefault({
          objectType:'feed',
          content:{title:'천기 - AI 관상 스캐너',description:'내 초대 링크로 가입하면 양쪽 380원 쿠폰! 사주·관상·뇌과학 3초 분석 🔮',imageUrl:'https://chungi.kr/logo8.png',link:{mobileWebUrl:inviteUrl,webUrl:inviteUrl}},
          buttons:[{title:'380원 쿠폰 받고 시작하기',link:{mobileWebUrl:inviteUrl,webUrl:inviteUrl}}],
        });
        onShare?.();return;
      }
    }catch(e){console.error("Kakao share error:",e);}
    navigator.clipboard?.writeText(inviteUrl).then(()=>alert('💬 카톡 공유가 안 돼서 링크를 대신 복사했어요!\n카톡 채팅창에 붙여넣어 친구에게 보내주세요 🔗\n\n'+inviteUrl)).catch(()=>alert('🔗 내 초대 링크\n\n'+inviteUrl+'\n\n복사해서 친구에게 보내주세요!'));
    onShare?.();
  }
  function shareInsta(){window.open('https://www.instagram.com/','_blank');onShare?.();}
  function shareThreads(){window.open('https://www.threads.net/intent/post?text='+encodeURIComponent('천기에서 내 운세 확인해봐! '+getInviteUrl()),'_blank');onShare?.();}
  function shareFacebook(){window.open('https://www.facebook.com/sharer/sharer.php?u='+encodeURIComponent(getInviteUrl()),'_blank');onShare?.();}
  function copyLink(){const url=getInviteUrl();navigator.clipboard?.writeText(url).then(()=>alert('내 초대 링크가 복사되었어요! 🎉\n친구가 가입·결제하면 양쪽 380원 쿠폰 + 공유 카운트 +1'));onShare?.();}

  const btnStyle:any={display:"flex",flexDirection:"column",alignItems:"center",gap:4,padding:"10px 4px",borderRadius:12,background:"#ffffff",border:"2px solid rgba(212,175,55,0.4)",cursor:"pointer",flex:1,minWidth:0,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"};

  return(
    <div style={{marginBottom:14}}>
      <div style={{fontSize:12,fontWeight:700,color:"var(--gold)",textAlign:"center",marginBottom:10}}>📸 스크린샷으로 캡쳐해서 친구에게 공유하세요!</div>
      <div style={{display:"flex",gap:8,marginBottom:8}}>
        <div style={{...btnStyle,flex:1}} onClick={shareKakao}><span style={{fontSize:20}}>💬</span><span style={{fontSize:10,color:"#1A3C32",fontWeight:700}}>카카오톡으로 공유하기</span></div>
        <div style={{...btnStyle,flex:1}} onClick={copyLink}><span style={{fontSize:20}}>🔗</span><span style={{fontSize:10,color:"#1A3C32",fontWeight:700}}>링크 복사하기</span></div>
      </div>
      <div style={{background:"rgba(212,175,55,0.07)",border:"1px solid rgba(212,175,55,0.2)",borderRadius:10,padding:"9px 12px",marginBottom:12,display:"flex",alignItems:"center",gap:9}}>
        <span style={{fontSize:16,flexShrink:0}}>🎁</span>
        <div style={{flex:1,minWidth:0,fontSize:10,color:"var(--mist)",lineHeight:1.5}}>
          위 링크는 <strong style={{color:"var(--gold)"}}>내 초대 코드</strong>가 포함돼요.<br/>친구가 가입·결제하면 <strong style={{color:"var(--gold)"}}>양쪽 380원 쿠폰</strong>, 공유 카운트도 +1 🍀
        </div>
      </div>
      <div style={{fontSize:10,color:"var(--mist)",textAlign:"center",padding:"6px 10px",background:"rgba(212,175,55,0.06)",borderRadius:8,border:"1px solid rgba(212,175,55,0.12)"}}>📋 이 결과는 <strong style={{color:"var(--gold)"}}>기록소</strong>에서 언제든 다시 볼 수 있어요</div>
    </div>
  );
}

// 두 사진이 가운데서 만나 합성되는 로딩 애니 (조선초상화·2세 예측 등)
function PhotoMergeLoader({duration=15000,leftSrc,rightSrc,leftLabel,rightLabel,centerLabel,messages=[]}:{duration?:number,leftSrc:string|null,rightSrc:string|null,leftLabel?:string,rightLabel?:string,centerLabel?:string,messages?:string[]}){
  const[pct,setPct]=useState(0);
  const[msgIdx,setMsgIdx]=useState(0);
  useEffect(()=>{
    setPct(0);setMsgIdx(0);let p=0;
    const iv=setInterval(()=>{
      p=Math.min(100,p+(100/(duration/180)));setPct(Math.floor(p));
      if(Math.random()>0.85)setMsgIdx(i=>(i+1)%(messages.length||1));
      if(p>=100)clearInterval(iv);
    },180);
    return()=>clearInterval(iv);
  },[duration]);
  // 진행도 ~50%까지: 양쪽 사진이 가운데로 이동, ~80%까지: 합성 글로우, ~100%: 반짝
  const phase=pct<50?"approach":pct<80?"merge":"reveal";
  // v509: tx 최대값 18→34% (사진이 가운데까지 가깝게 모이게).
  // centerLabel 있을 때만 가운데 글자 침범 방지로 18% 유지, 없을 때는 34% 허용
  const txMax=centerLabel?22:34;
  const tx=Math.min(txMax,(pct/50)*txMax);
  // merge phase 이후엔 양쪽 사진을 더 투명하게 — 가운데 합성 글자가 주인공
  const opacity=phase==="reveal"?0.4:phase==="merge"?0.45:0.85;
  return(
    <div style={{padding:"20px 12px",textAlign:"center"}}>
      <div style={{position:"relative",width:"100%",maxWidth:340,height:180,margin:"0 auto 18px"}}>
        {/* 글로우 배경 — centerLabel 있을 때만 노출 (이모지 뒤 후광용) */}
        {phase!=="approach"&&centerLabel&&<div style={{position:"absolute",top:50,left:"50%",transform:"translate(-50%,-50%)",width:160,height:160,borderRadius:"50%",background:"radial-gradient(circle,rgba(212,175,55,0.5) 0%,rgba(212,175,55,0.18) 40%,transparent 70%)",filter:"blur(8px)",animation:"pulse 1.6s ease-in-out infinite",zIndex:1}}/>}
        {/* 왼쪽 사진 — 사진을 컨테이너 위쪽 100px 영역에 배치 (top:0 ~ 100), 라벨은 그 아래 */}
        <div style={{position:"absolute",top:0,left:`calc(${tx}% - 50px)`,transition:"left .18s linear",zIndex:2}}>
          <div style={{width:100,height:100,borderRadius:"50%",overflow:"hidden",border:"3px solid var(--gold)",boxShadow:"0 4px 20px rgba(212,175,55,0.35)",background:"linear-gradient(135deg,#1a2a4a,#0d1a2e)",opacity}}>
            {leftSrc?<img src={leftSrc} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>:<div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:36}}>👤</div>}
          </div>
          {leftLabel&&<div style={{fontSize:9,color:"var(--gold)",fontWeight:700,marginTop:4,textAlign:"center"}}>{leftLabel}</div>}
        </div>
        {/* 오른쪽 사진 */}
        <div style={{position:"absolute",top:0,right:`calc(${tx}% - 50px)`,transition:"right .18s linear",zIndex:2}}>
          <div style={{width:100,height:100,borderRadius:"50%",overflow:"hidden",border:"3px solid var(--gold)",boxShadow:"0 4px 20px rgba(212,175,55,0.35)",background:"linear-gradient(135deg,#1a2a4a,#0d1a2e)",opacity}}>
            {rightSrc?<img src={rightSrc} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>:<div style={{width:"100%",height:"100%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:36}}>{rightLabel?.includes("조선")?"👑":rightLabel?.includes("아빠")?"👨":"✨"}</div>}
          </div>
          {rightLabel&&<div style={{fontSize:9,color:"var(--gold)",fontWeight:700,marginTop:4,textAlign:"center"}}>{rightLabel}</div>}
        </div>
        {/* 가운데 합성 표시 — 사진 중심 (top:50px). 항상 표시 (phase 변동 없음 — 위치 안정) */}
        {centerLabel&&<div style={{position:"absolute",top:50,left:"50%",transform:"translate(-50%,-50%)",width:90,height:90,borderRadius:"50%",background:phase==="approach"?"radial-gradient(circle,rgba(212,175,55,0.5) 0%,rgba(212,175,55,0.2) 60%,transparent 100%)":"radial-gradient(circle,rgba(212,175,55,0.95) 0%,rgba(212,175,55,0.5) 60%,transparent 100%)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:52,filter:phase==="approach"?"drop-shadow(0 0 8px rgba(212,175,55,0.5))":"drop-shadow(0 0 18px rgba(212,175,55,1))",animation:"pulse 1.4s ease-in-out infinite",zIndex:10,textShadow:"0 0 12px rgba(255,255,255,0.9)",opacity:phase==="approach"?0.55:1,transition:"all 0.4s ease"}}>{centerLabel}</div>}
      </div>
      {/* 진행도 바 */}
      <div style={{height:8,background:"rgba(255,255,255,0.06)",borderRadius:99,marginBottom:8,overflow:"hidden",maxWidth:300,margin:"0 auto 8px"}}>
        <div style={{height:"100%",width:`${pct}%`,background:"linear-gradient(90deg,var(--gold),var(--gold3))",transition:"width .18s linear"}}/>
      </div>
      <div style={{fontSize:14,fontWeight:700,color:"var(--gold)",marginBottom:6}}>{pct}%</div>
      <div style={{fontSize:11,color:"var(--mist)",minHeight:20}}>{messages[msgIdx]||"분석 중..."}</div>
      <LoadingHint/>
    </div>
  );
}

function ResultActions({isLoggedIn, onLoginRequest, onShare, captureId}:{isLoggedIn?:boolean,onLoginRequest?:()=>void,onShare?:()=>void,captureId?:string}){
  const[capturing,setCapturing]=useState(false);
  const rootRef=useRef<HTMLDivElement>(null);
  // 캡처 대상 element 결정 — captureId 우선, fallback: 가장 가까운 .md 모달 본문
  function findCaptureEl():HTMLElement|null{
    if(captureId){const el=document.getElementById(captureId);if(el)return el;}
    // fallback: 가장 가까운 .md 조상 (모달 본문 전체 캡처)
    let p:HTMLElement|null=rootRef.current;
    while(p){
      if(p.classList?.contains("md"))return p;
      p=p.parentElement;
    }
    return null;
  }
  // 결과 카드 캡처 → Canvas 반환 (재사용 가능)
  async function capture():Promise<HTMLCanvasElement|null>{
    const el=findCaptureEl();
    if(!el)return null;
    await document.fonts.ready;
    await new Promise(r=>setTimeout(r,300));
    const html2canvas=(await import('html2canvas')).default;
    const origPT=el.style.paddingTop;const origPB=el.style.paddingBottom;
    el.style.paddingTop="32px";el.style.paddingBottom="32px";
    const canvas=await html2canvas(el,{backgroundColor:"#ffffff",scale:window.devicePixelRatio||2,useCORS:true,windowWidth:el.scrollWidth,scrollX:0,scrollY:-window.scrollY});
    el.style.paddingTop=origPT;el.style.paddingBottom=origPB;
    return canvas;
  }
  async function saveToPhone(){
    setCapturing(true);
    try{
      const canvas=await capture();
      if(!canvas)throw new Error("capture failed");
      const link=document.createElement('a');
      link.download=`chungi_result_${Date.now()}.png`;
      link.href=canvas.toDataURL('image/png');
      link.click();
    }catch{alert("이미지 저장에 실패했어요. 스크린샷으로 저장해주세요!");}
    setCapturing(false);
  }
  // PDF 다운로드 — 결과 카드를 A4 PDF로 (자동 페이지 분할)
  async function downloadAsPDF(){
    setCapturing(true);
    try{
      const canvas=await capture();
      if(!canvas)throw new Error("capture failed");
      const{jsPDF}=await import("jspdf");
      const imgData=canvas.toDataURL("image/png");
      const pdf=new jsPDF({orientation:"portrait",unit:"mm",format:"a4"});
      const pageW=pdf.internal.pageSize.getWidth();
      const pageH=pdf.internal.pageSize.getHeight();
      const imgW=pageW-20;
      const imgH=(canvas.height*imgW)/canvas.width;
      let heightLeft=imgH;let position=10;
      pdf.addImage(imgData,"PNG",10,position,imgW,imgH,undefined,"FAST");
      heightLeft-=(pageH-20);
      while(heightLeft>0){
        position=heightLeft-imgH+10;pdf.addPage();
        pdf.addImage(imgData,"PNG",10,position,imgW,imgH,undefined,"FAST");
        heightLeft-=(pageH-20);
      }
      pdf.save(`chungi_result_${new Date().toISOString().slice(0,10)}.pdf`);
    }catch{alert("PDF 생성에 실패했어요. 잠시 후 다시 시도해주세요!");}
    setCapturing(false);
  }
  // Web Share API + 이미지 첨부 (모바일 우선)
  async function shareWithImage(){
    setCapturing(true);
    try{
      const canvas=await capture();
      if(!canvas){setCapturing(false);return;}
      const blob:Blob=await new Promise(r=>canvas.toBlob(b=>r(b!),'image/png',0.92));
      const file=new File([blob],`chungi_result_${Date.now()}.png`,{type:'image/png'});
      // Web Share API 지원 + 파일 공유 가능 시
      const nav:any=navigator;
      if(nav.canShare&&nav.canShare({files:[file]})){
        await nav.share({title:'천기 - 나의 운세 결과',text:'천기에서 분석한 내 결과 봐줘! 🔮',files:[file]});
        handleShare("native");
        setCapturing(false);
        return;
      }
      // fallback: 다운로드 후 안내
      const link=document.createElement('a');
      link.download=`chungi_result_${Date.now()}.png`;
      link.href=canvas.toDataURL('image/png');
      link.click();
      alert('이미지가 저장됐어요! 인스타·카톡에 직접 첨부하세요 📸');
      handleShare("download");
    }catch(err:any){
      if(err?.name!=="AbortError")alert("공유에 실패했어요. 다시 시도해주세요!");
    }
    setCapturing(false);
  }

  function handleShare(method:string){
    try{
      const dayKey=`chungi_share_day_${new Date().toISOString().slice(0,10)}`;
      const dayCount=parseInt(localStorage.getItem(dayKey)||"0");
      if(dayCount>=10){alert("오늘 공유 횟수를 초과했어요! 내일 다시 시도해주세요");return;}
      localStorage.setItem(dayKey,String(dayCount+1));
      const totalKey="chungi_share_total";
      const total=parseInt(localStorage.getItem(totalKey)||"0")+1;
      localStorage.setItem(totalKey,String(total));
    }catch{}
    onShare?.();
  }

  // 내 초대 링크 — 공유·복사 모두 이 URL로 통일 (카운트 로직이 ?ref= 도착 기준)
  function getInviteUrl(){
    let code="";
    try{
      code=localStorage.getItem("chungi_referral_code")||"";
      if(!code){code="CG"+Math.random().toString(36).substring(2,6).toUpperCase();localStorage.setItem("chungi_referral_code",code);}
    }catch{}
    return `https://chungi.kr/?ref=${code}`;
  }
  async function shareKakao(){
    const inviteUrl=getInviteUrl();
    const jsKey=process.env.NEXT_PUBLIC_KAKAO_JS_KEY||'';
    for(let i=0;i<15;i++){
      const K=(typeof window!=='undefined'&&(window as any).Kakao)||null;
      if(K){
        if(!K.isInitialized()&&jsKey){try{K.init(jsKey);}catch{}}
        if(K.isInitialized())break;
      }
      await new Promise(r=>setTimeout(r,100));
    }
    try{
      const K=(window as any).Kakao;
      if(K?.isInitialized?.()){
        K.Share.sendDefault({
          objectType:'feed',
          content:{title:'천기 - AI 관상 스캐너',description:'내 초대 링크로 가입하면 양쪽 380원 쿠폰! 사주·관상·뇌과학 3초 분석 🔮',imageUrl:'https://chungi.kr/logo8.png',link:{mobileWebUrl:inviteUrl,webUrl:inviteUrl}},
          buttons:[{title:'380원 쿠폰 받고 시작하기',link:{mobileWebUrl:inviteUrl,webUrl:inviteUrl}}],
        });
        handleShare("kakao");return;
      }
    }catch(e){console.error("Kakao share error:",e);}
    navigator.clipboard?.writeText(inviteUrl).then(()=>alert('💬 카톡 공유가 안 돼서 링크를 대신 복사했어요!\n카톡 채팅창에 붙여넣어 친구에게 보내주세요 🔗\n\n'+inviteUrl)).catch(()=>alert('🔗 내 초대 링크\n\n'+inviteUrl+'\n\n복사해서 친구에게 보내주세요!'));
    handleShare("kakao");
  }
  function shareInsta(){window.open('https://www.instagram.com/','_blank');handleShare("insta");}
  function shareThreads(){window.open('https://www.threads.net/intent/post?text='+encodeURIComponent('천기에서 내 운세 확인해봐! 🔮 '+getInviteUrl()),'_blank');handleShare("threads");}
  function shareFacebook(){window.open('https://www.facebook.com/sharer/sharer.php?u='+encodeURIComponent(getInviteUrl()),'_blank');handleShare("facebook");}
  function copyLink(){const url=getInviteUrl();navigator.clipboard?.writeText(url).then(()=>alert('내 초대 링크가 복사되었어요!\n가입·결제 시 양쪽 380원 쿠폰 🎁'));handleShare("link");}

  const btnStyle:any={display:"flex",flexDirection:"column",alignItems:"center",gap:4,padding:"10px 4px",borderRadius:12,background:"#ffffff",border:"2px solid rgba(212,175,55,0.4)",cursor:"pointer",flex:1,minWidth:0,boxShadow:"0 2px 8px rgba(0,0,0,0.06)"};

  return(
    <div ref={rootRef} style={{marginBottom:14}}>
      {!isLoggedIn&&(
        <div style={{background:"#fffbe9",border:"2px solid rgba(212,175,55,0.4)",borderRadius:12,padding:"12px",marginBottom:12,textAlign:"center",boxShadow:"0 2px 8px rgba(0,0,0,0.06)"}}>
          <button onClick={onLoginRequest} style={{fontSize:12,fontWeight:700,color:"#1A3C32",background:"none",border:"1px solid rgba(212,175,55,0.5)",borderRadius:20,padding:"8px 20px",cursor:"pointer",fontFamily:"inherit"}}>☁️ 로그인하고 저장해요!</button>
        </div>
      )}

      <div style={{fontSize:12,fontWeight:700,color:"var(--gold)",textAlign:"center",marginBottom:10}}>📸 스크린샷으로 캡쳐해서 친구에게 공유하세요!</div>
      <div style={{display:"flex",gap:8,marginBottom:8}}>
        <div style={{...btnStyle,flex:1}} onClick={shareKakao}><span style={{fontSize:20}}>💬</span><span style={{fontSize:10,color:"#1A3C32",fontWeight:700}}>카카오톡으로 공유하기</span></div>
        <div style={{...btnStyle,flex:1}} onClick={copyLink}><span style={{fontSize:20}}>🔗</span><span style={{fontSize:10,color:"#1A3C32",fontWeight:700}}>링크 복사하기</span></div>
      </div>
      {/* 초대 안내 — 카톡/링크 버튼 톤에 맞춘 옅은 골드 인포 */}
      <div style={{background:"rgba(212,175,55,0.07)",border:"1px solid rgba(212,175,55,0.2)",borderRadius:10,padding:"9px 12px",marginBottom:12,display:"flex",alignItems:"center",gap:9}}>
        <span style={{fontSize:16,flexShrink:0}}>🎁</span>
        <div style={{flex:1,minWidth:0,fontSize:10,color:"var(--mist)",lineHeight:1.5}}>
          위 링크는 <strong style={{color:"var(--gold)"}}>내 초대 코드</strong>가 포함돼요.<br/>친구가 가입·결제하면 <strong style={{color:"var(--gold)"}}>양쪽 380원 쿠폰</strong>, 공유 카운트도 +1 🍀
        </div>
      </div>
      <div style={{fontSize:10,color:"var(--mist)",textAlign:"center",padding:"6px 10px",background:"rgba(212,175,55,0.06)",borderRadius:8,border:"1px solid rgba(212,175,55,0.12)"}}>📋 이 결과는 <strong style={{color:"var(--gold)"}}>기록소</strong>에서 언제든 다시 볼 수 있어요</div>
    </div>
  );
}

// ━━━ 표준 유명인 매칭 섹션 (모든 결과팝업 공통) ━━━
// 결과팝업 화이트카드 안에 들어가는 "같은 X 유명인 10명" 섹션. 절대 디자인 변경 금지 — 한 곳에서만 관리.
// 사용처: 돌잡이·기질도·뇌과학·수비학·전생 등 모든 type-based 결과
function CelebMatchSection({label, emoji, celebs, prefix, theme}:{label:string, emoji?:string, celebs:string[], prefix?:string, theme?:{bg?:string,accent?:string,accent2?:string,soft?:string,text?:string,hint?:string,chipBg?:string,chipBorder?:string}}){
  if(!celebs||celebs.length===0)return null;
  // theme 있으면 다크 톤 사용 (수비학 등), 없으면 기본 화이트 (다른 콘텐츠)
  const bg=theme?.bg||"#fff";
  const labelColor=theme?.hint||"#7A5C00";
  const chipColor=theme?.text||"#1A3C32";
  const chipBg=theme?.chipBg||"#fffbe9";
  const chipBorder=theme?.chipBorder||"1px solid rgba(212,175,55,0.4)";
  const noteColor=theme?.hint||"#888";
  return (
    <div style={{background:bg,borderRadius:16,padding:"18px",marginBottom:12,boxShadow:"0 4px 20px rgba(0,0,0,0.14)",border:theme?`1px solid ${theme.soft||"rgba(255,255,255,0.1)"}`:"none"}}>
      <div style={{fontSize:9,color:labelColor,letterSpacing:3,marginBottom:10,fontWeight:600,textAlign:"center"}}>{emoji||"✨"} {label}</div>
      {/* v597: 관상짤 사이즈로 통일 — fontSize 10, padding 4x8, gap 5 (전체 컴팩트) */}
      <div style={{display:"flex",flexWrap:"wrap",gap:5,marginBottom:6,justifyContent:"center"}}>
        {celebs.map((cn:string)=>(
          <a key={cn} href={`https://search.naver.com/search.naver?query=${encodeURIComponent(cn)}`} target="_blank" rel="noreferrer" style={{fontSize:10,fontWeight:700,color:chipColor,padding:"4px 8px",background:chipBg,border:chipBorder,borderRadius:12,textDecoration:"none"}}>{prefix?prefix+" ":""}{cn}</a>
        ))}
      </div>
      <div style={{fontSize:9,color:noteColor,textAlign:"center",lineHeight:1.5}}>이름 클릭 시 네이버 검색</div>
    </div>
  );
}

