  numerology:   [{key:"focus",multi:true,title:"특별히 더 강조해서 봐드릴 부분이 있나요?",hint:"건너뛰면 전체 균등 / 선택하면 해당 항목 더 깊이",skipable:true,opts:[{e:"🔢",l:"나의 생명수·표현수 의미"},{e:"💰",l:"재물·금전을 부르는 숫자"},{e:"❤️",l:"인연·궁합 숫자"},{e:"📜",l:"시험·합격·관운 숫자"},{e:"🌟",l:"올해 운명수·개인년수"},{e:"🔐",l:"행운 번호·비밀번호에 쓸 숫자"},{e:"💼",l:"직업·사업에 맞는 숫자"},{e:"🌈",l:"전체 다 강조해서 봐줘!",all:true},{e:"💭",l:"기타",custom:true}]}],
  namereading:  [{key:"focus",multi:true,title:"특별히 더 강조해서 봐드릴 부분이 있나요?",hint:"건너뛰면 전체 균등 / 선택하면 해당 항목 더 깊이",skipable:true,opts:[{e:"💰",l:"재물운에 미치는 영향"},{e:"❤️",l:"인연·결혼운에 미치는 영향"},{e:"💼",l:"직업·사업·출세운에 미치는 영향"},{e:"📜",l:"시험·관운·합격운에 미치는 영향"},{e:"🌿",l:"건강운에 미치는 영향"},{e:"🧠",l:"성격·기질·대인관계에 미치는 영향"},{e:"🌈",l:"전체 다 강조해서 봐줘!",all:true},{e:"💭",l:"기타",custom:true}]}],
