function PreQuestionFlow({svcId,iconTitle,subtitle,onComplete,onClose,onBack,embedded=false,initialQStep=0,initialAnswers={}}:{svcId:string,iconTitle:string,subtitle?:string,onComplete:(answers:Record<string,any>)=>void,onClose:()=>void,onBack?:()=>void,embedded?:boolean,initialQStep?:number,initialAnswers?:Record<string,any>}){
  const questions=PRE_Q_CONFIG[svcId]||[];
  const[qStep,setQStep]=useState(initialQStep);
  const[answers,setAnswers]=useState<Record<string,any>>(initialAnswers);
  const[customText,setCustomText]=useState("");
  const[showCustom,setShowCustom]=useState(false);
  const q=questions[qStep];
  if(!q)return null;
  const totalQs=questions.length;
  const isLast=qStep===totalQs-1;
  const isMulti=!!q.multi;
  const currentVal=answers[q.key];
  const selected:string[]=isMulti?(Array.isArray(currentVal)?currentVal:[]):(currentVal?[currentVal]:[]);

  const advance=()=>{if(isLast)onComplete({...answers});else setQStep(qStep+1);setShowCustom(false);setCustomText("");};

  // v298: 자동 진입 제거 — 단일 선택도 "다음" 버튼 눌러야 진입 (수정 가능)
  const handlePick=(opt:PQOpt)=>{
    if(opt.custom){setShowCustom(true);return;}
    if(isMulti){
      // "전체 다" 토글 시 단독 선택
      if(opt.all){setAnswers({...answers,[q.key]:[opt.l]});return;}
      // 일반 옵션: "전체 다" 해제 + 토글
      let next=selected.filter(x=>!questions[qStep].opts.find(o=>o.l===x&&o.all));
      next=next.includes(opt.l)?next.filter(x=>x!==opt.l):[...next,opt.l];
      setAnswers({...answers,[q.key]:next});
    }else{
      // 단일 선택: 답 저장 (자동 진입 X — "다음" 버튼). 이미 고른 걸 다시 누르면 해제(건너뛰기 복귀 가능)
      const next={...answers};
      if(currentVal===opt.l)delete next[q.key]; else next[q.key]=opt.l;
      setAnswers(next);
    }
  };

  const handleCustomConfirm=()=>{
    if(!customText.trim()){alert("내용을 입력해주세요");return;}
    const tag=`[기타] ${customText}`;
    if(isMulti){
      const next=[...selected.filter(s=>!s.startsWith("[기타]")),tag];
      setAnswers({...answers,[q.key]:next});
      setShowCustom(false);setCustomText("");
    }else{
      // 단일 선택 기타: 답만 저장 (자동 진입 X)
      setAnswers({...answers,[q.key]:tag});
      setShowCustom(false);setCustomText("");
    }
  };

  // v757: 표준 레이아웃 — 모든 사전질문 통일
  // L1 제목(mt 19px) → L2 부제목(ms 12px) → L3 진행바(3px) → L4 안내박스(11px 자동 생성) → L5 질문(13px 보통, 제목과 차별화)
  // hint 자동 생성: multi/skipable 조합으로 표준 멘트 (PRE_Q_CONFIG hint 필드는 무시 — 콘텐츠마다 다른 멘트가 통일 불가 원인)
  const autoHint = q.multi && q.skipable
    ? "여러 개 선택 가능 · 건너뛰기 가능"
    : q.multi
      ? "여러 개 선택 가능 — 폭넓게 분석"
      : q.skipable
        ? "건너뛰기 가능 — 전체 균등 분석"
        : "가장 가까운 것 하나만 선택";
  const content=<>
      <div className="mt">{iconTitle}</div>
      <div className="ms">{qStep+1}/{totalQs}{subtitle?` · ${subtitle}`:""}</div>
      <div style={{height:3,background:"rgba(255,255,255,0.06)",borderRadius:99,marginBottom:14,overflow:"hidden"}}>
        <div style={{height:"100%",width:`${((qStep+1)/totalQs)*100}%`,background:"var(--gold)",transition:"width .3s"}}/>
      </div>
      <div style={{fontSize:11,color:"var(--mist)",marginBottom:12,lineHeight:1.6,padding:"8px 11px",background:"rgba(212,175,55,0.06)",borderRadius:8,border:"1px solid rgba(212,175,55,0.12)"}}>💡 {autoHint}</div>
      <div style={{fontSize:13,fontWeight:600,color:"var(--white)",marginBottom:12,lineHeight:1.5}}>{q.title}</div>
      <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:12}}>
        {q.opts.map(opt=>{
          const sel=selected.includes(opt.l);
          return(<button key={opt.l} onClick={()=>handlePick(opt)} style={{display:"flex",alignItems:"center",gap:10,padding:"13px 14px",background:sel?"rgba(212,175,55,0.12)":"var(--ink3)",border:sel?"1.5px solid var(--gold)":"1.5px solid rgba(255,255,255,0.06)",borderRadius:12,cursor:"pointer",textAlign:"left",fontFamily:"inherit",transition:"all .18s"}}>
            <span style={{fontSize:18,flexShrink:0}}>{opt.e}</span>
            <div style={{flex:1}}>
              <div style={{fontSize:13,fontWeight:700,color:sel?"var(--gold)":"var(--white)"}}>{opt.l}</div>
              {opt.s&&<div style={{fontSize:10,color:"var(--mist)",marginTop:1}}>{opt.s}</div>}
            </div>
            {isMulti&&<div style={{width:18,height:18,borderRadius:4,border:`1.5px solid ${sel?"var(--gold)":"rgba(168,196,184,0.3)"}`,background:sel?"var(--gold)":"transparent",display:"flex",alignItems:"center",justifyContent:"center",color:"var(--ink)",fontSize:11,fontWeight:900,flexShrink:0}}>{sel?"✓":""}</div>}
          </button>);
        })}
      </div>
      {showCustom&&(
        <div style={{marginBottom:12,padding:"12px",background:"var(--ink3)",borderRadius:12,border:"1px solid rgba(212,175,55,0.25)"}}>
          <input value={customText} onChange={e=>setCustomText(e.target.value.slice(0,80))} placeholder="직접 입력하세요" autoFocus style={{width:"100%",padding:"10px",background:"var(--ink2)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:8,color:"#fff",fontSize:13,fontFamily:"inherit"}} onKeyDown={e=>{if(e.key==="Enter")handleCustomConfirm();}}/>
          <div style={{display:"flex",gap:6,marginTop:8}}>
            <button onClick={()=>{setShowCustom(false);setCustomText("");}} style={{flex:1,padding:9,background:"transparent",border:"1px solid rgba(255,255,255,0.1)",borderRadius:8,color:"var(--mist)",fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>취소</button>
            <button onClick={handleCustomConfirm} style={{flex:1,padding:9,background:"var(--gold)",border:"none",borderRadius:8,color:"var(--ink)",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>확인</button>
          </div>
        </div>
      )}
      {/* v298: 다음 버튼 — 단일/다중 모두 선택 후 노출 (자동진입 X, 사용자가 직접 클릭) */}
      {selected.length>0&&(
        <button className="btn btn-p" style={{marginBottom:8}} onClick={advance}>{isLast?"✨ 완료하고 결과 보기":(isMulti?`다음 → (${selected.length}개 선택)`:"다음 →")}</button>
      )}
      {q.skipable&&selected.length===0&&(
        <button onClick={advance} style={{width:"100%",padding:11,background:"transparent",border:"1px dashed rgba(212,175,55,0.25)",borderRadius:12,color:"var(--gold)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",marginBottom:8}}>건너뛰기 →</button>
      )}
      <div style={{display:"flex",gap:6}}>
        <button onClick={()=>{if(qStep>0)setQStep(qStep-1);else if(onBack)onBack();else onClose();}} className="btn btn-g" style={{flex:1,marginTop:0,fontSize:12}}>← 이전</button>
        <button className="btn btn-g" style={{flex:1,marginTop:0}} onClick={onClose}>닫기</button>
      </div>
  </>;

  // embedded: 부모 모달 안에 그냥 콘텐츠로 렌더 (휘리릭/슬라이드업 애니메이션 회피)
  if(embedded) return content;

  return(
    <div className="ov"><div className="md"><div className="hd"/>
      <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}>
        <button onClick={onClose} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>
      </div>
      {content}
    </div></div>
  );
}

function CouponCodeInput({onAdded}:{onAdded:(c:any)=>void}){
  const[code,setCode]=useState("");
  const[busy,setBusy]=useState(false);
  const[err,setErr]=useState("");
  // DEMO 쿠폰 (서버 미연동 시 fallback) — 어드민 등록 코드 + 카톡 채널 쿠폰 수동 입력 지원
  // expDays: 발급일로부터 N일 후 만료 (어드민 정책과 일치)
  const DEMO_REDEEM:any={
    "WELCOME":{name:"🎉 가입 환영 1,000원 쿠폰",discount:"1,000원",discount_amount:1000,minPrice:1980,target:"전 상품",expDays:30},
    "FREELOOK":{name:"🎁 관상짤 무료 쿠폰",discount:"380원",discount_amount:380,minPrice:380,target:"관상짤",expDays:30},
    "OPEN500":{name:"🎊 오픈 기념 500원 쿠폰",discount:"500원",discount_amount:500,minPrice:980,target:"전 상품",expDays:30},
    "WELCOME280":{name:"🎉 관상짤 280원 할인 (카톡 친추)",discount:"280원",discount_amount:280,minPrice:100,target:"관상짤",expDays:7},
    "PREMIUM2000":{name:"💎 프리미엄 2,800원 할인 (카톡 친추)",discount:"2,800원",discount_amount:2800,minPrice:2000,target:"4,800원 프리미엄 콘텐츠",expDays:3},
    "NEWSAJU500":{name:"🌱 새싹 응원 쿠폰",discount:"500원",discount_amount:500,minPrice:980,target:"전 콘텐츠",expDays:3},
    "NEWGOODS10":{name:"🛍️ 첫 굿즈 구매 10% 할인",discount:"10%",discount_amount:0,discount_percent:10,minPrice:10000,target:"굿즈샵",expDays:365},
  };
  async function redeem(){
    const c=code.trim().toUpperCase();
    if(!c){setErr("코드를 입력해주세요");return;}
    setBusy(true);setErr("");
    // 1) 서버 API 시도 (로그인 시)
    try{
      const userId=(typeof window!=="undefined"&&localStorage.getItem("chungi_user_id"))||null;
      if(userId){
        const r=await fetch("/api/coupons/redeem",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({user_id:userId,code:c})});
        const j=await r.json();
        if(r.ok&&j.coupon){
          onAdded({...j.coupon,minPrice:j.coupon.min_price||0,discount:`${j.coupon.discount_amount.toLocaleString()}원`,target:j.coupon.target_service||"전 상품"});
          setCode("");setBusy(false);return;
        }
        if(j.error){setErr(j.error);setBusy(false);return;}
      }
    }catch{}
    // 2) Fallback: 로컬 DEMO 쿠폰
    const demo=DEMO_REDEEM[c];
    if(demo){
      // 중복 체크 (localStorage)
      try{
        const cps=JSON.parse(localStorage.getItem("chungi_coupons")||"[]");
        if(cps.find((x:any)=>x.code===c)){setErr("이미 등록된 코드예요");setBusy(false);return;}
      }catch{}
      // v389: expDays 적용 — 코드별 다른 만료 (WELCOME280=7일, PREMIUM2000=3일 등)
      const days=demo.expDays||30;
      onAdded({code:c,...demo,used:false,expires:`발급일로부터 ${days}일`,expires_at:new Date(Date.now()+days*86400000).toISOString()});
      setCode("");setBusy(false);return;
    }
    setErr("유효하지 않은 코드예요");setBusy(false);
  }
  return <div style={{marginTop:10,padding:"10px 12px",background:"rgba(212,175,55,0.06)",border:"1px dashed rgba(212,175,55,0.25)",borderRadius:11}}>
    <div style={{fontSize:10,color:"var(--gold)",fontWeight:700,marginBottom:6}}>🎁 쿠폰 코드 등록</div>
    <div style={{display:"flex",gap:6}}>
      <input value={code} onChange={e=>{setCode(e.target.value);setErr("");}} placeholder="예: WELCOME" style={{flex:1,padding:"9px 12px",background:"var(--ink3)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:9,color:"var(--white)",fontFamily:"inherit",fontSize:12,outline:"none",textTransform:"uppercase"}}/>
      <button onClick={redeem} disabled={busy||!code} style={{padding:"9px 14px",borderRadius:9,border:"none",background:busy||!code?"rgba(212,175,55,0.2)":"var(--gold)",color:busy||!code?"var(--mist)":"var(--ink)",fontSize:12,fontWeight:800,cursor:busy||!code?"default":"pointer",fontFamily:"inherit"}}>{busy?"...":"등록"}</button>
    </div>
    {err&&<div style={{fontSize:10,color:"var(--coral)",marginTop:5}}>{err}</div>}
  </div>;
}

function PayStepComp({price,onPay,onBack,loading,svcId}:any){
  const[m,setM]=useState("kakao");
  const[selectedCoupon,setSelectedCoupon]=useState<any>(null);
  const[useCash,setUseCash]=useState(false);
  const[cashAmount,setCashAmount]=useState(0);
  const[couponOpen,setCouponOpen]=useState(false);
  const[useTicket,setUseTicket]=useState(false);
  const[ticketOpen,setTicketOpen]=useState(false);
  // 해당 콘텐츠 이용권 조회
  const allTickets=(()=>{try{return JSON.parse(localStorage.getItem("chungi_my_tickets")||"[]");}catch{return [];}})();
  const availableTickets=svcId?allTickets.filter((t:any)=>t.svcId===svcId&&!t.used):[];
  const ticketDiscount=useTicket&&availableTickets.length>0?parseInt(String(price).replace(/[^0-9]/g,""))||0:0;
  const [cashBalance] = useState(() => {
    try { return parseInt(localStorage.getItem("chungi_cash_balance") || "0"); } catch { return 0; }
  });
  const allCoupons = (() => {
    try { return JSON.parse(localStorage.getItem("chungi_coupons") || "[]"); } catch { return []; }
  })();

  const origPrice = parseInt(String(price).replace(/[^0-9]/g,""))||0;
  // 미사용 쿠폰 전부 보여주되, 가격 조건 안 맞으면 비활성
  const displayCoupons = allCoupons.filter((c:any) => !c.used);
  const couponDiscount = selectedCoupon ? (selectedCoupon.discount_amount || parseInt(String(selectedCoupon.discount).replace(/[^0-9]/g,"")) || selectedCoupon.discountValue || 0) : 0;
  const cashDiscount = useCash ? cashAmount : 0;
  const remaining = useTicket&&availableTickets.length>0 ? 0 : Math.max(0, origPrice - couponDiscount - cashDiscount);

  return(
    <>
      {/* Cash section */}
      <div style={{background:"rgba(212,175,55,0.08)",borderRadius:12,padding:"12px",marginBottom:12}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:useCash?10:0}}>
          <div>
            <div style={{fontSize:11,color:"var(--mist)"}}>💰 보유 캐시</div>
            <div style={{fontSize:16,fontWeight:900,color:"var(--gold)"}}>{cashBalance.toLocaleString()}원</div>
          </div>
          <button onClick={()=>{if(cashBalance<=0)return;setUseCash(v=>!v);if(!useCash)setCashAmount(Math.min(cashBalance,origPrice-couponDiscount));}} disabled={cashBalance<=0} style={{padding:"6px 14px",borderRadius:10,background:useCash?"var(--gold)":"rgba(212,175,55,0.15)",color:useCash?"var(--ink)":"var(--gold)",border:"none",fontSize:11,fontWeight:700,cursor:cashBalance<=0?"default":"pointer",fontFamily:"inherit",opacity:cashBalance<=0?0.4:1}}>
            {useCash?"캐시 적용 중 ✓":"캐시 사용"}
          </button>
        </div>
        {useCash&&cashBalance>0&&(
          <div>
            <div style={{display:"flex",alignItems:"center",gap:6}}>
              <input type="range" min={0} max={Math.min(cashBalance,origPrice-couponDiscount)} value={cashAmount} onChange={e=>setCashAmount(parseInt(e.target.value))} style={{flex:1,accentColor:"var(--gold)"}}/>
              <span style={{fontSize:12,fontWeight:700,color:"var(--gold)",minWidth:60,textAlign:"right"}}>{cashAmount.toLocaleString()}원</span>
            </div>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:9,color:"var(--mist)",marginTop:4}}>
              <span>0원</span>
              <span>최대 {Math.min(cashBalance,origPrice-couponDiscount).toLocaleString()}원</span>
            </div>
          </div>
        )}
      </div>

      {/* 쿠폰 선택 (접기/펼치기) */}
      <div style={{marginBottom:12,background:"var(--ink3)",borderRadius:14,padding:"12px",border:"1px solid rgba(255,255,255,0.06)"}}>
        <div onClick={()=>{if(useTicket)setUseTicket(false);setCouponOpen(v=>!v);setTicketOpen(false);}} style={{display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer"}}>
          <div style={{fontSize:12,fontWeight:700,color:"var(--mist)"}}>🎟️ 쿠폰 ({displayCoupons.length}장){selectedCoupon&&!couponOpen&&<span style={{color:"var(--gold)",marginLeft:6}}>✓ {selectedCoupon.name}</span>}</div>
          <span style={{fontSize:10,color:"var(--mist)",transition:"transform .2s",transform:couponOpen?"rotate(180deg)":"rotate(0)"}}>▾</span>
        </div>
        {!couponOpen&&!selectedCoupon&&!useTicket&&<div style={{fontSize:10,color:"rgba(168,196,184,0.3)",marginTop:4}}>눌러서 쿠폰 목록 보기</div>}
        {couponOpen&&<div style={{marginTop:8}}>
          {displayCoupons.length > 0 ? displayCoupons.map((c:any) => {
            const minP = c.minPrice||0;
            const canUse = origPrice >= minP;
            const isSelected = selectedCoupon?.code===c.code;
            return (
            <div key={c.code} onClick={()=>{if(!canUse)return;setSelectedCoupon(isSelected?null:c);setCouponOpen(false);}} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 12px",background:isSelected?"rgba(212,175,55,0.1)":"rgba(26,60,50,0.5)",border:`1px solid ${isSelected?"rgba(212,175,55,0.3)":"rgba(255,255,255,0.06)"}`,borderRadius:12,marginBottom:6,cursor:canUse?"pointer":"default",opacity:canUse?1:0.4}}>
              <div style={{flex:1}}>
                <div style={{fontSize:12,fontWeight:700,marginBottom:2}}>{c.name}</div>
                <div style={{fontSize:11,color:canUse?"var(--gold)":"var(--mist)",fontWeight:700,marginBottom:2}}>{c.discount} 할인</div>
                <div style={{fontSize:10,color:"var(--mist)"}}>{c.target}{!canUse&&<span style={{color:"var(--coral)"}}> · {minP.toLocaleString()}원 이상 상품만</span>}</div>
              </div>
              <div style={{width:16,height:16,borderRadius:"50%",border:`2px solid ${isSelected?"var(--gold)":canUse?"rgba(168,196,184,0.2)":"rgba(168,196,184,0.1)"}`,background:isSelected?"var(--gold)":"transparent",flexShrink:0}}/>
            </div>
            );
          }) : <div style={{fontSize:11,color:"rgba(168,196,184,0.3)",textAlign:"center",padding:"4px"}}>보유 쿠폰이 없어요</div>}
          {/* 쿠폰 코드 등록 */}
          <CouponCodeInput onAdded={(c:any)=>{
            try{
              const cps=JSON.parse(localStorage.getItem("chungi_coupons")||"[]");
              cps.push(c);
              localStorage.setItem("chungi_coupons",JSON.stringify(cps));
              setSelectedCoupon(c);setCouponOpen(false);
              alert(`🎉 ${c.name} 발급 완료!`);
            }catch{}
          }}/>
        </div>}
      </div>

      {/* 이용권 사용 (접기/펼치기) - 전체 목록 */}
      <div style={{marginBottom:12,background:"var(--ink3)",borderRadius:14,padding:"12px",border:"1px solid rgba(255,255,255,0.06)"}}>
        <div onClick={()=>{if(selectedCoupon)setSelectedCoupon(null);setTicketOpen(v=>!v);setCouponOpen(false);}} style={{display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer"}}>
          <div style={{fontSize:12,fontWeight:700,color:"var(--mist)"}}>💳 이용권 ({allTickets.filter((t:any)=>!t.used).length}장){useTicket&&<span style={{color:"var(--gold)",marginLeft:6}}>✓ 이용권 사용</span>}</div>
          <span style={{fontSize:10,color:"var(--mist)",transition:"transform .2s",transform:ticketOpen?"rotate(180deg)":"rotate(0)"}}>▾</span>
        </div>
        {!ticketOpen&&!useTicket&&!selectedCoupon&&<div style={{fontSize:10,color:"rgba(168,196,184,0.3)",marginTop:4}}>눌러서 이용권 목록 보기</div>}
        {ticketOpen&&(()=>{
          // 콘텐츠별 그룹핑 (미사용만)
          const grouped:Record<string,{name:string,icon:string,remaining:number}>={};
          for(const t of allTickets){
            if(t.used)continue;
            const key=t.svcId||t.name;
            if(!grouped[key])grouped[key]={name:t.name,icon:t.icon||"🎟️",remaining:0};
            grouped[key].remaining++;
          }
          const entries=Object.entries(grouped);
          return <div style={{marginTop:8}}>
            {entries.length>0?entries.map(([key,g])=>{
              const canUse=key===svcId;
              return <div key={key} onClick={()=>{if(!canUse)return;setUseTicket(v=>!v);if(!useTicket){setSelectedCoupon(null);setUseCash(false);setCashAmount(0);}}} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 12px",background:canUse&&useTicket?"rgba(212,175,55,0.1)":"rgba(26,60,50,0.5)",border:`1px solid ${canUse?"rgba(212,175,55,0.2)":"rgba(255,255,255,0.06)"}`,borderRadius:12,marginBottom:6,cursor:canUse?"pointer":"default",opacity:canUse?1:0.4}}>
                <div>
                  <div style={{fontSize:12,fontWeight:700}}>{g.icon} {g.name}</div>
                  <div style={{fontSize:10,color:canUse?"var(--gold)":"var(--mist)",marginTop:2}}>{canUse?`잔여 ${g.remaining}장 → 1장 사용 시 무료!`:`잔여 ${g.remaining}장 · 다른 콘텐츠 전용`}</div>
                </div>
                {canUse&&<div style={{width:16,height:16,borderRadius:"50%",border:"2px solid var(--gold)",background:useTicket?"var(--gold)":"transparent",flexShrink:0}}/>}
              </div>;
            }):<div style={{fontSize:11,color:"rgba(168,196,184,0.3)",textAlign:"center",padding:"4px"}}>보유 이용권이 없어요</div>}
          </div>;
        })()}
      </div>

      {/* 가격 박스 */}
      <div className="price-box">
        <div className="pr"><span>상품 가격</span><span>{origPrice.toLocaleString()}원</span></div>
        {useTicket&&<div className="pr"><span>🎟️ 이용권 사용</span><span style={{color:"var(--jade)"}}>-{origPrice.toLocaleString()}원 (무료)</span></div>}
        {!useTicket&&couponDiscount > 0 && <>
          <div className="pr"><span>쿠폰 할인</span><span style={{color:"var(--jade)"}}>-{couponDiscount.toLocaleString()}원</span></div>
          {selectedCoupon&&<div style={{fontSize:10,color:"var(--jade)",marginBottom:4,marginTop:-2}}>✨ {selectedCoupon.name} 적용!</div>}
        </>}
        {!useTicket&&cashDiscount > 0 && <div className="pr"><span>캐시 차감</span><span style={{color:"var(--jade)"}}>-{cashDiscount.toLocaleString()}원</span></div>}
        <div className="pr tot"><span>결제 금액</span><span>{remaining.toLocaleString()}원</span></div>
      </div>

      {/* 결제 수단 — 전액 할인이면 숨김 */}
      {remaining > 0 ? (
        <div>
          <div style={{fontSize:11,fontWeight:700,color:"var(--mist)",marginBottom:6}}>💳 결제 수단</div>
          <div className="pay-list">
            {[{id:"kakao",ic:"🟡",name:"카카오페이",desc:"원터치 간편결제"},{id:"toss",ic:"🔵",name:"토스페이",desc:"간편결제"},{id:"naver",ic:"💚",name:"네이버페이",desc:"포인트 적립"},{id:"card",ic:"💳",name:"카드결제",desc:"신용/체크카드"},{id:"phone",ic:"📱",name:"핸드폰 결제",desc:"통신사 결제"}].map(p=>(
              <div key={p.id} className={`pay-opt${m===p.id?" on":""}`} onClick={()=>setM(p.id)}>
                <div className="pay-l"><span style={{fontSize:20}}>{p.ic}</span><div><div className="pay-name">{p.name}</div><div className="pay-desc">{p.desc}</div></div></div>
                <div className={`radio${m===p.id?" on":""}`}/>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div style={{background:"rgba(95,196,158,0.1)",borderRadius:12,padding:"12px",marginBottom:12,textAlign:"center"}}>
          <div style={{fontSize:13,fontWeight:700,color:"var(--jade)"}}>✅ {useTicket?"이용권으로 무료 이용!":"쿠폰/캐시로 전액 결제!"}</div>
          <div style={{fontSize:11,color:"var(--mist)",marginTop:4}}>추가 결제 없이 바로 이용 가능</div>
        </div>
      )}

      {loading?<Dots/>:<button className="btn btn-p" style={useTicket?{background:"linear-gradient(135deg,var(--jade),#2a9d6a)"}:{}} onClick={async()=>{
        // 이용권 사용 시 1장 차감 → 로딩 없이 바로 결과
        if(useTicket&&availableTickets.length>0&&svcId){
          try{const tk=JSON.parse(localStorage.getItem("chungi_my_tickets")||"[]");
          const idx=tk.findIndex((t:any)=>t.svcId===svcId&&!t.used);
          if(idx>=0)tk[idx].used=true;
          localStorage.setItem("chungi_my_tickets",JSON.stringify(tk));}catch{}
          onPay("ticket");
          return;
        }
        // 쿠폰 사용 처리 (localStorage + 서버)
        if(selectedCoupon){
          try{
            const cps=JSON.parse(localStorage.getItem("chungi_coupons")||"[]");
            const idx=cps.findIndex((c:any)=>c.code===selectedCoupon.code&&!c.used);
            if(idx>=0){cps[idx].used=true;cps[idx].used_at=new Date().toISOString();localStorage.setItem("chungi_coupons",JSON.stringify(cps));}
          }catch{}
          // 서버 API 호출 (로그인 시 user_id 있으면)
          try{
            const userId=(typeof window!=="undefined"&&localStorage.getItem("chungi_user_id"))||null;
            if(userId&&selectedCoupon.id){
              await fetch("/api/coupons/use",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({user_id:userId,coupon_id:selectedCoupon.id,order_id:`order_${Date.now()}`,used_amount:couponDiscount})});
            }
          }catch{}
        }
        if(cashDiscount>0){try{const newBal=Math.max(0,cashBalance-cashDiscount);localStorage.setItem("chungi_cash_balance",String(newBal));}catch{}}
        onPay(m);
      }}>
        {useTicket?"🎟️ 이용권으로 바로 보기":remaining > 0 ? `${remaining.toLocaleString()}원 결제하기` : "결과 보기"}
      </button>}
      <button className="btn btn-g" onClick={onBack}>이전으로</button>
      <div style={{fontSize:10,color:"rgba(168,196,184,0.3)",marginTop:10,textAlign:"center",lineHeight:1.6}}>
        결제 후 결과 무한 열람 · 자동 저장<br/>
        
      </div>
    </>
  );
}

// 🛍️ 굿즈 추천 — Supabase `/api/goods`에서 공개(is_public=true) 상품만 가져와 추천
// 어드민이 숨김 처리한 상품은 자동으로 추천에서 제외됨. 0개면 "준비중" 배너.
let _liveVisibleGoodsCache:any[]|null=null;
let _liveVisibleGoodsPromise:Promise<any[]>|null=null;
function fetchLiveVisibleGoods():Promise<any[]>{
  if(_liveVisibleGoodsCache)return Promise.resolve(_liveVisibleGoodsCache);
  if(_liveVisibleGoodsPromise)return _liveVisibleGoodsPromise;
  _liveVisibleGoodsPromise=fetch('/api/goods')
    .then(r=>r.json())
    .then(d=>{
      const list=Array.isArray(d.goods)?d.goods:[];
      // Supabase 컬럼 → GOODS_DB 포맷으로 매핑
      _liveVisibleGoodsCache=list.map((g:any)=>({
        id:g.id,name:g.name,price:g.price,
        cat:g.category||g.cat||"",
        icon:g.icon||"📦",color:g.color||"var(--ink3)",
        tags:g.tags||[],rec:g.is_active??false,
      }));
      return _liveVisibleGoodsCache!;
    })
    .catch(()=>{_liveVisibleGoodsCache=[];return[];});
  return _liveVisibleGoodsPromise;
}
function filterLiveGoodsForSvc(svcId:string,ctx:any,goods:any[]):any[]{
  // 서비스별 카테고리/태그 키워드 매핑
  const keywordMap:Record<string,string[]>={
    pawdong:["오행","부족"],
    gwansang_zal:["기운","오행","부적"],gwansang_full:["기운","오행"],
    saju:["오행","수비학","기운"],saju_monthly:["오행","시즌"],
    love:["연애","애정","분위기"],
    ddi:["띠별","오행"],zodiac:["별자리","기운"],blood:["혈액형","향"],
    ytype:["수호신","오행"],
    dream:["부적","회복"],today_tarot:["운세","기운"],
    tarot_love:["연애","운세"],tarot_health:["회복","향"],
    tarot_money:["운세","기운"],tarot_career:["기운","수비학"],tarot_life:["운세","기운"],
    numerology:["수비학"],namereading:["오행"],pawdong_signature:["오행"],
    joseon_portrait:["외국부적","한국"],past_life:["전생"],
    palmistry:["기운","럭키"],footreading:["기운","럭키"],
    mole:["부적","기운"],eye_mole:["부적","기운"],
    baby_gwansang:["천기주얼리","탄생","집안"],baby_face:["탄생","주얼리"],
    doljabi_sim:["탄생","주얼리"],
  };
  const keywords=keywordMap[svcId]||[];
  if(keywords.length===0)return goods.filter(g=>g.rec).slice(0,5);
  const matched=goods.filter(g=>{
    const cat=(g.cat||"").toLowerCase();
    const tags=(g.tags||[]).join(" ").toLowerCase();
    return keywords.some(k=>cat.includes(k.toLowerCase())||tags.includes(k.toLowerCase()));
  });
  // 매칭 없으면 추천(rec) 플래그가 있는 상품
  if(matched.length===0)return goods.filter(g=>g.rec).slice(0,5);
  return matched.slice(0,5);
}
function GoodsRecSection({svcId, ctx={}, cart, setCart, onGoShop, title, sub}){
  const[visibleGoods,setVisibleGoods]=useState<any[]|null>(null);
  useEffect(()=>{fetchLiveVisibleGoods().then(setVisibleGoods);},[]);
  function addCart(item:any){
    setCart((prev:any)=>{
      const ex=prev.find((c:any)=>c.id===item.id);
      return ex?prev.map((c:any)=>c.id===item.id?{...c,qty:c.qty+1}:c):[...prev,{...item,qty:1}];
    });
  }
  // 로딩 중 — 깜빡임 방지를 위해 아무것도 표시 안 함
  if(visibleGoods===null)return null;
  const recs=filterLiveGoodsForSvc(svcId,ctx,visibleGoods);
  // 공개 굿즈 자체가 0개이거나 이 서비스에 맞는 게 없으면 "준비중" 배너
  if(recs.length===0){
    return(
      <div style={{background:"linear-gradient(135deg,rgba(212,175,55,0.08),rgba(155,143,212,0.06))",border:"1px solid rgba(212,175,55,0.25)",borderRadius:14,padding:"14px 16px",marginBottom:14,textAlign:"center"}}>
        <div style={{fontSize:13,fontWeight:800,color:"var(--gold)",marginBottom:4}}>🛠️ 개운 굿즈 준비중</div>
        <div style={{fontSize:11,color:"var(--mist)",lineHeight:1.6}}>천기 오리지널 굿즈를 열심히 만들고 있어요.<br/>오픈 알림을 받고 싶으면 <strong style={{color:"var(--gold)"}}>카톡 채널</strong>을 추가해주세요 💛</div>
      </div>
    );
  }
  return(
    <div className="goods-rec">
      <div className="goods-rec-header">
        <span className="goods-rec-title">🛍️ {title||"맞춤 굿즈 추천"}</span>
        <span className="goods-rec-see-all" onClick={onGoShop}>전체 보기 →</span>
      </div>
      <div className="goods-rec-sub">{sub||"이 결과에 어울리는 기운 강화 아이템"}</div>
      <div className="goods-rec-scroll">
        {recs.map((g:any)=>(
          <div key={g.id} className="goods-mini-card">
            <div className="goods-mini-img" style={{background:g.color||"var(--ink3)"}}>{g.icon}</div>
            <div className="goods-mini-info">
              <div className="goods-mini-name">{g.name}</div>
              <div className="goods-mini-price">{(g.price||0).toLocaleString()}원</div>
            </div>
            <button className="goods-mini-add" onClick={()=>addCart(g)}>+ 담기</button>
          </div>
        ))}
      </div>
    </div>
  );
}

function PayDonePopup({svc, ctx={}, cart, setCart, onClose, onGoShop}){
  return(
    <div className="pay-done-ov">
      <div className="pay-done-md">
        <div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={onClose} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
        {/* v652: 테스트 모드 시뮬레이션 명시 — 실제 PortOne 연동 시 원복 */}
        <div className="pdc-icon">🧪</div>
        <div className="pdc-title">테스트 모드 — 결제 시뮬레이션</div>
        <div className="pdc-sub">
          실제 결제는 진행되지 않았어요.<br/>
          {svc.name} 결과를 확인해보세요!
        </div>
        <button className="btn btn-p" onClick={onClose} style={{marginTop:16}}>결과 보기 →</button>
      </div>
    </div>
  );
}

