// 텍스트에서 사주 용어 첫 등장에 풀이 자동 추가 (이미 풀이가 있으면 스킵)
function _enrichSajuText(text:string):string{
  if(!text||typeof text!=="string")return text;
  let out=text;
  const seen=new Set<string>();
  // 길이가 긴 용어부터 매칭 (정관격이 정관보다 먼저)
  const keys=Object.keys(_SAJU_GLOSS).sort((a,b)=>b.length-a.length);
  for(const k of keys){
    if(seen.has(k))continue;
    // 이미 괄호로 풀이된 경우(예: "정관격(...)" 또는 "정관격 — ...") 스킵
    const idx=out.indexOf(k);
    if(idx<0)continue;
    const after=out.slice(idx+k.length,idx+k.length+3);
    if(after.startsWith("(")||after.startsWith("(")||after.startsWith(" —")||after.startsWith("(")||after.match(/^\s*\([^)]/))continue;
    // 첫 등장만 풀이 추가
    out=out.slice(0,idx)+_SAJU_GLOSS[k]+out.slice(idx+k.length);
    seen.add(k);
  }
  return out;
}

// 한국어 조사 자동 처리 (받침에 따라 은/는, 을/를, 이/가)
function _josa(name:string,type:"은는"|"을를"|"이가"="은는"):string{
  if(!name)return type==="은는"?"는":type==="을를"?"를":"가";
  const lc=name.charCodeAt(name.length-1);
  if(lc<0xAC00||lc>0xD7A3){const m={은는:"는",을를:"를",이가:"가"};return m[type];}
  const jong=(lc-0xAC00)%28;
  if(type==="은는")return jong?"은":"는";
  if(type==="을를")return jong?"을":"를";
  return jong?"이":"가";
}

