// v330: 정밀 매칭 — 사용자 사주(생년·일간오행) + 성별 fit score 기반 상위 N명
function _pickCelebs(pool:string[]|undefined, opts:{birth?:string,gender?:"M"|"F",ilOh?:string,n?:number}={}){
  if(!pool||pool.length===0)return [] as string[];
  const{birth,gender,ilOh,n=10}=opts;
  const now=new Date().getFullYear();
  const userYear=birth&&/^\d{4}/.test(birth)?parseInt(birth.slice(0,4)):now-30;
  const seedKey=birth?birth.replace(/[^0-9]/g,""):"";
  const seed=seedKey?parseInt(seedKey)%10000:Math.floor(Math.random()*10000);
  const _ohOf=(m:_CelebMeta|undefined):string|undefined=>{
    if(!m)return undefined;
    if(m.oh)return m.oh;
    if(!m.b)return undefined;
    if(m.b in _OH_CACHE)return _OH_CACHE[m.b];
    try{const sp=_sajuPillars(m.b,"");_OH_CACHE[m.b]=sp?.ilOh;}catch{_OH_CACHE[m.b]=undefined;}
    return _OH_CACHE[m.b];
  };
  const scored=pool.map((name,i)=>{
    const m=_CELEB_META[name];
    let score=0;
    if(m){
      const cOh=_ohOf(m);
      if(ilOh&&cOh&&cOh===ilOh)score+=30;
      if(gender&&m.g&&m.g===gender)score+=10;
      if(m.y){
        const diff=Math.abs((now-m.y)-(now-userYear));
        if(diff<=10)score+=20;
        else if(diff<=20)score+=12;
        else if(diff<=30)score+=6;
      }
    }
    // 시드 기반 노이즈 (다양성 — 같은 사용자도 매번 살짝 다른 순위)
    score+=((seed+i*17)%18);
    return{name,score,m};
  });
  scored.sort((a,b)=>b.score-a.score);
  return scored.slice(0,n).map(x=>x.name);
}
