  const _SKIP_INPUT_TO_HANJA=["namereading"];
  const _initStep=preloadResult?"result":(svc._forceIntro?"info":(needPerson?"info":isLoggedIn||svc.free?(_SKIP_INPUT_TO_HANJA.includes(svc.id)&&selectedPerson?"hanjapick":_SKIP_INPUT_TO_PREQS.includes(svc.id)&&selectedPerson?"preqs":"input"):"auth"));
  const[step,setStep]=useState(_initStep);
  // celeb_compat 등: 모달 인스턴스 유지된 채로 selectedPerson 들어오면 즉시 다음 step으로 (paint 전 — intro 깜빡임 제거)
  useLayoutEffect(()=>{
    if(!selectedPerson)return;
    if(step!=="info")return;
    if(_SKIP_INPUT_TO_PREQS.includes(svc.id)){setStep("preqs");return;}
    if(_SKIP_INPUT_TO_HANJA.includes(svc.id)){setStep("hanjapick");return;}
    if(isLoggedIn||svc.free){setStep("input");}
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[selectedPerson?.name,selectedPerson?.birth]);
  const[loading,setLoading]=useState(false);
  const[showHandFootCollection,setShowHandFootCollection]=useState(false);
  const[celebTab,setCelebTab]=useState(0); // v355: 궁합 연예인 5명 탭 인덱스
  const sp=selectedPerson||{};
  const spBirth=sp.birth?sp.birth.split("-"):[];
  const spTime=sp.time&&sp.time!=="모름"?sp.time.split(":"):[];
  // 0-padded 값(예: "08") → 옵션 값("8")과 매칭되도록 정수 변환
  const stripZero=(v:string)=>v?String(parseInt(v,10)):"";
  const[form,setForm]=useState({name:sp.name||preloadResult?._name||"",year:stripZero(spBirth[0]||""),month:stripZero(spBirth[1]||""),day:stripZero(spBirth[2]||""),hour:stripZero(spTime[0]||""),minute:stripZero(spTime[1]||""),calendar:sp.calendar||"양력",gender:sp.gender||""});
  const[ctx,setCtx]=useState(preloadResult?._ctx||{ohaeng:"화", number:7}); // 분석 결과 컨텍스트 (preload 우선)
  const[showPayDone,setShowPayDone]=useState(false);
  const fileRef=useRef<any>(null);const[imgSrc,setImgSrc]=useState<any>(preloadResult?._imgSrc||null);
  const fileRef2=useRef<any>(null);const[imgSrc2,setImgSrc2]=useState<any>(preloadResult?._imgSrc2||null);
  const fileRef3=useRef<any>(null);const[imgSrc3,setImgSrc3]=useState<any>(preloadResult?._imgSrc3||null);
  const[realAnalysis,setRealAnalysis]=useState<any>(preloadResult||null);
  const[validating,setValidating]=useState(false);
  // 📝 이름 풀이 전용: 사주에 맞는 한자 picker (성+이름 2자 = 총 3자 한자 선택)
  // v665: 기록소 재진입 시 한자 picker 선택 복원 (#17 한자 picker 선택 state 풀림 fix)
  const[nrHanjaSurname,setNrHanjaSurname]=useState<any>(preloadResult?.nrHanjaSurname||null); // 성(姓) 한자 — slot 0
  const[nrHanja1,setNrHanja1]=useState<any>(preloadResult?.nrHanja1||null); // 이름 첫 자 — slot 1
  const[nrHanja2,setNrHanja2]=useState<any>(preloadResult?.nrHanja2||null); // 이름 둘째 자 — slot 2 (3글자 이름일 때)
  const[nrRecStrokes,setNrRecStrokes]=useState<{first:number[],second:number[]}|null>(null);
  const[nrSajuMeta,setNrSajuMeta]=useState<{ilOh:string,lackOh:string}>(preloadResult?.nrSajuMeta||{ilOh:"토",lackOh:"금"});
  // 🍼 아기 이름 짓기 전용 — 성씨 + 돌림자 2자리 한자 picker
  const[babySurnameHanja,setBabySurnameHanja]=useState<any>(preloadResult?.babySurnameHanja||null);  // 성(姓) 한자 — 필수
  const[babyDolrim2,setBabyDolrim2]=useState<any>(preloadResult?.babyDolrim2||null);             // 두 번째 자리 돌림자 (null|"없음"|{c,y,m,s})
  const[babyDolrim2None,setBabyDolrim2None]=useState(!!preloadResult?.babyDolrim2None);         // "없음" 명시 토글
