  const curPreQs=SVC_PRE_QS[svc.id]||[];
  const hasPreQs=hasV3Preqs||curPreQs.length>0;

  // 이름 풀이 — 사주 분석 후 추천 한자 획수 세팅 (한자 picker 진입 직전)
  // v273: namereading은 마운트 시 hanjapick으로 바로 진입하므로 prepareNamereadingHanja 자동 호출
  useEffect(()=>{
    if(svc.id==="namereading"&&selectedPerson&&!nrRecStrokes&&_initStep==="hanjapick"){
      prepareNamereadingHanja();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  },[svc.id,selectedPerson]);

  function prepareNamereadingHanja(){
    try{
      // 🍼 baby_naming은 아기(selectedPerson2) 사주 기반, 그 외(이름풀이)는 사용자 본인(form)
      let birth="", time="";
      if(svc.id==="baby_naming"){
        birth=selectedPerson2?.birth||"";
        time=selectedPerson2?.time&&selectedPerson2.time!=="모름"?selectedPerson2.time:"";
      } else {
        birth=`${form.year}-${String(form.month).padStart(2,"0")}-${String(form.day).padStart(2,"0")}`;
        time=form.hour?`${String(form.hour).padStart(2,"0")}:${String(form.minute||"0").padStart(2,"0")}`:"";
      }
      // 생년월일 모름 → 사주 분석 불가, 추천 길수 비활성 (전체 획수 모드)
      if(!birth||!/^\d{4}-\d{1,2}-\d{1,2}$/.test(birth)){
        setNrSajuMeta({ilOh:"-",lackOh:"-"});
        setNrRecStrokes({first:[],second:[]});
        return;
      }
      const sp=_sajuPillars(birth,time);
      const _il=sp?.ilOh||"토";
      const ohE:any[]=sp?.ohang?Object.entries(sp.ohang):[];
      const _lack=ohE.length?ohE.reduce((a,b)=>b[1]<a[1]?b:a)[0]:"금";
      setNrSajuMeta({ilOh:_il,lackOh:_lack});
      setNrRecStrokes(pawdongRecommendStrokes(_il,_lack));
    }catch{setNrRecStrokes({first:[8,11,13,15,16],second:[8,11,13,15,16]});}
  }
  function doAnalyze(){
    if(svc.id==="celeb_compat"){
      const ck=`chungi_daily_celeb_${new Date().toISOString().slice(0,10)}_count`;
      const cnt=parseInt(localStorage.getItem(ck)||"0");
      // v293: 1일 1회 초과 시 alert 대신 결과창 자동 진입 (오늘 본 결과 다시 보여주기)
      if(cnt>=1){setStep("result");return;}
      // v300: 카운트 증가는 onLoadingDone에서 (history 저장 시점과 동기화 — 중도 취소 시 카운트만 닳는 버그 방지)
    }
    // v259: 택일 무료(좋은 날 확인하기) — 1일 3회 무료 (다회 사용이라 alert 유지)
    if(svc.id==="taegil_free"){
      const ck=`chungi_daily_taegil_${new Date().toISOString().slice(0,10)}_count`;
      const cnt=parseInt(localStorage.getItem(ck)||"0");
      if(cnt>=3){alert("오늘 좋은 날 확인하기는 3회까지 무료예요!\n내일 다시 이용해주세요.\n\n📋 오늘 본 결과는 기록소에서 다시 확인할 수 있어요.");return;}
      try{localStorage.setItem(ck,String(cnt+1));}catch{}
    }
    // v640: 사전질문 있는 콘텐츠는 무조건 사전질문 거치게 (preQ 채워져 있어도 첫 페이지부터 다시)
    // → input→preqs→input 이전 케이스, "다른쪽 보기" 케이스 모두 사전질문 재확인 강제
    // → 사전질문 답이 결과·결제 가치에 영향을 주므로 스킵 자체가 잘못 (v638 _PAY_REQUIRED_LIST 안전망보다 근본 대응)
    if(hasPreQs){setPreQStep(0);setStep("preqs");return;}
    // 이름풀이 — 사주 기반 한자 추천 → 한자 picker
    if((svc.id==="namereading"||svc.id==="name_reading")&&!nrHanja1){prepareNamereadingHanja();setStep("hanjapick");return;}
    // 🍼 아기 이름 짓기 — 성씨·돌림자 한자 picker
    if(svc.id==="baby_naming"&&!babySurnameHanja){prepareNamereadingHanja();setStep("babyhanja");return;}
    // 감성질문 필요하면 감성질문 먼저
    if(!skipEmotion&&!emotionAnswers.mood){setStep("emotion");return;}
    // 로딩 화면으로
    setStep("loading");
  }
  function onPreQsDone(){
    // v265: celeb_compat은 input step skip하므로 doAnalyze 카운트 체크가 안 거침 → 여기서 처리
    if(svc.id==="celeb_compat"){
      const ck=`chungi_daily_celeb_${new Date().toISOString().slice(0,10)}_count`;
      const cnt=parseInt(localStorage.getItem(ck)||"0");
      // v293: 1일 1회 초과 시 alert 대신 결과창 자동 진입
      if(cnt>=1){setStep("result");return;}
      // v300: 카운트 증가는 onLoadingDone에서 (history 저장 시점과 동기화)
    }
    // v273: 이름풀이는 한자 picker 후 preqs로 진입 → preqs 끝나면 결제로
    if((svc.id==="namereading"||svc.id==="name_reading")&&nrHanja1){setStep("pay");return;}
    // 이름풀이 — 한자 picker 아직이면 (보강용 폴백)
    if((svc.id==="namereading"||svc.id==="name_reading")&&!nrHanja1){prepareNamereadingHanja();setStep("hanjapick");return;}
    // 🍼 아기 이름 짓기 — preqs(정보) 이후 한자 picker
    if(svc.id==="baby_naming"&&!babySurnameHanja){prepareNamereadingHanja();setStep("babyhanja");return;}
    // 🍼 아기 이름 짓기 — 한자 picker 후 preqs2(focus) 이미 답함 → 결제
    if(svc.id==="baby_naming"&&babySurnameHanja){setStep("pay");return;}
    if(!skipEmotion&&!emotionAnswers.mood){setStep("emotion");return;}
    // v268: 유료 콘텐츠는 사전질문 후 결제로 (매몰비용 극대화)
    // v324: 관상궁합 7종 추가 (input → 사전질문 → 결제 → 결과)
    const _PAY_AFTER_PREQ=["palmistry","footreading","mole","eye_mole","lucky_number","lucky_wallpaper","gwansang_compat","parent_child_compat","bff_compat","fan_compat","biz_gwansang","enemy_compat","pet_owner_compat"];
    if(_PAY_AFTER_PREQ.includes(svc.id)){setStep("pay");return;}
    setStep("loading");
  }
  function onEmotionDone(answers:any){setEmotionAnswers(answers);setStep("loading");}
  // 손금/발금/얼굴점/눈점 — 사진 진입 시 API 분석 백그라운드 호출
  useEffect(()=>{
    if(step!=="loading"||!imgSrc)return;
    const PALM_LIKE=["palmistry","footreading"];
    const MOLE_LIKE=["mole","eye_mole"];
    if(PALM_LIKE.includes(svc.id)){
      const t=svc.id==="footreading"
        ?((preQ.foot||"").includes("오른발")?"foot_right":"foot_left")
        :((preQ.hand||"").includes("오른손")?"palm_right":"palm_left");
      fetch("/api/palm-reading",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({imageData:imgSrc,type:t,mediaType:"image/jpeg"})})
        .then(r=>r.json()).then(j=>{if(j.result)setRealAnalysis(j.result);}).catch(()=>{});
    }else if(MOLE_LIKE.includes(svc.id)){
      const t=svc.id==="eye_mole"?"eye":"face";
      fetch("/api/mole-reading",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({imageData:imgSrc,type:t,mediaType:"image/jpeg"})})
        .then(r=>r.json()).then(j=>{if(j.result)setRealAnalysis(j.result);}).catch(()=>{});
    }
  },[step,svc.id,imgSrc]);
  function onLoadingDone(){
    setStep("result");
    // v300: celeb_compat 카운트 증가 (실제 완료 시점에 — history 저장과 동기화)
    if(svc.id==="celeb_compat"){
      try{
        const ck=`chungi_daily_celeb_${new Date().toISOString().slice(0,10)}_count`;
        const cnt=parseInt(localStorage.getItem(ck)||"0");
        localStorage.setItem(ck,String(cnt+1));
      }catch{}
    }
    // 관상궁합 7종은 resultType에 점수 데이터 저장 (인증서 컬렉션 카운팅용)
    const COMPAT_7=["gwansang_compat","parent_child_compat","bff_compat","fan_compat","biz_gwansang","enemy_compat","pet_owner_compat"];
    const isCompat=COMPAT_7.includes(svc.id);
    let rt:any=undefined;
    if(isCompat){
      const seed=(form.name||selectedPerson?.name||"x").charCodeAt(0)+(selectedPerson2?.name||"y").charCodeAt(0);
      const total=60+(seed*7)%40;
      const grade=total>=85?"S":total>=75?"A":total>=65?"B":"C";
      rt={total,grade,p1:form.name||selectedPerson?.name||"나",p2:selectedPerson2?.name||"상대",svcId:svc.id,_birth:selectedPerson?.birth,_imgSrc:imgSrc||null,_imgSrc2:imgSrc2||null,_preQ:preQ,_testDate:new Date().toLocaleString("ko-KR",{year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"})};
    }
    // v316: celeb_compat도 resultType 저장 (기록소에서 결과창과 동일하게 보이도록)
    if(svc.id==="celeb_compat"){
      rt={svcId:"celeb_compat",_birth:selectedPerson?.birth,_imgSrc:imgSrc||null,_testDate:new Date().toLocaleString("ko-KR",{year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"})};
    }
    // v665: 결과↔기록소 동기화 — 사진 분석/이름풀이/행운번호·배경화면도 resultType 저장
    const _td=new Date().toLocaleString("ko-KR",{year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"});
    if(["palmistry","footreading","mole","eye_mole"].includes(svc.id)){
      rt={svcId:svc.id,...(realAnalysis||{}),_imgSrc:imgSrc||null,_preQ:preQ,_birth:selectedPerson?.birth,_testDate:_td};
    }
    if(svc.id==="namereading"||svc.id==="name_reading"){
      rt={svcId:svc.id,nrHanjaSurname,nrHanja1,nrHanja2,nrSajuMeta,_birth:selectedPerson?.birth,_preQ:preQ,_testDate:_td};
    }
    if(svc.id==="baby_naming"){
      rt={svcId:svc.id,babySurnameHanja,babyDolrim2,babyDolrim2None,babyDolrim3,babyDolrim3None,_birth:selectedPerson2?.birth,_preQ:preQ,_testDate:_td};
    }
    if(svc.id==="lucky_number"||svc.id==="lucky_wallpaper"){
      rt={svcId:svc.id,_birth:selectedPerson?.birth,_preQ:preQ,_testDate:_td};
    }
    addHistory({icon:svc.icon,name:svc.name,svcId:svc.id,person:form.name||selectedPerson?.name||"나",person2:selectedPerson2?.name||"",person3:selectedPerson3?.name||"",date:new Date().toLocaleDateString("ko-KR"),ctx,emotion:emotionAnswers,preQuestions:preQ,...(rt?{resultType:rt}:{})});
  }
