                        {Array.isArray(realAnalysis.overall.turning_points)&&realAnalysis.overall.turning_points.length>0&&<div style={{fontSize:11,color:"#444",lineHeight:1.75}}>🔄 <strong style={{color:"#7A5C00"}}>인생 전환점</strong> — {realAnalysis.overall.turning_points.join(" · ")}</div>}
