                        {realAnalysis.overall.warning_mole&&<div style={{padding:"9px 11px",background:"rgba(239,68,68,0.06)",borderRadius:8,borderLeft:"3px solid #ef4444",fontSize:11,color:"#b91c1c",lineHeight:1.7}}>⚠️ <strong>주의</strong> — {realAnalysis.overall.warning_mole}</div>}
