  "쥐":{keywords:["💡 영민함","💰 재물 감각","⚡ 빠른 판단"],strength:"기회를 놓치지 않는 직감과 정보력. 작은 신호도 놓치지 않는 눈썰미",weakness:"너무 많은 가능성을 보다가 결정을 미루는 경향. 신중함이 우유부단으로 변할 수 있음",weekly:["월:기획","화:정보수집","수:실행","목:점검","금:네트워킹","토:충전","일:정리"],compatible:["용","원숭이","소"],incompatible:["말","양"],career:"기획·금융·IT·기자·연구",season:"겨울 (12~1월)",time:"23~01시 (자시)",flower:"매화",food:"견과류·곡물"},
