  "범":{keywords:["🔥 카리스마","⚔️ 도전 정신","👑 리더십"],strength:"위기 앞에서 더 강해지는 담력. 따르는 사람들이 자연스레 모임",weakness:"성급함과 조급함. 디테일보다 큰 그림에 치우치기 쉬움",weekly:["월:선언","화:돌파","수:추진","목:협상","금:확장","토:사교","일:재충전"],compatible:["말","개","돼지"],incompatible:["원숭이","뱀"],career:"경영·마케팅·스포츠·연예·군경",season:"봄 (2~3월)",time:"03~05시 (인시)",flower:"동백",food:"육류·매운맛"},
