  "말":{keywords:["🐎 자유로움","🚀 활동력","💫 매력"],strength:"어디든 적응하는 유연성. 사람을 끄는 매력으로 인맥이 넓음",weakness:"한곳에 오래 머물기 어려움. 마무리가 약할 수 있음",weekly:["월:출발","화:이동","수:만남","목:확장","금:경험","토:여행","일:정리"],compatible:["범","개","양"],incompatible:["쥐","소"],career:"여행·운수·영업·스포츠·외교",season:"여름 (6~7월)",time:"11~13시 (오시)",flower:"해바라기",food:"단백질"},
  "양":{keywords:["☁️ 온화함","🎭 예술성","💞 헌신"],strength:"공감 능력 최고. 평화를 만드는 조정자 역할",weakness:"우유부단함과 의존성. 자기 의견 내세우기 어려움",weekly:["월:평온","화:봉사","수:창작","목:협력","금:치유","토:가족","일:기도"],compatible:["토끼","돼지","말"],incompatible:["소","개"],career:"복지·예술·교육·종교·디자인",season:"여름 (7~8월)",time:"13~15시 (미시)",flower:"카네이션",food:"채소·약선"},
