  "닭":{keywords:["🌟 디테일","🎯 정확성","✨ 자존감"],strength:"꼼꼼한 완벽주의. 아름다움에 대한 안목과 자기 관리",weakness:"비판적인 태도. 자기 기준이 높아 타인도 힘들게 함",weekly:["월:정리","화:체크","수:실행","목:점검","금:완벽","토:꾸미기","일:관리"],compatible:["소","뱀","용"],incompatible:["토끼","개"],career:"회계·뷰티·요리·디자인·언론",season:"가을 (9~10월)",time:"17~19시 (유시)",flower:"국화",food:"정갈한 한식"},
