                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {[{l:"초년 (20대)",v:s.y,c:"#22c55e"},{l:"중년 (30~50대)",v:s.m,c:"#a855f7"},{l:"말년 (60대~)",v:s.o,c:"#6b21a8"}].map(st=>(
                    <div key={st.l} style={{background:"#f8f9fa",borderRadius:8,padding:"8px 11px",borderLeft:`3px solid ${st.c}`}}>
                      <div style={{fontSize:9,color:st.c,fontWeight:800,marginBottom:2}}>{st.l}</div>
                      <div style={{fontSize:11,color:"#555",lineHeight:1.6}}>{st.v}</div>
                    </div>
                  ))}
                </div>
