        const hashFootNum=<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:14,paddingTop:10,paddingBottom:10,marginLeft:-20,marginRight:-20,paddingLeft:20,paddingRight:20,borderTop:`1px solid ${theme.soft}`,flexWrap:"wrap",gap:4,fontSize:9,color:"#aaa",fontWeight:600,letterSpacing:0.3}}><span>#천기수비학 #소울넘버{r.soul_number} #{(r.soul_name||"").replace(/\s/g,"")} #{(personName||"").replace(/\s/g,"")}</span><span style={{fontWeight:600}}>🌐 천기.kr</span></div>;
