              <div style={{position:"absolute",left:"50%",top:"50%",transform:"translate(-50%,-50%) scale(0)",opacity:0,width:110,height:110,borderRadius:"50%",overflow:"hidden",border:"4px solid var(--gold)",boxShadow:"0 0 30px rgba(212,175,55,0.6)",animation:"babyAppear 4.5s infinite ease-in-out"}}>
                <img src="/img/gemini (21).png" alt="2세 예측" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
              </div>
              {/* 스캔 라인 */}
              <div style={{position:"absolute",width:"100%",height:2,background:"linear-gradient(90deg,transparent,var(--gold),transparent)",boxShadow:"0 0 10px var(--gold)",animation:"laserScan 3s infinite ease-in-out",pointerEvents:"none"}}/>
