                        <div style={{width:`${dadPct}%`,background:"linear-gradient(90deg,#74b9ff,#1a73e8)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:800,color:"#fff"}}>{dadPct>=20?`${dadPct}% 👨`:""}</div>
