function _getDominantOhang(birth?:string){
  if(!birth)return"토";
  const parts=birth.replace(/[^0-9]/g,"-").split("-").filter(Boolean);
  if(parts.length<3)return"토";
  const y=+parts[0]||1990,m=+parts[1]||1,day=+parts[2]||1;
  const a=Math.floor((14-m)/12),y2=y-a,m2=m+12*a-2;
  const jd=day+Math.floor((153*m2+2)/5)+365*y2+Math.floor(y2/4)-Math.floor(y2/100)+Math.floor(y2/400)-32045;
  const ilgan=(jd+4)%10;
  return["목","목","화","화","토","토","금","금","수","수"][ilgan];
}
function _seededRng(seed:number){let s=(seed>>>0)||1;return()=>{s=(s*1664525+1013904223)>>>0;return s/0x100000000;};}
function _pick(arr:any[],rng:any){return arr[Math.floor(rng()*arr.length)];}
function _calcUnse(loggedIn:boolean,personBirth?:string){
  const d=new Date(),seed=d.getFullYear()*10000+(d.getMonth()+1)*100+d.getDate()+(loggedIn?7777:0);
  const rng=_seededRng(seed);
  const headline=_pick(_UNSE_HEADLINES,rng);
  const dominant=loggedIn?_getDominantOhang(personBirth):"토";
  const areas=_UNSE_AREAS.map(({id,area,emoji,color,sub})=>{
    const opts=_UNSE_MSGS[id];
    const bucket=opts[Math.min(opts.length-1,Math.floor(rng()*opts.length))];
    const base=bucket[0] as number;
    const score=Math.min(99,Math.max(15,base+Math.floor(rng()*10)-4));
    return{id,area,emoji,color,sub,score,text:bucket[1] as string,detail:bucket[2] as string};
  });
  const totalScore=Math.round(areas.reduce((s,a)=>s+a.score,0)/areas.length);
  const star=Math.min(5,Math.max(1,Math.round(totalScore/20)));
  return{headline,areas,star,totalScore,
    spoiler:_pick(_UNSE_SPOILERS,rng),
    spot:_pick(_UNSE_SPOTS,rng),
    guiin:_pick(_UNSE_GUIIN,rng),
    lastWord:_pick(_UNSE_LASTWORDS,rng),
    solution:_pick(_UNSE_SOLUTIONS,rng),
    luckyColor:_pick(_LUCKY_POOL.color,rng),luckyNum:_pick(_LUCKY_POOL.num,rng),luckyDir:_pick(_LUCKY_POOL.dir,rng),luckyFood:_pick(_LUCKY_POOL.food,rng),luckyTime:_pick(_LUCKY_POOL.time,rng),
    luckyAnimal:_pick(_LUCKY_POOL.animal,rng),
    ohang:dominant,ohangColor:_OHANG_COLORS[dominant]};
}

