// v527: 부분매칭 버그 fix — "건물"의 "물"이 "물 꿈"에 매칭되던 문제.
// 어절 단위 split + 한국어 조사 제거하여 정확한 단어 일치만 매칭.
function _stripJosa(t:string){return t.replace(/(이라고|이라는|이라|라고|라는|에서|에게|한테|로서|부터|까지|보다|이|가|을|를|에|의|와|과|도|만|는|은|로)$/,"");}
function _tokenize(text:string){return text.toLowerCase().split(/[\s.,!?;:'"`()[\]{}<>·\-—~]+/).filter(Boolean).map(_stripJosa);}
function _matchDream(text:string){const tokens=_tokenize(text);return _DREAM_DB.find(d=>d.keywords.some(k=>tokens.includes(k)))||_DREAM_UNKNOWN;}
function _matchTaemong(text:string){const tokens=_tokenize(text);return _TAEMONG_DB.find(d=>d.keywords.some(k=>tokens.includes(k)))||_TAEMONG_UNKNOWN;}

