  const[savedResult]=useState(()=>preloadResult||null);
  // selectedPerson 있으면 questions, 없으면 info — 인트로에서 인물 선택 후 자동 진행
  // 닫기 시 selectedPerson 리셋은 부모에서 처리 (Task #11 일괄 작업)
  const[step,setStep]=useState<"info"|"questions"|"pay"|"loading"|"result">(preloadResult?"result":(_spHasBirth?"questions":"info"));
  const[preQ,setPreQ]=useState<any>(preloadResult?.preQ||{});
