function ComingModal({svc,onClose,userData,isLoggedIn}){
  const [agreed, setAgreed] = useState(false);
  const [done, setDone] = useState(false);
  const [loading, setLoading] = useState(false);

  const notifyMethod = userData?.email?.includes("kakao") ? "카카오톡" : "이메일";
  const contactInfo = userData?.email || "게스트";

  async function signup() {
    setLoading(true);
    try {
      await fetch("/api/notification-signups", {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({
          service_id: svc.id,
          service_name: svc.name,
          user_email: userData?.email || "",
          user_name: userData?.name || "게스트",
          notify_method: notifyMethod === "카카오톡" ? "kakao" : "email",
        })
      });
      setDone(true);
    } catch {} finally { setLoading(false); }
  }

  return (
    <div className="ov">
      <div className="md"><div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={onClose} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
        <div style={{textAlign:"center",fontSize:52,marginBottom:12}}>{svc.icon}</div>
        <div className="mt" style={{textAlign:"center"}}>{svc.name}</div>
        <div className="ms" style={{textAlign:"center"}}>준비 중이에요! 곧 만나실 수 있어요 🙌</div>

        {!done ? <>
          {isLoggedIn && userData ? (
            <>
              <div style={{background:"var(--ink3)",borderRadius:14,padding:"14px",marginBottom:12,border:"1px solid rgba(255,255,255,0.06)"}}>
                <div style={{fontSize:12,color:"var(--mist)",marginBottom:6}}>오픈 시 알림을 받으시겠어요?</div>
                <div style={{fontSize:13,fontWeight:700,color:"var(--gold)"}}>카톡이나 이메일로 안내해드려요</div>
              </div>

              <div style={{display:"flex",alignItems:"center",gap:9,marginBottom:14,cursor:"pointer"}} onClick={()=>setAgreed(v=>!v)}>
                <div style={{width:18,height:18,borderRadius:5,border:`2px solid ${agreed?"var(--jade)":"rgba(255,255,255,0.15)"}`,background:agreed?"var(--jade)":"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                  {agreed&&<span style={{fontSize:11,color:"var(--ink)",fontWeight:900}}>✓</span>}
                </div>
                <div style={{fontSize:11,color:"var(--mist)"}}>오픈 알림 수신에 동의합니다</div>
              </div>

              {loading ? <Dots/> : <button className="btn btn-p" disabled={!agreed} onClick={signup}>출시 알림 신청</button>}
            </>
          ) : (
            <div style={{background:"var(--ink3)",borderRadius:14,padding:"14px",marginBottom:12,border:"1px solid rgba(255,255,255,0.06)",textAlign:"center"}}>
              <div style={{fontSize:12,color:"var(--mist)"}}>로그인하면 오픈 알림을 받을 수 있어요!</div>
            </div>
          )}
        </> : (
          <div style={{background:"rgba(95,196,158,0.1)",border:"1px solid rgba(95,196,158,0.2)",borderRadius:13,padding:"14px",textAlign:"center"}}>
            <div style={{fontSize:24,marginBottom:6}}>✅</div>
            <div style={{fontSize:13,fontWeight:700,color:"var(--jade)"}}>알림 신청 완료!</div>
            <div style={{fontSize:11,color:"var(--mist)",marginTop:4}}>오픈되면 카톡이나 이메일로 알려드릴게요</div>
          </div>
        )}

        <button className="btn btn-g" onClick={onClose}>닫기</button>
      </div>
    </div>
  );
}

