                <img src={t.card} alt={t.id} style={{width:62,height:62,objectFit:"contain",margin:"0 auto 4px",display:"block",filter:`drop-shadow(0 2px 6px ${t.color}66)`}} onError={(e:any)=>{e.currentTarget.style.display="none";}}/>
