                <span style={{fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:20,background:"rgba(5,77,149,0.14)",color:"#054D95",border:"1px solid rgba(5,77,149,0.35)"}}>🌻 대지 ESFJ</span>
