          {shareCount>0?(
            <span onClick={()=>setActiveModal("badge_share")} className="tag" style={{background:"rgba(95,196,158,0.12)",color:"#5fc49e",border:"1px solid rgba(95,196,158,0.3)",cursor:"pointer"}}>🔗 공유 {shareCount}회</span>
          ):(
            <span onClick={()=>setActiveModal("badge_share")} className="tag" style={{background:"rgba(168,196,184,0.08)",color:"rgba(168,196,184,0.5)",border:"1px solid rgba(168,196,184,0.15)",cursor:"pointer"}}>🔗 공유 없음</span>
          )}
