// 대나무숲 가로 레터박스 이미지 (상세 보기 전용)
function BambooLandscapeImage({thumb}:{thumb:string}){
  const[failed,setFailed]=useState(false);
  if(failed)return null;
  return(
    <div style={{width:"100%",aspectRatio:"16/9",borderRadius:12,overflow:"hidden",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.08)",marginBottom:10}}>
      <img src={thumb} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}} onError={()=>setFailed(true)}/>
    </div>
  );
}
// 대나무숲 정사각 우측 썸네일 (피드 카드용 — 글 높이 맞춤)
function BambooSquareThumb({thumb}:{thumb:string}){
  const[failed,setFailed]=useState(false);
  if(failed)return null;
  return(
    <div style={{flexShrink:0,width:96,height:96,borderRadius:10,overflow:"hidden",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.08)",alignSelf:"center"}}>
      <img src={thumb} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}} onError={()=>setFailed(true)}/>
    </div>
  );
}
// 대나무숲 피드카드 우측 썸네일 — 카드 전체 높이에 맞춰 세로 늘어남 (정사각 → 세로형)
function BambooStretchThumb({thumb}:{thumb:string}){
  const[failed,setFailed]=useState(false);
  if(failed)return null;
  return(
    <div style={{flexShrink:0,width:112,alignSelf:"stretch",borderRadius:10,overflow:"hidden",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.08)"}}>
      <img src={thumb} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}} onError={()=>setFailed(true)}/>
    </div>
  );
}

// 천기 공식 등급 시스템 — MyPage LEVELS와 동기화 (7단계, 포인트 기준)
// 포인트 = userHistory.length × 100 (사용 1건당 100점)
const _BAMBOO_TIERS=[
  {min:0,    emoji:"🌱", label:"새싹",   desc:"가입한 모든 사람"},
  {min:50,   emoji:"🌙", label:"달",     desc:"유료 콘텐츠 1가지 이용"},
  {min:300,  emoji:"⭐", label:"별",     desc:"유료 콘텐츠 5가지 이용"},
  {min:800,  emoji:"☀️", label:"태양",   desc:"유료 콘텐츠 10가지 이용"},
  {min:1500, emoji:"🌟", label:"샛별",   desc:"총 결제 3만원 이상"},
  {min:3000, emoji:"💫", label:"북극성", desc:"총 결제 5만원 이상"},
  {min:5000, emoji:"🐉", label:"천기인", desc:"전체 콘텐츠 다 이용"},
];
function _bambooTierEmoji(historyCount:number):string{
  const points=historyCount*100;
  for(let i=_BAMBOO_TIERS.length-1;i>=0;i--){
    if(points>=_BAMBOO_TIERS[i].min)return _BAMBOO_TIERS[i].emoji;
  }
  return"🌱";
}
function _bambooTierLabel(historyCount:number):string{
  const points=historyCount*100;
  for(let i=_BAMBOO_TIERS.length-1;i>=0;i--){
    if(points>=_BAMBOO_TIERS[i].min)return _BAMBOO_TIERS[i].label;
  }
  return"새싹";
}

function BambooPage({onGoHome,isLoggedIn,onLogin,userData,userHistory}:any){
  const myTier=_bambooTierEmoji(userHistory?.length||0);
  const[posts,setPosts]=useState<any[]>(()=>{try{const saved=localStorage.getItem("chungi_bamboo_posts");return saved?JSON.parse(saved):BAMBOO_SAMPLE_POSTS;}catch{return BAMBOO_SAMPLE_POSTS;}});
  const[activeCat,setActiveCat]=useState("전체");
  const[writeOpen,setWriteOpen]=useState(false);
  const[viewPost,setViewPost]=useState<any>(null);
  const[comments,setComments]=useState<Record<number,any[]>>(()=>{
    try{
      const saved=localStorage.getItem("chungi_bamboo_comments");
      const parsed=saved?JSON.parse(saved):null;
      // 저장 데이터 없거나 빈 객체면 샘플 댓글 사용 / 있으면 샘플 위에 저장분 병합
      if(!parsed||Object.keys(parsed).length===0)return BAMBOO_SAMPLE_COMMENTS;
      return{...BAMBOO_SAMPLE_COMMENTS,...parsed};
    }catch{return BAMBOO_SAMPLE_COMMENTS;}
  });
  const[myLikes,setMyLikes]=useState<Set<number>>(()=>{try{const saved=localStorage.getItem("chungi_bamboo_likes");return new Set(saved?JSON.parse(saved):[]);}catch{return new Set();}});
  // v712: 다양한 공감 이모지 — 사용자 "좋아요 말고 다양한 공감 이모지들"
  // myReactions[postId] = ['heart','fire',...] — 한 글에 여러 reaction 가능
  const[myReactions,setMyReactions]=useState<Record<number,string[]>>(()=>{try{const s=localStorage.getItem("chungi_bamboo_reactions");return s?JSON.parse(s):{};}catch{return {};}});
  // 닉네임 기억하기 — 저장된 닉네임 있으면 복원
  const[savedNick,setSavedNick]=useState<string>(()=>{try{return localStorage.getItem("chungi_bamboo_nick")||"";}catch{return "";}});
  // v712: 대나무숲 6종 공감 이모지 정의 + helper
  const _BAMBOO_REACTIONS=[
    {k:"heart",   e:"❤️",l:"좋아요",  c:"#ff6b6b"},
    {k:"support", e:"💪",l:"응원해요",c:"#5fc49e"},
    {k:"hug",     e:"🤗",l:"안아줄게",c:"#fbb040"},
    {k:"sad",     e:"😢",l:"슬퍼요",  c:"#74b9ff"},
    {k:"fun",     e:"😂",l:"웃겨요",  c:"#fdcb6e"},
    {k:"fire",    e:"🔥",l:"화이팅",  c:"#e17055"},
  ] as const;
  function getRxCount(p:any,k:string){
    const rx=p?.reactions||{};
    // heart는 옛 likes 호환 — reactions.heart 없으면 p.likes 사용
    if(k==="heart"&&!("heart" in rx))return p?.likes||0;
    return rx[k]||0;
  }
  function getRxTotal(p:any){
    const rx=p?.reactions||{};
    let sum=Object.values(rx).reduce((a:number,b:any)=>a+(Number(b)||0),0);
    if(!("heart" in rx))sum+=(p?.likes||0); // 옛 likes 호환
    return sum;
  }
  function hasMyRx(postId:number,k:string){return (myReactions[postId]||[]).includes(k);}
  function saveMyReactions(next:Record<number,string[]>){setMyReactions(next);try{localStorage.setItem("chungi_bamboo_reactions",JSON.stringify(next));}catch{}}
  function handleReaction(postId:number,k:string){
    const cur=myReactions[postId]||[];
    const has=cur.includes(k);
    const nextMy={...myReactions,[postId]:has?cur.filter(x=>x!==k):[...cur,k]};
    saveMyReactions(nextMy);
    // 게시글 카운트 갱신 — k가 heart고 reactions.heart 없으면 p.likes에서 마이그레이션
    const updated=posts.map((p:any)=>{
      if(p.id!==postId)return p;
      const rx={...(p.reactions||{})};
      if(k==="heart"&&!("heart" in rx))rx.heart=p.likes||0;
      rx[k]=Math.max(0,(rx[k]||0)+(has?-1:1));
      const np={...p,reactions:rx};
      // 호환: heart 토글 시 p.likes 동기화 (리스트뷰에서 ❤ {likes} 사용 중)
      if(k==="heart")np.likes=rx.heart;
      return np;
    });
    saveAndUpdate(updated);
    setViewPost((vp:any)=>vp&&vp.id===postId?updated.find(p=>p.id===postId):vp);
  }
  // "내 글만 보기" 필터
  const[myOnly,setMyOnly]=useState(false);
  // 수정 중인 글 id
  const[editingId,setEditingId]=useState<number|null>(null);
  // 드래그 중인 이미지 인덱스
  const[dragImgIdx,setDragImgIdx]=useState<number|null>(null);
  // 어드민이 관리하는 카테고리/키워드/차단 사용자 (localStorage에서 로드)
  const[adminCats,setAdminCats]=useState<any[]>(()=>{try{const s=localStorage.getItem("chungi_bamboo_categories");return s?JSON.parse(s):null;}catch{return null;}});
  const[blockedWords,setBlockedWords]=useState<string[]>(()=>{try{const s=localStorage.getItem("chungi_bamboo_blocked_words");return s?JSON.parse(s):[];}catch{return[];}});
  const[blockedNicks,setBlockedNicks]=useState<string[]>(()=>{try{const s=localStorage.getItem("chungi_bamboo_blocked_nicks");return s?JSON.parse(s):[];}catch{return[];}});
  // localStorage 실시간 동기화 (어드민에서 변경 반영)
  useEffect(()=>{
    const sync=()=>{
      try{
        const sc=localStorage.getItem("chungi_bamboo_categories");if(sc)setAdminCats(JSON.parse(sc));
        const sw=localStorage.getItem("chungi_bamboo_blocked_words");setBlockedWords(sw?JSON.parse(sw):[]);
        const sn=localStorage.getItem("chungi_bamboo_blocked_nicks");setBlockedNicks(sn?JSON.parse(sn):[]);
      }catch{}
    };
    window.addEventListener("storage",sync);
    window.addEventListener("focus",sync);
    return()=>{window.removeEventListener("storage",sync);window.removeEventListener("focus",sync);};
  },[]);
  const[newPost,setNewPost]=useState<{cat:string,title:string,content:string,image:string|null,images:string[],nick:string,keepNick:boolean}>(()=>{
    let initNick="";let initKeep=false;
    try{const s=localStorage.getItem("chungi_bamboo_nick");if(s){initNick=s;initKeep=true;}}catch{}
    return {cat:"자랑",title:"",content:"",image:null,images:[],nick:initNick,keepNick:initKeep};
  });
  const[newComment,setNewComment]=useState("");
  const imgRef=useRef<HTMLInputElement|null>(null);
  const imgMultiRef=useRef<HTMLInputElement|null>(null);

  // 카테고리 — 어드민 설정 있으면 사용 (active만), 없으면 기본
  const activeAdminCats=(adminCats||[]).filter((c:any)=>c.active!==false);
  const cats=(()=>{
    if(activeAdminCats.length>0){
      return["전체","🔥 인기",...activeAdminCats.sort((a:any,b:any)=>(a.order||0)-(b.order||0)).map((c:any)=>`${c.emoji} ${c.name}`)];
    }
    // v316: 어드민 default와 동기화 — 9개 카테고리
    return["전체","🔥 인기","✨ 자랑","💭 고민","🙏 성지순례","❓ Q&A","💘 연애","💰 재물","💼 이직","🌿 건강","☕ 일상"];
  })();

  // 자동 닉네임 생성 (닉네임 미입력시 fallback)
  const autoNickname=()=>{
    const places=["강남역","홍대","성수동","한강","서울숲","연남동","이태원","망원동","잠실","여의도"];
    const traits=["도화살 92%","재물운 상위","갓생러","럭키 비키","복덩이","도도한","감성","먹보","워커홀릭","츤데레"];
    const animals=["사슴","포메라니안","부엉이","다람쥐","토끼","너구리","고양이","강아지","햄스터","여우"];
    return `${places[Math.floor(Math.random()*places.length)]} ${traits[Math.floor(Math.random()*traits.length)]} ${animals[Math.floor(Math.random()*animals.length)]}`;
  };

  function saveAndUpdate(newPosts:any[]){setPosts(newPosts);try{localStorage.setItem("chungi_bamboo_posts",JSON.stringify(newPosts));}catch{}}
  function saveComments(nc:Record<number,any[]>){setComments(nc);try{localStorage.setItem("chungi_bamboo_comments",JSON.stringify(nc));}catch{}}
  function saveLikes(ls:Set<number>){setMyLikes(ls);try{localStorage.setItem("chungi_bamboo_likes",JSON.stringify(Array.from(ls)));}catch{}}

  function handleLike(postId:number){
    const alreadyLiked=myLikes.has(postId);
    const newLikes=new Set(myLikes);
    if(alreadyLiked)newLikes.delete(postId);else newLikes.add(postId);
    saveLikes(newLikes);
    const updated=posts.map(p=>p.id===postId?{...p,likes:Math.max(0,p.likes+(alreadyLiked?-1:1))}:p);
    saveAndUpdate(updated);
    // viewPost도 같이 갱신 (상세화면에서 카운트 즉시 반영)
    setViewPost((vp:any)=>vp&&vp.id===postId?updated.find(p=>p.id===postId):vp);
  }
  function handleView(post:any){
    saveAndUpdate(posts.map(p=>p.id===post.id?{...p,views:(p.views||0)+1}:p));
    setViewPost(post);
  }
  // 금칙어 감지 — 글/댓글 본문에서 어드민 설정 키워드 찾기
  function checkBlockedWords(text:string):string|null{
    const t=(text||"").toLowerCase();
    for(const w of blockedWords){
      if(w&&t.includes(w.toLowerCase()))return w;
    }
    return null;
  }

  function handleSubmitPost(){
    if(!isLoggedIn){alert("로그인이 필요해요 🌿");onLogin?.();return;}
    if(!newPost.title.trim()||!newPost.content.trim()){alert("제목과 내용을 입력해주세요");return;}
    if(newPost.content.length>2000){alert("본문은 2000자 이내로 작성해주세요");return;}
    // 금칙어 검사 (제목 + 본문)
    const badWord=checkBlockedWords(`${newPost.title} ${newPost.content}`);
    if(badWord){alert(`🚫 '${badWord}' 같은 부적절한 단어는 사용할 수 없어요.\n광고·홍보·욕설 등 커뮤니티 규칙을 지켜주세요.`);return;}
    // 닉네임 차단 검사
    if(newPost.nick.trim()&&blockedNicks.includes(newPost.nick.trim())){alert("🚫 이 닉네임은 사용할 수 없어요. 다른 닉네임으로 시도해주세요.");return;}
    const finalNick=newPost.nick.trim()||autoNickname();
    try{
      if(newPost.keepNick&&newPost.nick.trim()){localStorage.setItem("chungi_bamboo_nick",newPost.nick.trim());setSavedNick(newPost.nick.trim());}
      else if(!newPost.keepNick){localStorage.removeItem("chungi_bamboo_nick");setSavedNick("");}
    }catch{}
    // 수정 모드일 때
    if(editingId){
      saveAndUpdate(posts.map(p=>p.id===editingId?{
        ...p,cat:newPost.cat,title:newPost.title,content:newPost.content,nick:finalNick,tier:myTier,
        image:newPost.image||undefined,images:newPost.images&&newPost.images.length>0?newPost.images:undefined,
        edited:true,editedDate:"방금 수정",
      }:p));
      setEditingId(null);
    }else{
      const p:any={id:Date.now(),cat:newPost.cat,title:newPost.title,nick:finalNick,tier:myTier,content:newPost.content,likes:0,comments:0,views:1,date:"방금"};
      if(newPost.image)p.image=newPost.image;
      if(newPost.images&&newPost.images.length>0)p.images=newPost.images;
      saveAndUpdate([p,...posts]);
    }
    setNewPost(prev=>({cat:"자랑",title:"",content:"",image:null,images:[],nick:prev.keepNick?prev.nick:"",keepNick:prev.keepNick}));
    setWriteOpen(false);
  }
  // 이미지 리사이즈 유틸 (800px · JPEG 72%)
  function resizeImage(file:File):Promise<string>{
    return new Promise((resolve,reject)=>{
      if(file.size>2*1024*1024){reject(new Error("2MB 이하"));return;}
      const reader=new FileReader();
      reader.onload=ev=>{
        try{
          const img2=new window.Image();
          img2.onload=()=>{
            try{
              const M=800;let w=img2.width,h=img2.height;
              if(w>M||h>M){const r=Math.min(M/w,M/h);w=Math.round(w*r);h=Math.round(h*r);}
              const cv=document.createElement("canvas");cv.width=w;cv.height=h;
              cv.getContext("2d")?.drawImage(img2,0,0,w,h);
              resolve(cv.toDataURL("image/jpeg",0.72));
            }catch{resolve(ev.target?.result as string);}
          };
          img2.src=ev.target?.result as string;
        }catch{resolve(ev.target?.result as string);}
      };
      reader.onerror=()=>reject(new Error("읽기 실패"));
      reader.readAsDataURL(file);
    });
  }
  // 대표 사진 단일 업로드 (피드 썸네일용)
  async function handleImagePick(e:React.ChangeEvent<HTMLInputElement>){
    const f=e.target.files?.[0];if(!f)return;
    try{const data=await resizeImage(f);setNewPost(p=>({...p,image:data}));}
    catch(err:any){alert(err.message==="2MB 이하"?"2MB 이하 이미지만 올려주세요 🙏":"이미지 처리 실패");}
    if(e.target)e.target.value="";
  }
  // 본문 이미지 여러 장 업로드
  async function handleMultiImagePick(e:React.ChangeEvent<HTMLInputElement>){
    const files=Array.from(e.target.files||[]);if(!files.length)return;
    if(files.length+newPost.images.length>6){alert("본문 이미지는 최대 6장까지 올릴 수 있어요 🙏");return;}
    try{
      const results=await Promise.all(files.map(f=>resizeImage(f).catch(()=>null)));
      const ok=results.filter(Boolean) as string[];
      setNewPost(p=>{
        const newImages=[...p.images,...ok];
        // 대표 사진 미지정이면 첫 업로드 이미지를 자동 대표로
        return{...p,images:newImages,image:p.image||ok[0]||null};
      });
    }catch{alert("이미지 처리 실패");}
    if(e.target)e.target.value="";
  }
  // 본문 이미지 중 하나를 대표 사진으로 지정
  function setCoverImage(imgData:string){setNewPost(p=>({...p,image:imgData}));}
  // 본문 이미지 삭제
  function removeContentImage(idx:number){
    setNewPost(p=>{
      const newImages=p.images.filter((_,i)=>i!==idx);
      const removedImg=p.images[idx];
      const newCover=p.image===removedImg?(newImages[0]||null):p.image;
      return{...p,images:newImages,image:newCover};
    });
  }
  // 이미지 드래그 순서 변경
  function onImgDragStart(idx:number){setDragImgIdx(idx);}
  function onImgDragOver(e:React.DragEvent){e.preventDefault();}
  function onImgDrop(targetIdx:number){
    if(dragImgIdx===null||dragImgIdx===targetIdx){setDragImgIdx(null);return;}
    setNewPost(p=>{
      const arr=[...p.images];
      const[moved]=arr.splice(dragImgIdx,1);
      arr.splice(targetIdx,0,moved);
      return{...p,images:arr};
    });
    setDragImgIdx(null);
  }
  // 내 글인지 판별 (저장된 닉네임으로)
  function isMyPost(p:any){return savedNick&&p.nick===savedNick;}
  // 글 수정 시작 — writeOpen 열고 기존 값 채움
  function handleEditPost(post:any){
    setEditingId(post.id);
    setNewPost(p=>({
      ...p,
      cat:post.cat||"자랑",
      title:post.title||"",
      content:post.content||"",
      nick:post.nick||"",
      image:post.image||null,
      images:post.images||(post.image?[post.image]:[]),
    }));
    setViewPost(null);
    setWriteOpen(true);
  }
  // 글 삭제
  function handleDeletePost(id:number){
    if(!confirm("이 글을 삭제할까요? 댓글도 함께 사라져요."))return;
    saveAndUpdate(posts.filter(p=>p.id!==id));
    const nc={...comments};delete nc[id];saveComments(nc);
    setViewPost(null);
  }
  function handleSubmitComment(){
    if(!viewPost){alert("글이 선택되지 않았어요");return;}
    if(!newComment.trim()){alert("댓글 내용을 입력해주세요");return;}
    if(!isLoggedIn){alert("로그인이 필요해요 🌿");onLogin?.();return;}
    // 금칙어 검사
    const badWord=(()=>{const t=newComment.toLowerCase();for(const w of blockedWords){if(w&&t.includes(w.toLowerCase()))return w;}return null;})();
    if(badWord){alert(`🚫 '${badWord}' 같은 부적절한 단어는 사용할 수 없어요.`);return;}
    // 댓글도 저장된 닉네임 사용 (있으면)
    const commentNick=savedNick||autoNickname();
    const c={id:Date.now(),nick:commentNick,tier:myTier,content:newComment,date:"방금",likes:0};
    const updated={...comments,[viewPost.id]:[...(comments[viewPost.id]||[]),c]};
    saveComments(updated);
    saveAndUpdate(posts.map(p=>p.id===viewPost.id?{...p,comments:(p.comments||0)+1}:p));
    setNewComment("");
  }

  // 차단된 닉네임 글 제외 (단, 본인 글은 보이도록)
  const visiblePosts=posts.filter(p=>!blockedNicks.includes(p.nick)||p.nick===savedNick);
  const catFiltered=activeCat==="전체"?visiblePosts:activeCat==="🔥 인기"?[...visiblePosts].sort((a,b)=>(b.likes+b.views/10)-(a.likes+a.views/10)).slice(0,10):visiblePosts.filter(p=>activeCat.includes(p.cat));
  const filtered=myOnly?catFiltered.filter(p=>savedNick&&p.nick===savedNick):catFiltered;
  const pinned=filtered.filter(p=>p.pinned);
  // 🔥 HOT 박스에 들어간 글 ID 계산 — 일반 리스트에서 중복 제외 (사용자 요청 v233)
  const hotBoxIds=(()=>{
    if(myOnly)return new Set<any>();
    if(activeCat==="전체")return new Set(pinned.map((p:any)=>p.id));
    if(activeCat==="🔥 인기")return new Set([...visiblePosts].sort((a:any,b:any)=>(b.likes+b.views/10)-(a.likes+a.views/10)).slice(0,3).map((p:any)=>p.id));
    const inCat=visiblePosts.filter((p:any)=>activeCat.includes(p.cat));
    // v340: 글이 4개 이상일 때만 베스트 분리. 적으면 일반 목록 그대로 노출 (사용자 요청 — 새 글 사라지는 버그 fix)
    if(inCat.length<4)return new Set<any>();
    return new Set([...inCat].sort((a:any,b:any)=>b.likes-a.likes).slice(0,3).map((p:any)=>p.id));
  })();
  // v341: 베스트 박스에 들어간 글도 하단 일반 목록에 그대로 노출 (사용자 요청 — 흡수해도 다 보이게)
  const normal=filtered.filter(p=>!p.pinned);

  return(
    <div className="page">
      {/* 헤더 — 이용권 / 기록소와 동일 규격 (20/12px) + 내 글 버튼 */}
      <div style={{padding:"20px 18px 10px",display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:20,fontWeight:900,marginBottom:2}}>🎋 대나무숲</div>
          <div style={{fontSize:12,color:"var(--mist)"}}>천기 유저들의 익명 수다 · 운세 자랑 · 고민 상담</div>
        </div>
        {savedNick&&
          <button onClick={()=>setMyOnly(v=>!v)} style={{flexShrink:0,padding:"7px 12px",borderRadius:14,background:myOnly?"linear-gradient(135deg,#E8C87A,#B8942E)":"rgba(232,200,122,0.08)",border:`1px solid ${myOnly?"#E8C87A":"rgba(232,200,122,0.3)"}`,color:myOnly?"#1A1A1A":"#E8C87A",fontSize:11,fontWeight:800,cursor:"pointer",fontFamily:"inherit",boxShadow:myOnly?"0 3px 10px rgba(232,200,122,0.35)":"none"}}>
            {myOnly?"✓ 내 글":"📝 내 글"}
          </button>
        }
      </div>

      {/* 카테고리 탭 — pill + 드래그 가능 가로 스크롤 */}
      <div className="drag-scroll" style={{display:"flex",gap:7,overflowX:"auto",padding:"0 18px 14px",scrollbarWidth:"none",WebkitOverflowScrolling:"touch" as any}}>
        {cats.map(c=>{
          const sel=activeCat===c;
          return <button key={c} onClick={()=>setActiveCat(c)} style={{flexShrink:0,padding:"8px 16px",background:sel?"linear-gradient(135deg,#5fc49e,#3a9e74)":"rgba(255,255,255,0.04)",color:sel?"#0e2921":"var(--mist)",border:`1px solid ${sel?"#5fc49e":"rgba(255,255,255,0.08)"}`,borderRadius:22,fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap",boxShadow:sel?"0 3px 10px rgba(95,196,158,0.3)":"none",transition:"all .18s"}}>{c}</button>;
        })}
      </div>

      {/* 글쓰기 FAB — v702: 천기용어풀이 FAB(bottom:78)와 겹치지 않게 위로 (78+40+20=138) */}
      <button onClick={()=>setWriteOpen(true)} style={{position:"fixed",bottom:140,right:20,width:56,height:56,borderRadius:"50%",background:"linear-gradient(135deg,#5fc49e,#2f8d6a)",color:"#fff",border:"none",fontSize:24,cursor:"pointer",boxShadow:"0 8px 24px rgba(95,196,158,0.45)",zIndex:100,fontFamily:"inherit"}}>✏️</button>

      {/* 포스트 카드 — 좌측 글 / 우측 정사각 썸네일 (글 높이에 맞춘 리듬) */}
      {(()=>{
        const renderCard=(p:any,isPinned:boolean)=>{
          const thumb=p.image||p.resultType?._imgSrc||p.resultType?._imgSrc1||null;
          const liked=myLikes.has(p.id);
          const mine=isMyPost(p);
          return(
          <div key={p.id} onClick={()=>handleView(p)} style={{background:isPinned?"linear-gradient(135deg,rgba(95,196,158,0.08),rgba(95,196,158,0.02))":"transparent",borderBottom:"1px solid rgba(255,255,255,0.07)",padding:"16px 4px 14px",cursor:"pointer",transition:"background .15s",display:"flex",gap:12,alignItems:"stretch"}}>
            {/* 좌측: 메타 + 제목 + 본문 + 하단지표 (전체 높이 채움) */}
            <div style={{flex:1,minWidth:0,display:"flex",flexDirection:"column"}}>
              {/* 상단 메타 */}
              <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:8,fontSize:11,flexWrap:"wrap"}}>
                <span style={{color:mine?"#5fc49e":"#E8C87A",fontWeight:800}}>{p.tier||"🌿"} {p.nick}</span>
                {mine&&<span style={{fontSize:9,background:"rgba(95,196,158,0.18)",color:"#5fc49e",padding:"1px 6px",borderRadius:5,fontWeight:800}}>내 글</span>}
                <span style={{color:"rgba(168,196,184,0.35)"}}>·</span>
                <span style={{color:"#5fc49e",fontWeight:700}}>{p.cat}</span>
                <span style={{color:"rgba(168,196,184,0.35)"}}>·</span>
                <span style={{color:"rgba(168,196,184,0.55)"}}>{p.date}{p.edited?" · 수정됨":""}</span>
                {isPinned&&<span style={{marginLeft:"auto",fontSize:10,background:"linear-gradient(135deg,#ff6b6b,#ee5a52)",color:"#fff",padding:"2px 8px",borderRadius:8,fontWeight:900,letterSpacing:0.3,boxShadow:"0 2px 6px rgba(255,107,107,0.35)"}}>🔥 HOT</span>}
              </div>
              {/* 제목 */}
              <div style={{fontSize:16,fontWeight:800,color:"#ffffff",marginBottom:6,lineHeight:1.4,letterSpacing:"-0.2px",wordBreak:"keep-all",display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical" as any,overflow:"hidden"}}>{p.title}</div>
              {/* 본문 */}
              <div style={{fontSize:12.5,fontWeight:400,color:"rgba(220,232,226,0.68)",lineHeight:1.55,display:"-webkit-box",WebkitLineClamp:thumb?2:3,WebkitBoxOrient:"vertical" as any,overflow:"hidden",wordBreak:"keep-all",flex:1}}>{p.content}</div>
              {/* 하단 메타 — v712: ✨ 공감(전체 reactions 합) 💬 댓글 👁 조회 */}
              <div style={{display:"flex",alignItems:"center",gap:16,fontSize:11,color:"rgba(180,210,195,0.55)",marginTop:10}}>
                {(()=>{const tot=getRxTotal(p);const myCnt=(myReactions[p.id]||[]).length;return <span style={{color:myCnt>0?"#ff6b6b":"rgba(180,210,195,0.6)",fontWeight:myCnt>0?700:500}}>✨ {tot}</span>;})()}
                <span>💬 {p.comments}</span>
                <span>👁 {p.views}</span>
              </div>
            </div>
            {/* 우측: 이미지 — 좌측 컬럼 높이 따라 stretch */}
            {thumb&&<BambooStretchThumb thumb={thumb}/>}
          </div>);
        };
        return(<div style={{padding:"0 18px"}}>
          {/* 📌 공지/HOT 배너 — 모든 탭 상단에 박스 형식 (전체=고정글, 인기/카테고리=베스트 3) */}
          {(()=>{
            // 탭별 HOT 리스트 결정
            //  - 전체 + !myOnly: pinned 글
            //  - 인기 탭: 좋아요+조회수 기준 Top 3
            //  - 자랑/고민/성지순례/Q&A: 카테고리 내 좋아요 기준 Top 3
            //  - myOnly: 박스 숨김
            if(myOnly)return null;
            let hotList:any[]=[];
            let hotLabel="";
            let hotIcon="🔥";
            if(activeCat==="전체"){
              hotList=pinned;hotLabel="고정 · HOT 글";hotIcon="📌";
            } else if(activeCat==="🔥 인기"){
              hotList=[...visiblePosts].sort((a:any,b:any)=>(b.likes+b.views/10)-(a.likes+a.views/10)).slice(0,3);hotLabel="인기 베스트";hotIcon="🔥";
            } else {
              const inCat=visiblePosts.filter((p:any)=>activeCat.includes(p.cat));
              // v499: 베스트 박스는 항상 노출. 좋아요 1개 이상인 글만 베스트로 인정
              hotList=[...inCat].filter((p:any)=>p.likes>0).sort((a:any,b:any)=>b.likes-a.likes).slice(0,3);
              // v603: 이모지 중복 제거 (hotIcon이 별도라 라벨에선 🔥/✨ 빼고 카테고리명만)
              hotLabel=`${activeCat.replace(/^[^\s가-힣]+\s*/,"")} 베스트`;hotIcon="🔥";
            }
            // v499: hotList 비어있어도 안내 박스 노출 (사용자 요청 — 박스 자체가 없어서 헷갈림)
            const isEmpty=hotList.length===0;
            return(
              <div style={{marginBottom:14,background:"linear-gradient(135deg,rgba(95,196,158,0.12) 0%,rgba(232,200,122,0.08) 100%)",border:"1px solid rgba(95,196,158,0.3)",borderRadius:14,padding:"10px 12px",boxShadow:"0 3px 14px rgba(95,196,158,0.12)"}}>
                <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:8,fontSize:10,fontWeight:800,color:"#5fc49e",letterSpacing:1}}>
                  <span style={{fontSize:12}}>{hotIcon}</span>
                  <span>{hotLabel}</span>
                  <span style={{marginLeft:"auto",fontSize:9,color:"rgba(168,196,184,0.6)",fontWeight:600}}>{hotList.length}개</span>
                </div>
                {isEmpty&&<div style={{padding:"14px 6px",textAlign:"center",fontSize:11,color:"rgba(168,196,184,0.7)",fontWeight:600,lineHeight:1.7}}>아직 베스트가 없습니다 🌿<br/><span style={{fontSize:10,opacity:0.8}}>좋아요를 가장 많이 받은 글이 여기에 노출돼요</span></div>}
                {hotList.map((p:any,idx:number)=>(
                  <div key={p.id} onClick={()=>handleView(p)} style={{display:"flex",gap:9,alignItems:"center",padding:"8px 6px",cursor:"pointer",borderTop:"1px dashed rgba(255,255,255,0.06)"}}>
                    {/* v603: 베스트 순위 표시 (🥇🥈🥉) — 모든 항목 🔥 중복 정리 */}
                    <span style={{fontSize:16,flexShrink:0,width:24,textAlign:"center"}}>{idx===0?"🥇":idx===1?"🥈":idx===2?"🥉":"🔥"}</span>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:13,fontWeight:700,color:"#fff",marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.title}</div>
                      <div style={{fontSize:10,color:"rgba(168,196,184,0.6)"}}>{p.tier||"🌿"} {p.nick} · {p.date} · ❤ {p.likes}</div>
                    </div>
                    {(p.image||p.resultType?._imgSrc)&&
                      <div style={{flexShrink:0,width:40,height:40,borderRadius:8,overflow:"hidden",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.08)"}}>
                        <img src={p.image||p.resultType?._imgSrc} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.currentTarget.parentElement.style.display="none";}}/>
                      </div>
                    }
                  </div>
                ))}
              </div>
            );
          })()}
          {/* 일반 글 리스트 — v316: HOT 박스에 이미 들어간 pinned는 중복 제외, 하단 잘림 방지 padding-bottom */}
          {(activeCat==="전체"&&!myOnly?[]:pinned.filter(p=>!hotBoxIds.has(p.id))).map(p=>renderCard(p,true))}
          {normal.map(p=>renderCard(p,false))}
          {filtered.length===0&&myOnly&&
            <div style={{textAlign:"center",padding:"40px 20px",color:"var(--mist)",fontSize:12}}>
              ✍️ 아직 작성한 글이 없어요<br/>
              <span style={{fontSize:10,opacity:0.7}}>글쓰기 버튼을 눌러 첫 글을 남겨보세요!</span>
            </div>
          }
          {/* 하단 여백 — 탭바·플로팅 버튼이 글 잘리는 거 방지 */}
          <div style={{height:120}}/>
        </div>);
      })()}

      {filtered.length===0&&<div style={{textAlign:"center",padding:"60px 20px",color:"var(--mist)"}}>
        <div style={{fontSize:40,marginBottom:12}}>🎋</div>
        <div style={{fontSize:13}}>아직 이 카테고리엔 글이 없어요</div>
        <div style={{fontSize:11,color:"rgba(168,196,184,0.6)",marginTop:6}}>첫 번째로 글을 써보세요!</div>
      </div>}

      {/* 글쓰기 모달 — 바깥 클릭 닫힘 방지 (X/취소 버튼으로만 닫힘) */}
      {writeOpen&&<div className="ov">
        <div className="md">
          <div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={()=>setWriteOpen(false)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
          <div className="mt">🎋 대나무숲에 글쓰기</div>
          <div className="ms">닉네임 직접 입력 or 자동 생성 · 최대 6장 사진</div>
          <div style={{marginTop:12}}>
            {/* 카테고리 — 어드민 active 카테고리 자동 연동 (사용자 요청 v316: 배지 → select 드롭다운) */}
            <div style={{fontSize:11,color:"var(--mist)",marginBottom:6}}>카테고리</div>
            {(()=>{
              const writeCats=activeAdminCats.length>0
                ?activeAdminCats.sort((a:any,b:any)=>(a.order||0)-(b.order||0)).map((c:any)=>({label:`${c.emoji} ${c.name}`,value:c.name}))
                :[{label:"✨ 자랑",value:"자랑"},{label:"💭 고민",value:"고민"},{label:"🙏 성지순례",value:"성지순례"},{label:"❓ Q&A",value:"Q&A"},{label:"💘 연애",value:"연애"},{label:"💰 재물",value:"재물"},{label:"💼 이직",value:"이직"},{label:"🌿 건강",value:"건강"},{label:"☕ 일상",value:"일상"}];
              return <select value={newPost.cat} onChange={e=>setNewPost(p=>({...p,cat:e.target.value}))} style={{width:"100%",padding:"10px 12px",background:"var(--ink3)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:11,color:newPost.cat?"#5fc49e":"var(--mist)",fontSize:13,fontWeight:700,fontFamily:"inherit",marginBottom:12,cursor:"pointer",appearance:"auto"}}>
                <option value="" style={{background:"#234F42",color:"#A8C4B8"}}>카테고리 선택</option>
                {writeCats.map(c=>(<option key={c.value} value={c.value} style={{background:"#234F42",color:"#fff"}}>{c.label}</option>))}
              </select>;
            })()}

            {/* 닉네임 입력 + 계속 사용하기 */}
            <div style={{fontSize:11,color:"var(--mist)",marginBottom:6,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
              <span>🌿 닉네임 {savedNick&&<span style={{color:"#E8C87A",fontSize:10,marginLeft:6}}>(저장된 닉네임)</span>}</span>
              <label style={{display:"flex",alignItems:"center",gap:5,cursor:"pointer",fontSize:10,color:"var(--mist)"}}>
                <input type="checkbox" checked={newPost.keepNick} onChange={e=>setNewPost(p=>({...p,keepNick:e.target.checked}))} style={{cursor:"pointer",accentColor:"#5fc49e"}}/>
                계속 사용하기
              </label>
            </div>
            <input type="text" placeholder="나만의 닉네임 (비우면 자동 생성)" value={newPost.nick} onChange={e=>setNewPost(p=>({...p,nick:e.target.value.slice(0,20)}))} maxLength={20} style={{width:"100%",padding:10,background:"var(--ink3)",border:"1px solid rgba(232,200,122,0.25)",borderRadius:11,color:"#E8C87A",fontSize:12,fontWeight:700,marginBottom:12,fontFamily:"inherit"}}/>

            {/* 제목 + 글자수 */}
            <div style={{position:"relative",marginBottom:8}}>
              <input type="text" placeholder="제목을 입력하세요" value={newPost.title} onChange={e=>setNewPost(p=>({...p,title:e.target.value.slice(0,60)}))} maxLength={60} style={{width:"100%",padding:"12px 56px 12px 12px",background:"var(--ink3)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:11,color:"#fff",fontSize:13,fontFamily:"inherit"}}/>
              <div style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",fontSize:9,color:newPost.title.length>=55?"#ff6b6b":"rgba(168,196,184,0.5)",fontWeight:700}}>{newPost.title.length}/60</div>
            </div>
            {/* 본문 + 글자수 */}
            <div style={{position:"relative",marginBottom:10}}>
              <textarea placeholder="자유롭게 적어주세요 🎋&#10;(예: 수비학 7번 나왔는데 다들 내향적인가요?)" value={newPost.content} onChange={e=>setNewPost(p=>({...p,content:e.target.value.slice(0,2000)}))} maxLength={2000} rows={6} style={{width:"100%",padding:12,background:"var(--ink3)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:11,color:"#fff",fontSize:12,resize:"none",fontFamily:"inherit",display:"block"}}/>
              <div style={{position:"absolute",right:10,bottom:10,fontSize:9,color:newPost.content.length>=1900?"#ff6b6b":"rgba(168,196,184,0.5)",fontWeight:700,background:"rgba(0,0,0,0.4)",padding:"2px 6px",borderRadius:6}}>{newPost.content.length}/2000</div>
            </div>

            {/* 본문 이미지 업로드 (여러 장, 최대 6장) */}
            <input ref={imgMultiRef} type="file" accept="image/*" multiple onChange={handleMultiImagePick} style={{display:"none"}}/>
            <input ref={imgRef} type="file" accept="image/*" onChange={handleImagePick} style={{display:"none"}}/>

            {/* 이미지 추가 버튼 */}
            {newPost.images.length===0?(
              <button onClick={()=>imgMultiRef.current?.click()} style={{width:"100%",padding:"24px 14px",background:"linear-gradient(135deg,rgba(95,196,158,0.12),rgba(95,196,158,0.04))",border:"2px dashed rgba(95,196,158,0.5)",borderRadius:12,cursor:"pointer",fontFamily:"inherit",color:"var(--mist)",display:"flex",flexDirection:"column",alignItems:"center",gap:8,marginBottom:10}}>
                <span style={{fontSize:40}}>🖼️</span>
                <span style={{fontSize:14,fontWeight:700,color:"#5fc49e"}}>📸 사진 추가하기 (최대 6장)</span>
                <span style={{fontSize:11,color:"rgba(168,196,184,0.7)",textAlign:"center",lineHeight:1.5}}>관상짤·사주·타로 결과 캡처 공유<br/>첫 번째 사진이 자동 대표 사진 · ⭐ 지정 가능</span>
              </button>
            ):(
              <div style={{marginBottom:10}}>
                <div style={{fontSize:11,color:"var(--mist)",marginBottom:6,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <span>📸 본문 사진 <strong style={{color:"#5fc49e"}}>{newPost.images.length}</strong>/6장</span>
                  <span style={{fontSize:10,color:"#E8C87A"}}>⭐ 대표 = 피드 썸네일</span>
                </div>
                <div style={{fontSize:9,color:"rgba(168,196,184,0.6)",marginBottom:6,fontStyle:"italic"}}>💡 사진을 드래그해서 순서를 바꿀 수 있어요</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6,marginBottom:8}}>
                  {newPost.images.map((img,i)=>{
                    const isCover=newPost.image===img;
                    const isDragging=dragImgIdx===i;
                    return(
                      <div key={i}
                        draggable
                        onDragStart={()=>onImgDragStart(i)}
                        onDragOver={onImgDragOver}
                        onDrop={()=>onImgDrop(i)}
                        onDragEnd={()=>setDragImgIdx(null)}
                        style={{position:"relative",aspectRatio:"1/1",borderRadius:10,overflow:"hidden",border:isCover?"2.5px solid #E8C87A":"1px solid rgba(255,255,255,0.1)",boxShadow:isCover?"0 0 12px rgba(232,200,122,0.35)":"none",opacity:isDragging?0.4:1,cursor:"grab"}}>
                        <img src={img} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block",pointerEvents:"none"}}/>
                        {/* 순서 번호 */}
                        <div style={{position:"absolute",top:4,right:4,background:"rgba(0,0,0,0.7)",color:"#fff",width:20,height:20,borderRadius:"50%",fontSize:10,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center"}}>{i+1}</div>
                        {isCover&&<div style={{position:"absolute",top:4,left:4,background:"#E8C87A",color:"#1A1A1A",padding:"2px 7px",borderRadius:6,fontSize:9,fontWeight:900,letterSpacing:0.3}}>⭐ 대표</div>}
                        {/* 하단 버튼들 */}
                        <div style={{position:"absolute",bottom:0,left:0,right:0,display:"flex",gap:2,padding:3,background:"linear-gradient(to top,rgba(0,0,0,0.8),transparent)"}}>
                          {!isCover&&<button onClick={(e)=>{e.stopPropagation();setCoverImage(img);}} style={{flex:1,padding:"4px 0",background:"rgba(0,0,0,0.7)",border:"1px solid rgba(232,200,122,0.4)",color:"#E8C87A",fontSize:9,fontWeight:700,borderRadius:5,cursor:"pointer",fontFamily:"inherit"}}>⭐</button>}
                          <button onClick={(e)=>{e.stopPropagation();removeContentImage(i);}} style={{flex:isCover?1:0.6,padding:"4px 0",background:"rgba(0,0,0,0.7)",border:"1px solid rgba(255,107,107,0.4)",color:"#ff6b6b",fontSize:9,fontWeight:700,borderRadius:5,cursor:"pointer",fontFamily:"inherit"}}>✕ 삭제</button>
                        </div>
                      </div>
                    );
                  })}
                </div>
                {newPost.images.length<6&&
                  <button onClick={()=>imgMultiRef.current?.click()} style={{width:"100%",padding:"10px",background:"rgba(95,196,158,0.08)",border:"1px dashed rgba(95,196,158,0.35)",borderRadius:10,cursor:"pointer",fontFamily:"inherit",color:"#5fc49e",fontSize:12,fontWeight:700}}>
                    ➕ 사진 더 추가하기 ({newPost.images.length}/6)
                  </button>
                }
              </div>
            )}
          </div>
          <button className="btn btn-p" style={{marginTop:12,background:"linear-gradient(135deg,#5fc49e,#2f8d6a)"}} onClick={handleSubmitPost}>{editingId?"✏️ 수정 완료":"🎋 대나무숲에 던지기"}</button>
          <button className="btn btn-g" style={{marginTop:8}} onClick={()=>{setWriteOpen(false);setEditingId(null);}}>취소</button>
        </div>
      </div>}

      {/* 글 상세 모달 — 바깥 클릭 닫힘 방지 (X/닫기 버튼으로만 닫힘) */}
      {viewPost&&<div className="ov">
        <div className="md" style={{maxHeight:"85vh",overflowY:"auto"}}>
          <div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={()=>setViewPost(null)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
            <div style={{fontSize:9,color:"#5fc49e",fontWeight:700}}>{viewPost.cat}</div>
            {/* v727: X 버튼(우측 상단 sticky 28px)과 시각적 겹침 fix — 수정/삭제 버튼 그룹에 marginRight 36 (X 28 + 여유 8) 추가해서 안쪽으로 */}
            {isMyPost(viewPost)&&<div style={{display:"flex",gap:6,marginRight:36}}>
              <button onClick={()=>handleEditPost(viewPost)} style={{padding:"4px 10px",borderRadius:8,background:"rgba(232,200,122,0.12)",border:"1px solid rgba(232,200,122,0.35)",color:"#E8C87A",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>✏️ 수정</button>
              <button onClick={()=>handleDeletePost(viewPost.id)} style={{padding:"4px 10px",borderRadius:8,background:"rgba(255,107,107,0.12)",border:"1px solid rgba(255,107,107,0.35)",color:"#ff6b6b",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>🗑️ 삭제</button>
            </div>}
          </div>
          <div className="mt" style={{fontSize:17}}>{viewPost.title}</div>
          <div style={{fontSize:10,color:"var(--mist)",marginBottom:10,display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
            <span>{viewPost.tier||"🌿"} {viewPost.nick}</span>
            <span>·</span>
            <span>{viewPost.date}{viewPost.edited?" · 수정됨":""}</span>
            <span>·</span>
            <span>👁 {viewPost.views}</span>
          </div>
          <div style={{background:"var(--ink3)",borderRadius:12,padding:14,fontSize:12,color:"#fff",lineHeight:1.75,marginBottom:12,whiteSpace:"pre-wrap",wordBreak:"keep-all" as any}}>{viewPost.content}</div>
          {/* 본문 이미지 여러 장 — 원본 비율 그대로 세로 스택 */}
          {(viewPost.images&&viewPost.images.length>0)&&(
            <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:12}}>
              {viewPost.images.map((img:string,i:number)=>(
                <div key={i} style={{borderRadius:10,overflow:"hidden",border:"1px solid rgba(255,255,255,0.08)",background:"rgba(0,0,0,0.3)"}}>
                  <img src={img} alt="" style={{width:"100%",height:"auto",display:"block"}}/>
                </div>
              ))}
            </div>
          )}
          {/* 본문 이미지 없고 대표사진만 있을 때 — 원본 비율 */}
          {(!viewPost.images||viewPost.images.length===0)&&viewPost.image&&(
            <div style={{borderRadius:12,overflow:"hidden",border:"1px solid rgba(255,255,255,0.08)",marginBottom:12,background:"rgba(0,0,0,0.3)"}}>
              <img src={viewPost.image} alt="" style={{width:"100%",height:"auto",display:"block"}}/>
            </div>
          )}
          {/* v712: 6종 공감 이모지 그리드 (3열 × 2행) + 댓글 버튼 */}
          <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:16}}>
            <div style={{fontSize:10,color:"var(--mist)",fontWeight:700,letterSpacing:0.5,marginBottom:2}}>이 글이 어땠나요? — 여러 개 선택 가능</div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6}}>
              {_BAMBOO_REACTIONS.map(r=>{
                const has=hasMyRx(viewPost.id,r.k);
                const cnt=getRxCount(viewPost,r.k);
                return(
                  <button key={r.k} onClick={()=>handleReaction(viewPost.id,r.k)} style={{
                    padding:"9px 6px",
                    background:has?`${r.c}22`:"var(--ink3)",
                    border:`1px solid ${has?r.c+"66":"rgba(255,255,255,0.08)"}`,
                    borderRadius:10,
                    color:has?r.c:"var(--mist)",
                    fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"inherit",
                    display:"flex",alignItems:"center",justifyContent:"center",gap:5,
                    transition:"all .18s",
                  }}>
                    <span style={{fontSize:14}}>{r.e}</span>
                    <span style={{whiteSpace:"nowrap"}}>{r.l}</span>
                    {cnt>0&&<span style={{fontSize:10,opacity:0.85,fontWeight:800}}>{cnt}</span>}
                  </button>
                );
              })}
            </div>
            <button onClick={()=>{const el=document.getElementById("bamboo-comment-input");el?.focus();el?.scrollIntoView({behavior:"smooth",block:"center"});}} style={{padding:10,background:"var(--ink3)",border:"1px solid rgba(95,196,158,0.25)",borderRadius:10,color:"#5fc49e",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>💬 댓글 {(comments[viewPost.id]||[]).length}</button>
          </div>

          {/* 댓글 리스트 */}
          <div style={{marginBottom:12}}>
            <div style={{fontSize:12,fontWeight:800,color:"#5fc49e",marginBottom:8}}>💬 댓글</div>
            {(comments[viewPost.id]||[]).length===0&&<div style={{textAlign:"center",color:"var(--mist)",fontSize:11,padding:"16px 0"}}>첫 댓글을 달아보세요!</div>}
            {(comments[viewPost.id]||[]).map(c=>(
              <div key={c.id} style={{background:"var(--ink3)",borderRadius:10,padding:10,marginBottom:6,borderLeft:"2px solid #5fc49e"}}>
                <div style={{fontSize:9,color:"#5fc49e",fontWeight:700,marginBottom:3}}>{c.tier||"🌿"} {c.nick} <span style={{color:"rgba(168,196,184,0.5)",fontWeight:500}}>· {c.date}</span></div>
                <div style={{fontSize:11,color:"#fff",lineHeight:1.6,whiteSpace:"pre-wrap"}}>{c.content}</div>
              </div>
            ))}
          </div>

          {/* 댓글 입력 */}
          <div style={{display:"flex",gap:6}}>
            <input id="bamboo-comment-input" type="text" placeholder={isLoggedIn?"댓글을 적어주세요...":"🔒 로그인 후 댓글 작성"} value={newComment} onChange={e=>setNewComment(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")handleSubmitComment();}} style={{flex:1,padding:10,background:"var(--ink3)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:10,color:"#fff",fontSize:11,fontFamily:"inherit"}}/>
            <button onClick={handleSubmitComment} style={{padding:"10px 16px",background:"#5fc49e",color:"#0e2921",border:"none",borderRadius:10,fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit"}}>작성</button>
          </div>
          <button className="btn btn-g" style={{marginTop:12}} onClick={()=>setViewPost(null)}>닫기</button>
        </div>
      </div>}
    </div>
  );
}

function TicketsPage({onBuy}:any){
  const [specialItems,setSpecialItems] = useState(() => {
    try { const s = localStorage.getItem('chungi_special_items_v4'); if (s){const p=JSON.parse(s);if(p.length>=15)return p;} } catch {}
    return SPECIAL_ITEMS_DEFAULT;
  });
  // 어드민 비공개 토글 즉시 반영 — storage 이벤트 + visibilitychange
  useEffect(()=>{
    const sync=()=>{try{const s=localStorage.getItem('chungi_special_items_v4');if(s){const p=JSON.parse(s);if(p.length>=15)setSpecialItems(p);}}catch{}};
    window.addEventListener("storage",sync);
    const onVis=()=>{if(document.visibilityState==="visible")sync();};
    document.addEventListener("visibilitychange",onVis);
    const i=setInterval(sync,3000);
    return()=>{window.removeEventListener("storage",sync);document.removeEventListener("visibilitychange",onVis);clearInterval(i);};
  },[]);
  const [giftItem,setGiftItem] = useState<any>(null);
  const [giftPhone,setGiftPhone] = useState("");

  // 어드민 비공개 토글 적용 — visible:false 항목은 홈에서 숨김
  const packages = specialItems.filter((p:any)=>!p.id.startsWith("gift")&&p.visible!==false);
  const gifts = specialItems.filter((p:any)=>p.id.startsWith("gift")&&p.visible!==false);
  return(
    <div className="page">
      <div style={{padding:"20px 18px 10px"}}>
        <div style={{fontSize:20,fontWeight:900,marginBottom:2}}>💳 이용권 / 선물권</div>
        <div style={{fontSize:12,color:"var(--mist)"}}>패키지 · 선물권 · 구매 즉시 내정보에서 확인</div>
      </div>

      {/* 패키지 이용권 */}
      <div style={{padding:"0 18px 6px"}}><div style={{fontSize:14,fontWeight:700}}>📦 패키지 이용권</div></div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,padding:"0 18px 16px"}}>
        {packages.map((p,i)=>(
          <div key={i} style={{background:"var(--ink2)",border:"1px solid rgba(255,255,255,0.06)",borderRadius:16,padding:"14px 12px",cursor:"pointer",position:"relative",textAlign:"center"}} onClick={()=>onBuy({type:"ticket",title:p.title,price:p.price,originalPrice:p.originalPrice,discount:p.discount,icon:p.icon,id:p.id,contents:p.contents,sub:p.sub})}>
            {p.badge&&p.badge!=="없음"&&<div style={{position:"absolute",top:8,right:8,fontSize:8,fontWeight:700,padding:"2px 7px",borderRadius:8,background:"rgba(212,175,55,0.2)",color:"var(--gold)"}}>{p.badge}</div>}
            <div style={{fontSize:28,marginBottom:6}}>{p.icon}</div>
            <div style={{fontSize:12,fontWeight:700,marginBottom:3,lineHeight:1.3}}>{p.title}</div>
            <div style={{fontSize:9,color:"var(--mist)",marginBottom:6,lineHeight:1.4,whiteSpace:"pre-line"}}>{p.sub}</div>
            {p.originalPrice&&<div style={{fontSize:10,color:"var(--mist)",textDecoration:"line-through",marginBottom:2}}>정가 {p.originalPrice}</div>}
            <div style={{fontSize:14,fontWeight:900,color:"var(--gold)"}}>{p.price}</div>
            {p.discount&&<div style={{fontSize:9,fontWeight:700,color:"var(--coral)",marginTop:2}}>{p.discount} 할인</div>}
          </div>
        ))}
      </div>

      {/* 선물권 */}
      <div style={{padding:"0 18px 6px"}}><div style={{fontSize:14,fontWeight:700}}>🎁 선물권</div></div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,padding:"0 18px 16px"}}>
        {gifts.map((p,i)=>(
          <div key={i} style={{background:"var(--ink2)",border:"1px solid rgba(155,143,212,0.1)",borderRadius:16,padding:"14px 12px",cursor:"pointer",position:"relative",textAlign:"center"}} onClick={()=>{setGiftItem(p);setGiftPhone("");}}>
            {p.badge&&p.badge!=="없음"&&<div style={{position:"absolute",top:8,right:8,fontSize:8,fontWeight:700,padding:"2px 7px",borderRadius:8,background:"rgba(155,143,212,0.2)",color:"var(--violet)"}}>{p.badge}</div>}
            <div style={{fontSize:28,marginBottom:6}}>{p.icon}</div>
            <div style={{fontSize:12,fontWeight:700,marginBottom:3}}>{p.title}</div>
            <div style={{fontSize:9,color:"var(--mist)",marginBottom:6,lineHeight:1.4,whiteSpace:"pre-line"}}>{p.sub}</div>
            <div style={{fontSize:14,fontWeight:900,color:"var(--gold)"}}>{p.price}</div>
          </div>
        ))}
      </div>

      {/* 선물권 번호 입력 모달 */}
      {giftItem&&<div className="ov">
        <div className="md"><div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={()=>setGiftItem(null)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
          <div className="mt">🎁 선물하기</div>
          <div className="ms">{giftItem.title}</div>
          <label style={{fontSize:11,color:"var(--mist)",fontWeight:700,display:"block",marginBottom:5}}>받는 분 전화번호</label>
          <input className="inp" placeholder="010-0000-0000" value={giftPhone} onChange={e=>{const v=e.target.value.replace(/[^0-9]/g,"").slice(0,11);const f=v.length<=3?v:v.length<=7?v.slice(0,3)+"-"+v.slice(3):v.slice(0,3)+"-"+v.slice(3,7)+"-"+v.slice(7);setGiftPhone(f);}} inputMode="tel"/>
          <div style={{background:"var(--ink3)",borderRadius:12,padding:"12px",marginBottom:14,border:"1px solid rgba(255,255,255,0.06)"}}>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:12}}>
              <span style={{color:"var(--mist)"}}>선물권 금액</span>
              <span style={{fontWeight:700,color:"var(--gold)"}}>{giftItem.price}</span>
            </div>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"var(--jade)",marginTop:4}}>
              <span>10% 페이백 쿠폰</span>
              <span>+{Math.round(parseInt(giftItem.price.replace(/[^0-9]/g,""))*0.1).toLocaleString()}원</span>
            </div>
          </div>
          <button className="btn btn-p" disabled={giftPhone.replace(/[^0-9]/g,"").length<10} onClick={()=>{
            const amt=parseInt(giftItem.price.replace(/[^0-9]/g,""))||0;
            onBuy({type:"gift",title:`🎁 ${giftItem.title}`,price:giftItem.price,amount:amt,phone:giftPhone});
            setGiftItem(null);setGiftPhone("");
          }}>결제하고 선물 보내기 📱</button>
          <button className="btn btn-g" onClick={()=>{setGiftItem(null);setGiftPhone("");}}>취소</button>
        </div>
      </div>}

      {/* 안내 */}
      <div style={{padding:"0 18px"}}>
        <div style={{background:"var(--ink2)",borderRadius:14,padding:"14px",border:"1px solid rgba(255,255,255,0.06)"}}>
          <div style={{fontSize:12,fontWeight:700,color:"var(--gold)",marginBottom:8}}>💡 이용권 · 선물권 안내</div>
          <div style={{fontSize:11,color:"var(--mist)",lineHeight:1.7}}>
            · 패키지 구매 시 해당 콘텐츠 이용권 즉시 지급<br/>
            · 내정보 → 이용권에서 확인 가능<br/>
            · 유효기간 없음 (영구 소장)<br/>
            · 선물권: 구매 시 10% 페이백 쿠폰 증정<br/>
            · 선물권 코드를 카카오톡으로 전송 가능<br/>
            · 캐시로 모든 콘텐츠 자유롭게 이용
          </div>
        </div>
      </div>

      <div style={{height:70}}/>
    </div>
  );
}

// 알림 벨 — nav 우측, unread badge + 클릭 시 알림 패널
// 내정보-알림 통합 모달 (받은 알림 + 알림 설정 2개 탭)
function NotificationModal({onClose,browserPushPerm,requestBrowserPush,notiUnse,setNotiUnse,notiReward,setNotiReward,notiEvent,setNotiEvent,notiMarketing,setNotiMarketing}:any){
  const[subTab,setSubTab]=useState<"received"|"settings">("received");
  const[list,setList]=useState<ChungiNotif[]>([]);
  useEffect(()=>{
    try{setList(JSON.parse(localStorage.getItem("chungi_notifications")||"[]"));}catch{}
  },[]);
  const unreadCount=list.filter(n=>!n.read).length;
  useEffect(()=>{
    if(subTab==="received"&&unreadCount>0){
      const t=setTimeout(()=>{
        try{
          const updated=list.map(n=>({...n,read:true}));
          localStorage.setItem("chungi_notifications",JSON.stringify(updated));
          setList(updated);
        }catch{}
      },800);
      return()=>clearTimeout(t);
    }
  },[subTab]);
  function clearAll(){
    if(!confirm("모든 알림을 삭제할까요?"))return;
    try{localStorage.setItem("chungi_notifications","[]");setList([]);}catch{}
  }
  function timeAgo(ts:number){
    const d=Date.now()-ts;
    if(d<60_000)return"방금";
    if(d<3600_000)return`${Math.floor(d/60_000)}분 전`;
    if(d<86400_000)return`${Math.floor(d/3600_000)}시간 전`;
    if(d<7*86400_000)return`${Math.floor(d/86400_000)}일 전`;
    return new Date(ts).toLocaleDateString("ko-KR");
  }
  return(
    <div className="ov" onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div className="md" style={{maxHeight:"86dvh"}} onClick={e=>e.stopPropagation()}>
        <div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={onClose} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
        <div className="mt">🔔 알림</div>
        <div className="ms">받은 알림 · 알림 수신 설정</div>

        {/* 탭 스위처 */}
        <div style={{display:"flex",gap:6,marginTop:14,marginBottom:14,background:"var(--ink3)",borderRadius:10,padding:4}}>
          <button type="button" onClick={()=>setSubTab("received")} style={{flex:1,padding:"10px 0",border:"none",background:subTab==="received"?"var(--gold)":"transparent",color:subTab==="received"?"var(--ink)":"var(--mist)",borderRadius:8,fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit",position:"relative"}}>
            🔔 받은 알림
            {unreadCount>0&&subTab!=="received"&&<span style={{position:"absolute",top:6,right:10,background:"var(--blush)",color:"#fff",fontSize:9,fontWeight:900,minWidth:16,height:16,padding:"0 4px",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center"}}>{unreadCount>9?"9+":unreadCount}</span>}
          </button>
          <button type="button" onClick={()=>setSubTab("settings")} style={{flex:1,padding:"10px 0",border:"none",background:subTab==="settings"?"var(--gold)":"transparent",color:subTab==="settings"?"var(--ink)":"var(--mist)",borderRadius:8,fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit"}}>
            ⚙️ 알림 설정
          </button>
        </div>

        {/* 받은 알림 탭 */}
        {subTab==="received"&&(
          <>
            {list.length>0&&
              <div style={{display:"flex",justifyContent:"flex-end",marginBottom:8}}>
                <button onClick={clearAll} style={{background:"none",border:"none",color:"var(--mist)",fontSize:11,cursor:"pointer",fontFamily:"inherit",padding:6}}>모두 삭제</button>
              </div>
            }
            {list.length===0?(
              <div style={{textAlign:"center",padding:"40px 0",color:"var(--mist)"}}>
                <div style={{fontSize:42,marginBottom:12}}>📭</div>
                <div style={{fontSize:13,fontWeight:700,marginBottom:6}}>알림이 없어요</div>
                <div style={{fontSize:11,lineHeight:1.6}}>출석·공유 보상·이벤트 알림이<br/>여기에 모여요</div>
              </div>
            ):(
              <div style={{maxHeight:"50dvh",overflowY:"auto",margin:"0 -4px"}}>
                {list.map(n=>(
                  <div key={n.id} style={{display:"flex",alignItems:"flex-start",gap:11,padding:"12px 12px",background:n.read?"var(--ink2)":"rgba(212,175,55,0.08)",borderRadius:12,marginBottom:6,border:`1px solid ${n.read?"rgba(255,255,255,0.04)":"rgba(212,175,55,0.2)"}`}}>
                    <div style={{width:36,height:36,borderRadius:10,background:"var(--ink3)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>{n.emoji}</div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:12,fontWeight:800,color:n.read?"var(--white)":"var(--gold)"}}>{n.title}{!n.read&&<span style={{display:"inline-block",width:6,height:6,borderRadius:"50%",background:"var(--blush)",marginLeft:6,verticalAlign:"middle"}}/>}</div>
                      <div style={{fontSize:11,color:"var(--mist)",marginTop:3,lineHeight:1.5}}>{n.desc}</div>
                      <div style={{fontSize:10,color:"rgba(168,196,184,0.4)",marginTop:4}}>{timeAgo(n.date)}</div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* 알림 설정 탭 */}
        {subTab==="settings"&&(
          <>
            {/* 브라우저 알림 권한 박스 */}
            <div style={{background:"var(--ink3)",borderRadius:12,padding:"14px",marginBottom:14,border:`1px solid ${browserPushPerm==="granted"?"rgba(95,196,158,0.3)":"rgba(212,175,55,0.2)"}`}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
                <div style={{fontSize:13,fontWeight:800,color:browserPushPerm==="granted"?"var(--jade)":"var(--gold)"}}>📱 브라우저 알림</div>
                <span style={{fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:10,background:browserPushPerm==="granted"?"rgba(95,196,158,0.15)":browserPushPerm==="denied"?"rgba(220,53,69,0.15)":browserPushPerm==="unsupported"?"rgba(168,196,184,0.1)":"rgba(212,175,55,0.12)",color:browserPushPerm==="granted"?"var(--jade)":browserPushPerm==="denied"?"#DC3545":"var(--mist)"}}>{browserPushPerm==="granted"?"✓ 허용됨":browserPushPerm==="denied"?"차단됨":browserPushPerm==="unsupported"?"지원 안 함":"미설정"}</span>
              </div>
              <div style={{fontSize:11,color:"var(--mist)",marginBottom:browserPushPerm==="granted"?0:10,lineHeight:1.5}}>출석 리마인더, 새 보상, 이벤트 알림을 휴대폰 알림으로 받아요</div>
              {browserPushPerm!=="granted"&&browserPushPerm!=="unsupported"&&<button onClick={requestBrowserPush} style={{width:"100%",padding:"9px",borderRadius:10,background:"linear-gradient(135deg,var(--gold),var(--gold3))",border:"none",color:"var(--ink)",fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit"}}>알림 켜기</button>}
            </div>
            {([["운세 알림","매일 오전 8시 오늘의 운세 알림",notiUnse,setNotiUnse],["보상 알림","출석·공유 보상 알림 받기",notiReward,setNotiReward],["이벤트 알림","할인, 신규 서비스 등 이벤트 소식",notiEvent,setNotiEvent],["마케팅 알림","맞춤 추천 및 프로모션 안내",notiMarketing,setNotiMarketing]] as [string,string,boolean,(v:boolean)=>void][]).map(([label,desc,val,setter])=>(
              <div key={label} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 0",borderBottom:"1px solid rgba(255,255,255,0.04)"}}>
                <div>
                  <div style={{fontSize:13,fontWeight:700}}>{label}</div>
                  <div style={{fontSize:11,color:"var(--mist)",marginTop:2}}>{desc}</div>
                </div>
                <div onClick={()=>setter(!val)} style={{width:44,height:24,borderRadius:12,background:val?"var(--gold)":"var(--ink3)",border:`1px solid ${val?"var(--gold)":"rgba(255,255,255,0.1)"}`,cursor:"pointer",position:"relative",transition:"all .2s",flexShrink:0}}>
                  <div style={{width:18,height:18,borderRadius:9,background:val?"var(--ink)":"var(--mist)",position:"absolute",top:2,left:val?22:2,transition:"all .2s"}}/>
                </div>
              </div>
            ))}
          </>
        )}

        <button className="btn btn-g" style={{marginTop:16}} onClick={onClose}>닫기</button>
      </div>
    </div>
  );
}

function NotificationBell(){
  const[list,setList]=useState<ChungiNotif[]>([]);
  const[open,setOpen]=useState(false);
  const openedAtRef=useRef<number>(0); // overlay 방금 열림 lockout
  function load(){try{setList(JSON.parse(localStorage.getItem("chungi_notifications")||"[]"));}catch{setList([]);}}
  useEffect(()=>{
    load();
    const onUpdate=()=>load();
    window.addEventListener("chungi-notif",onUpdate);
    window.addEventListener("storage",onUpdate);
    return()=>{window.removeEventListener("chungi-notif",onUpdate);window.removeEventListener("storage",onUpdate);};
  },[]);
  const unreadCount=list.filter(n=>!n.read).length;
  function markAllRead(){
    try{
      const updated=list.map(n=>({...n,read:true}));
      localStorage.setItem("chungi_notifications",JSON.stringify(updated));
      setList(updated);
    }catch{}
  }
  function clearAll(){
    if(!confirm("모든 알림을 삭제할까요?"))return;
    try{localStorage.setItem("chungi_notifications","[]");setList([]);}catch{}
  }
  function timeAgo(ts:number){
    const d=Date.now()-ts;
    if(d<60_000)return"방금";
    if(d<3600_000)return`${Math.floor(d/60_000)}분 전`;
    if(d<86400_000)return`${Math.floor(d/3600_000)}시간 전`;
    if(d<7*86400_000)return`${Math.floor(d/86400_000)}일 전`;
    return new Date(ts).toLocaleDateString("ko-KR");
  }
  function openPanel(e:React.MouseEvent){
    e.stopPropagation();
    e.preventDefault();
    openedAtRef.current=Date.now();
    setOpen(true);
    if(unreadCount>0)setTimeout(markAllRead,800);
  }
  // overlay 배경 클릭 → 닫기 (단, 마운트 직후 300ms 이내는 무시 — 열자마자 닫히는 버그 방지)
  function handleOverlayClick(e:React.MouseEvent){
    if(e.target!==e.currentTarget)return;
    if(Date.now()-openedAtRef.current<300)return;
    setOpen(false);
  }
  return<>
    <button type="button" onClick={openPanel} style={{position:"relative",background:"none",border:"none",fontSize:20,cursor:"pointer",padding:4}}>
      🔔{unreadCount>0&&<span style={{position:"absolute",top:-2,right:-4,background:"var(--blush)",color:"#fff",fontSize:9,fontWeight:900,minWidth:16,height:16,padding:"0 4px",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center"}}>{unreadCount>9?"9+":unreadCount}</span>}
    </button>
    {open&&<div className="ov" style={{zIndex:9200}} onClick={handleOverlayClick}>
      <div className="md" style={{maxHeight:"86dvh"}} onClick={e=>e.stopPropagation()}>
        <div className="hd"/>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
          <div className="mt" style={{marginBottom:0}}>🔔 알림 {list.length>0&&<span style={{fontSize:12,color:"var(--mist)",fontWeight:400,marginLeft:6}}>({list.length})</span>}</div>
          <div style={{display:"flex",gap:6}}>
            {list.length>0&&<button onClick={clearAll} style={{background:"none",border:"none",color:"var(--mist)",fontSize:11,cursor:"pointer",fontFamily:"inherit",padding:6}}>모두 삭제</button>}
            <button onClick={()=>setOpen(false)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>
          </div>
        </div>
        {list.length===0?(
          <div style={{textAlign:"center",padding:"40px 0",color:"var(--mist)"}}>
            <div style={{fontSize:42,marginBottom:12}}>📭</div>
            <div style={{fontSize:13,fontWeight:700,marginBottom:6}}>알림이 없어요</div>
            <div style={{fontSize:11,lineHeight:1.6}}>출석·미션·공유 보상을 받으면<br/>여기에 모여요</div>
          </div>
        ):(
          <div style={{maxHeight:"60dvh",overflowY:"auto",margin:"0 -4px"}}>
            {list.map(n=>(
              <div key={n.id} style={{display:"flex",alignItems:"flex-start",gap:11,padding:"12px 12px",background:n.read?"var(--ink2)":"rgba(212,175,55,0.08)",borderRadius:12,marginBottom:6,border:`1px solid ${n.read?"rgba(255,255,255,0.04)":"rgba(212,175,55,0.2)"}`}}>
                <div style={{width:36,height:36,borderRadius:10,background:"var(--ink3)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>{n.emoji}</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:12,fontWeight:800,color:n.read?"var(--white)":"var(--gold)"}}>{n.title}{!n.read&&<span style={{display:"inline-block",width:6,height:6,borderRadius:"50%",background:"var(--blush)",marginLeft:6,verticalAlign:"middle"}}/>}</div>
                  <div style={{fontSize:11,color:"var(--mist)",marginTop:3,lineHeight:1.5}}>{n.desc}</div>
                  <div style={{fontSize:10,color:"rgba(168,196,184,0.4)",marginTop:4}}>{timeAgo(n.date)}</div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>}
  </>;
}

// PWA 홈 화면 추가 배너 — Android/Chrome은 beforeinstallprompt, iOS는 안내 모달
function PWAInstallBanner(){
  const[show,setShow]=useState(false);
  const[deferred,setDeferred]=useState<any>(null);
  const[isIOS,setIsIOS]=useState(false);
  const[showIOSGuide,setShowIOSGuide]=useState(false);
  useEffect(()=>{
    try{
      // 이미 설치되어 standalone 실행 중이면 표시 안 함
      const standalone=window.matchMedia("(display-mode: standalone)").matches||(window.navigator as any).standalone;
      if(standalone)return;
      // 디스미스 후 7일 쿨다운
      const dismissedAt=parseInt(localStorage.getItem("chungi_pwa_dismissed")||"0");
      if(dismissedAt&&Date.now()-dismissedAt<7*86400_000)return;
      // iOS 감지
      const ua=navigator.userAgent;
      const ios=/iPad|iPhone|iPod/.test(ua)&&!(window as any).MSStream;
      setIsIOS(ios);
      const onPrompt=(e:any)=>{e.preventDefault();setDeferred(e);setShow(true);};
      window.addEventListener("beforeinstallprompt",onPrompt);
      // iOS는 beforeinstallprompt 없음 → 5초 후 표시
      if(ios){const t=setTimeout(()=>setShow(true),5000);return()=>{window.removeEventListener("beforeinstallprompt",onPrompt);clearTimeout(t);};}
      return()=>window.removeEventListener("beforeinstallprompt",onPrompt);
    }catch{}
  },[]);
  function dismiss(){
    try{localStorage.setItem("chungi_pwa_dismissed",String(Date.now()));}catch{}
    setShow(false);setShowIOSGuide(false);
  }
  async function install(){
    if(isIOS){setShowIOSGuide(true);return;}
    if(!deferred)return;
    deferred.prompt();
    const result=await deferred.userChoice.catch(()=>null);
    if(result?.outcome==="accepted"){
      try{localStorage.setItem("chungi_pwa_installed","1");}catch{}
    }
    setShow(false);setDeferred(null);
  }
  if(!show)return null;
  return<>
    <div style={{position:"fixed",bottom:74,left:12,right:12,zIndex:8000,background:"linear-gradient(135deg,#1A3C32,#2d5a4e)",borderRadius:16,padding:"14px 16px",boxShadow:"0 12px 32px rgba(0,0,0,0.35)",border:"1px solid rgba(212,175,55,0.4)",display:"flex",alignItems:"center",gap:12,animation:"slideUp .4s ease-out"}}>
      <div style={{fontSize:32,flexShrink:0,filter:"drop-shadow(0 0 8px rgba(212,175,55,0.4))"}}>📱</div>
      <div style={{flex:1,minWidth:0}}>
        <div style={{fontSize:13,fontWeight:800,color:"#fff",marginBottom:2}}>천기를 홈 화면에 추가</div>
        <div style={{fontSize:11,color:"rgba(255,255,255,0.7)",lineHeight:1.4}}>홈에서 바로 실행 · 매일 출석 알림 · 오프라인 결과 확인</div>
      </div>
      <button onClick={install} style={{padding:"8px 14px",borderRadius:10,background:"linear-gradient(135deg,#D4AF37,#C9A74E)",border:"none",color:"#1A3C32",fontSize:12,fontWeight:800,cursor:"pointer",fontFamily:"inherit",flexShrink:0,boxShadow:"0 2px 8px rgba(212,175,55,0.3)"}}>설치</button>
      <button onClick={dismiss} style={{background:"none",border:"none",color:"rgba(255,255,255,0.5)",fontSize:16,cursor:"pointer",fontFamily:"inherit",padding:4,flexShrink:0}}>✕</button>
    </div>
    {showIOSGuide&&<div className="ov" style={{zIndex:9100,background:"rgba(0,0,0,0.7)"}} onClick={(e)=>{if(e.target===e.currentTarget)setShowIOSGuide(false);}}>
      <div className="md" style={{maxWidth:340,padding:0,overflow:"hidden"}}>
        <div style={{background:"#FDFCF8",padding:"24px 22px",border:"2px solid rgba(201,167,78,0.35)",borderRadius:20,color:"#1A3C32"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
            <div style={{fontSize:16,fontWeight:900}}>📱 iPhone에 설치하는 법</div>
            <button onClick={()=>setShowIOSGuide(false)} style={{background:"none",border:"none",color:"#888",fontSize:18,cursor:"pointer",fontFamily:"inherit"}}>✕</button>
          </div>
          <ol style={{fontSize:13,color:"#555",lineHeight:1.8,paddingLeft:20,margin:"12px 0"}}>
            <li>Safari 하단 <strong style={{color:"#1A3C32"}}>공유 버튼 (📤)</strong> 탭</li>
            <li>아래로 스크롤 → <strong style={{color:"#1A3C32"}}>'홈 화면에 추가'</strong> 선택</li>
            <li>오른쪽 상단 <strong style={{color:"#1A3C32"}}>'추가'</strong> 탭</li>
          </ol>
          <div style={{fontSize:11,color:"#888",background:"#F4F1E1",padding:"10px 12px",borderRadius:10,marginBottom:14,lineHeight:1.6}}>💡 설치하면 홈 화면 아이콘으로 바로 실행 가능 + 매일 출석 알림 받기</div>
          <button onClick={dismiss} style={{width:"100%",padding:"12px",borderRadius:10,background:"linear-gradient(135deg,#1A3C32,#2d5a4e)",border:"none",color:"#fff",fontSize:13,fontWeight:800,cursor:"pointer",fontFamily:"inherit"}}>알겠어요</button>
        </div>
      </div>
    </div>}
  </>;
}

// 첫 방문 온보딩 (4단계) — localStorage flag로 1회만 표시
function OnboardingOverlay({onClose}:{onClose:()=>void}){
  const[step,setStep]=useState(0);
  const STEPS=[
    {emoji:"🔮",title:"천기에 오신 걸 환영해요!",desc:"AI가 사주·관상·뇌과학·기질을 분석해\n당신의 운명을 풀어드려요.",img:"/img/gemini (24).png"},
    {emoji:"📸",title:"사진 1장이면 충분",desc:"관상·조선초상화·2세예측까지\n셀카 한 장으로 3초 분석!",img:"/img/gemini (25).png"},
    {emoji:"🎁",title:"매일 출석 보상",desc:"7·14·21·30일 출석마다\n무료 콘텐츠 + 굿즈 쿠폰 지급",img:"/img/gemini (26).png"},
    {emoji:"📋",title:"기록소에 모든 결과 저장",desc:"본 결과는 자동 저장되어\n언제든 다시 꺼내볼 수 있어요.",img:"/img/gemini (24)_2.png"},
  ];
  function done(){try{localStorage.setItem("chungi_onboard_done","1");}catch{}onClose();}
  function next(){if(step<STEPS.length-1)setStep(step+1);else done();}
  const s=STEPS[step];
  return(
    <div className="ov" style={{zIndex:9000,background:"rgba(26,60,50,0.85)",backdropFilter:"blur(8px)"}}>
      <div className="md" style={{maxWidth:340,padding:0,overflow:"hidden"}}>
        <div style={{background:"#FDFCF8",padding:"28px 22px 18px",border:"2px solid rgba(201,167,78,0.35)",borderRadius:20,color:"#1A3C32",textAlign:"center"}}>
          <div style={{display:"flex",justifyContent:"flex-end",marginBottom:-12}}>
            <button onClick={done} style={{background:"none",border:"none",color:"#888",fontSize:11,cursor:"pointer",fontFamily:"inherit",padding:4}}>건너뛰기 ✕</button>
          </div>
          <div style={{fontSize:52,marginBottom:8,filter:"drop-shadow(0 4px 12px rgba(201,167,78,0.3))"}}>{s.emoji}</div>
          {s.img&&<div style={{width:"100%",maxWidth:200,aspectRatio:"1/1",margin:"0 auto 12px",borderRadius:16,overflow:"hidden",background:"#F4F1E1",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <img src={s.img} alt={s.title} style={{width:"100%",height:"100%",objectFit:"cover"}} onError={(e:any)=>{e.target.style.display="none";}}/>
          </div>}
          <div style={{fontSize:18,fontWeight:800,color:"#1A3C32",marginBottom:10,letterSpacing:-0.3}}>{s.title}</div>
          <div style={{fontSize:13,color:"#555",lineHeight:1.6,marginBottom:18,whiteSpace:"pre-line"}}>{s.desc}</div>
          {/* 진행 도트 */}
          <div style={{display:"flex",justifyContent:"center",gap:6,marginBottom:18}}>
            {STEPS.map((_,i)=>(
              <div key={i} style={{width:i===step?22:6,height:6,borderRadius:3,background:i===step?"var(--gold)":"rgba(201,167,78,0.3)",transition:"all 0.3s"}}/>
            ))}
          </div>
          <button onClick={next} style={{width:"100%",padding:"12px",borderRadius:12,background:"linear-gradient(135deg, #C9A74E 0%, #D4AF37 100%)",border:"none",color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:"0 4px 12px rgba(201,167,78,0.35)"}}>
            {step<STEPS.length-1?"다음 →":"천기 시작하기 ✨"}
          </button>
          {step>0&&<button onClick={()=>setStep(step-1)} style={{width:"100%",marginTop:8,background:"none",border:"none",color:"#888",fontSize:11,cursor:"pointer",fontFamily:"inherit",padding:6}}>← 이전</button>}
        </div>
      </div>
    </div>
  );
}

export default function Page(){
  // v678: Hydration mismatch 차단 — React error #418 (사용자 콘솔 보고).
  // 13곳의 useState(()=>{ localStorage... }) 가 SSR에서는 throw→catch→기본값,
  // CSR에서는 실제값을 읽어 SSR/CSR 결과가 달라짐. mount 후만 렌더로 통일.
  const[_hydrated,_setHydrated]=useState(false);
  useEffect(()=>{_setHydrated(true);},[]);
  useDragScroll();
  // 자정 자동 갱신: TODAY 객체(오늘운세/이달운세/로또 등)는 모듈 로드 시점 1회 계산되므로
  // 자정 지나도 페이지 새로고침 안 하면 그대로. 1분 polling + 페이지 활성화 시 자정 감지 → 자동 reload.
  useEffect(()=>{
    let curSeed=_todaySeedNow();
    const check=()=>{
      const ns=_todaySeedNow();
      if(ns!==curSeed){
        curSeed=ns;
        // 모달 안 열려 있을 때만 reload (사용자 작업 보호)
        if(typeof document!=="undefined"&&!document.querySelector(".ov")){
          window.location.reload();
        }
      }
    };
    const intv=setInterval(check,60_000);
    const onVisible=()=>{if(document.visibilityState==="visible")check();};
    document.addEventListener("visibilitychange",onVisible);
    return()=>{clearInterval(intv);document.removeEventListener("visibilitychange",onVisible);};
  },[]);
  const[tab,setTab]=useState(()=>{try{const p=new URLSearchParams(window.location.search);const t=p.get("tab");if(t&&["home","bamboo","tickets","goods","archive","my"].includes(t))return t;}catch{}return "home";});
  // 모달 스택 — 퍼널/크로스셀에서 새 모달 열어도 닫으면 이전 모달 복원
  const[modalStack,setModalStack]=useState<any[]>([]);
  const modal=modalStack[modalStack.length-1]||null;
  // setModal(svc) = 새 콘텐츠 시작 = 스택 전체 리셋 (1개로)
  // setModal(null) = 모두 닫기
  const setModal=(s:any)=>{
    if(s===null||s===undefined){setModalStack([]);return;}
    // _inst: 매번 호출 시 새 인스턴스 마운트 강제 (재시작 버그 fix — 같은 svcId 다시 클릭 시 새 useState)
    setModalStack([{...s,_inst:s._inst||Date.now()}]);
  };
  // 퍼널·크로스셀 → 현재 위에 쌓기 (닫으면 이전 모달 복원)
  const pushModal=(s:any)=>setModalStack(prev=>[...prev,{...s,_inst:s._inst||Date.now()}]);
  const[overlayModal,setOverlayModal]=useState<any>(null); // 결과 위에 뜨는 서비스 팝업
  const[authOpen,setAuthOpen]=useState(false);
  // 첫 방문 온보딩 — localStorage flag 체크 (마운트 1회)
  const[showOnboard,setShowOnboard]=useState(false);
  const[refToast,setRefToast]=useState<string|null>(null);
  // 첫 방문 온보딩 4단계 팝업 비활성화 — greetToast(5초 토스트)로 대체 (사용자 요청)
  // 필요 시 아래 useEffect와 21324 라인의 <OnboardingOverlay/>를 복구
  // v387: 시간대별 환영 토스트 — 진입 시 1회 (세션당, 5초) 사용자 유지 결정
  const[greetToast,setGreetToast]=useState<string|null>(null);
  useEffect(()=>{
    try{
      if(sessionStorage.getItem("chungi_greeted")==="1")return;
      sessionStorage.setItem("chungi_greeted","1");
      const h=new Date().getHours();
      const greetings=
        h<5?{emoji:"🌙",msg:"늦은 시간이네요, 천천히 둘러보세요"}:
        h<10?{emoji:"☀️",msg:"좋은 아침이에요! 오늘의 운세부터 확인해볼까요?"}:
        h<14?{emoji:"🌤️",msg:"점심시간! 오늘 하루 운은 어떨지 봐볼래요?"}:
        h<18?{emoji:"🍵",msg:"여유로운 오후, 천기와 함께 해요"}:
        h<22?{emoji:"🌅",msg:"하루 마무리 — 오늘 일진 돌아보기 어때요?"}:
        {emoji:"🌌",msg:"고요한 밤, 내일을 위한 운세 살펴보세요"};
      const t=setTimeout(()=>{
        setGreetToast(`${greetings.emoji}  ${greetings.msg}`);
        setTimeout(()=>setGreetToast(null),5000);
      },1200);
      return()=>clearTimeout(t);
    }catch{}
  },[]);

  // 친구 초대 ?ref=CODE 처리 — 신규 방문자에게 INVITE1000 쿠폰 자동 지급
  useEffect(()=>{
    try{
      const p=new URLSearchParams(window.location.search);
      const ref=p.get("ref");
      if(!ref)return;
      // 이미 처리된 초대 → 무시
      if(localStorage.getItem("chungi_referred_by"))return;
      // 자기 자신 초대 방지
      if(localStorage.getItem("chungi_referral_code")===ref)return;
      localStorage.setItem("chungi_referred_by",ref);
      // v386: 친구 초대 쿠폰 지급 제거 (쿠폰 정책 폐지). 카운트만 유지 (인바이터 통계용).
      const cnt=parseInt(localStorage.getItem("chungi_invited_count")||"0")+1;
      localStorage.setItem("chungi_invited_count",String(cnt));
      addNotification({type:"invite",emoji:"🎉",title:`${ref}님의 초대로 입장!`,desc:"천기에 오신 걸 환영해요. 마음에 드는 운세부터 즐겨보세요."});
      setRefToast(`🎉 ${ref}님의 초대로 입장했어요!`);
      setTimeout(()=>setRefToast(null),5000);
      // URL에서 ref param 제거 (히스토리 깔끔)
      const url=new URL(window.location.href);url.searchParams.delete("ref");
      window.history.replaceState({},"",url.toString());
    }catch{}
  },[]);
  const[isLoggedIn,setIsLoggedIn]=useState(false);
  const[cart,setCart]=useState([]);
  const[savedPersons,setSavedPersons]=useState(()=>{
    try{const s=localStorage.getItem("chungi_persons");if(s)return JSON.parse(s);}catch{}return[];
  });
  useEffect(()=>{try{localStorage.setItem("chungi_persons",JSON.stringify(savedPersons));}catch{}},[savedPersons]);
  const[userHistory,setUserHistory]=useState(()=>{
    try{
      const s=localStorage.getItem("chungi_history");
      if(s){
        const parsed=JSON.parse(s);
        if(Array.isArray(parsed)){
          // 손상된 항목 필터 + 큰 이미지 제거 (마운트 시 안전 정리)
          // v697: 옛 데이터에 _id 없는 항목 retroactive 할당 — 즐겨찾기 모든 동일 svc 토글 버그 fix
          //   (예: 수비학 5번 했는데 _id 없으면 composite key가 동일해서 같이 별표 됨)
          let _retroSeq=0;
          return parsed.filter((h:any)=>h&&typeof h==="object").map((h:any,idx:number)=>{
            const fixed:any={...h};
            if(!fixed._id){
              // 기존 데이터엔 timestamp 없을 수 있으니 idx+seq로 안정적 unique 부여
              fixed._id=`hl_${Date.now()}_${idx}_${_retroSeq++}_${Math.random().toString(36).slice(2,6)}`;
            }
            if(fixed.resultType&&typeof fixed.resultType==="object"){
              const rt={...fixed.resultType};
              ["_imgSrc","_imgSrc1","_imgSrc2"].forEach(k=>{
                if(rt[k]&&typeof rt[k]==="string"&&rt[k].length>200000){
                  rt[k]=null;rt._imgWasLarge=true;
                }
              });
              fixed.resultType=rt;
            }
            return fixed;
          });
        }
      }
    }catch{
      // 손상된 데이터 → 정리
      try{localStorage.removeItem("chungi_history");}catch{}
    }
    return[];
  });
  // 큰 base64 이미지가 localStorage 용량(5~10MB)을 초과하면 setItem 실패 + 페이지 크래시 가능
  // 저장 시 base64를 슬림화 (썸네일 또는 제거) + 실패 시 더 줄이기
  useEffect(()=>{
    function slim(arr:any[]){
      return arr.map((h:any)=>{
        if(!h.resultType)return h;
        const rt={...h.resultType};
        ["_imgSrc","_imgSrc1","_imgSrc2"].forEach(k=>{
          // 큰 base64는 통째로 제거 (잘라내면 깨진 이미지가 됨)
          if(rt[k]&&typeof rt[k]==="string"&&rt[k].length>200000){
            rt[k]=null;rt._imgWasLarge=true;
          }
        });
        return{...h,resultType:rt};
      });
    }
    function tryStore(data:any[]){
      try{localStorage.setItem("chungi_history",JSON.stringify(data));return true;}
      catch{return false;}
    }
    // 1차: 원본 → 2차: 이미지 제거 → 3차: 절반만
    if(tryStore(userHistory))return;
    if(tryStore(slim(userHistory)))return;
    // v335: localStorage quota 초과 시 fallback도 50개로 확장 (이전 10개)
    if(tryStore(slim(userHistory.slice(0,50))))return;
    tryStore(slim(userHistory.slice(0,20)));
  },[userHistory]);
  const[userData,setUserData]=useState<any>(null);
  // 첫 렌더부터 어드민 설정 적용 — localStorage에서 즉시 hydrate. 빈 배열로 시작하면 fetch 끝날 때까지 비공개·준비중이 잠깐 보임("잔상")
  const[contentSettings,setContentSettings]=useState<any[]>(()=>{
    if(typeof window==="undefined")return [];
    try{
      const saved=localStorage.getItem('chungi_content_settings');
      if(!saved)return [];
      const parsed=JSON.parse(saved);
      // localStorage(admin 저장: id/isPublic/isPreparing/...)와 API 응답(content_id/is_public/is_preparing/...) 형식 호환
      return parsed.map((s:any)=>({
        content_id:s.content_id||s.id,
        price:s.price,
        is_public:typeof s.is_public==="boolean"?s.is_public:(s.isPublic!==false),
        is_preparing:typeof s.is_preparing==="boolean"?s.is_preparing:!!s.isPreparing,
        name:s.name,
        badge_type:s.badge_type||s.badgeType,
        original_price:s.original_price||s.originalPrice||0,
      }));
    }catch{return [];}
  });

  // 관리자 미리보기 모드
  const[isAdmin,setIsAdmin]=useState(false);
  const[adminPwOpen,setAdminPwOpen]=useState(false);
  const[logoTap,setLogoTap]=useState(0);
  const logoTapTimer=useRef<any>(null);
  useEffect(()=>{try{if(localStorage.getItem("chungi_admin")==="true")setIsAdmin(true);}catch{}},[]);
  function handleLogoTap(){
    const next=logoTap+1;
    setLogoTap(next);
    clearTimeout(logoTapTimer.current);
    if(next>=5){setAdminPwOpen(true);setLogoTap(0);return;}
    logoTapTimer.current=setTimeout(()=>setLogoTap(0),2000);
  }
  function adminLogin(pw:string){
    if(pw==="chungi2026"){localStorage.setItem("chungi_admin","true");setIsAdmin(true);setAdminPwOpen(false);}
    else{alert("비밀번호가 틀렸습니다");}
  }
  function adminLogout(){localStorage.removeItem("chungi_admin");setIsAdmin(false);}
  const cartCount=cart.reduce((s,c)=>s+c.qty,0);

  // Fetch content settings from Supabase — localStorage hydrate가 우선 (admin 토글 즉시 반영용)
  // Supabase는 새 콘텐츠 보강 + 첫 방문 hydrate에만 사용 (잔상 방지)
  useEffect(()=>{
    fetch("/api/content-settings")
      .then(r=>r.json())
      .then(d=>{
        if(!d.settings)return;
        setContentSettings(prev=>{
          if(!prev||prev.length===0)return d.settings; // 첫 방문 (localStorage 비어있음)
          // localStorage 데이터 우선, supabase는 누락된 콘텐츠만 채움
          const prevMap=new Map(prev.map((s:any)=>[s.content_id,s]));
          const merged=d.settings.map((s:any)=>prevMap.get(s.content_id)||s);
          const supaIds=new Set(d.settings.map((s:any)=>s.content_id));
          const onlyLocal=prev.filter((s:any)=>!supaIds.has(s.content_id));
          return [...merged,...onlyLocal];
        });
      })
      .catch(()=>{});
  },[]);

  // Fetch special items (패키지·선물권) from Supabase — localStorage 갱신해 HomePage/ShopPage 등이 polling으로 픽업
  useEffect(()=>{
    fetch("/api/special-items")
      .then(r=>r.json())
      .then(d=>{
        const rows=d?.items;
        if(!Array.isArray(rows)||rows.length===0)return;
        const mapped=rows.map((r:any)=>({
          id:r.id,icon:r.icon||"",title:r.title||"",sub:r.sub||"",
          price:r.price||"",originalPrice:r.original_price||"",discount:r.discount||"",
          badge:r.badge||"",imageUrl:r.image_url||"",contents:r.contents||[],
        }));
        try{localStorage.setItem('chungi_special_items_v4',JSON.stringify(mapped));}catch{}
      })
      .catch(()=>{});
  },[]);

  // Supabase 세션 감지 + 게스트 복원
  useEffect(()=>{
    // 게스트 모드 복원
    try{
      if(localStorage.getItem("chungi_guest")==="true"){
        setIsLoggedIn(true);
        setUserData({email:"guest@천기.kr",name:"게스트",avatar:null,isGuest:true});
      }
    }catch{}
    const { data: { subscription } } = onAuthStateChange((event, session)=>{
      if(session?.user) {
        setIsLoggedIn(true);
        setUserData({
          email: session.user.email,
          name: session.user.user_metadata?.full_name || session.user.user_metadata?.name || session.user.email?.split("@")[0],
          avatar: session.user.user_metadata?.avatar_url || session.user.user_metadata?.picture,
          provider: session.user.app_metadata?.provider || "unknown",
        });
        // 기록소·쿠폰·푸시 연동을 위한 user_id 저장
        try{localStorage.setItem("chungi_user_id",session.user.id);localStorage.removeItem("chungi_guest");}catch{}
        // v386: 가입 환영 쿠폰 2종 — NEWSAJU500 + NEWGOODS10 (어드민 설정과 일치)
        try{
          if(!localStorage.getItem("chungi_signup_bonus_paid")){
            const cp=JSON.parse(localStorage.getItem("chungi_coupons")||"[]");
            const ts=Date.now();
            cp.push({name:"🌱 새싹 응원 쿠폰",code:`NEWSAJU500_${ts}`,discount:"500원",discount_amount:500,discountValue:500,expires:"발급일로부터 3일",used:false,minPrice:980,target:"전 콘텐츠"});
            cp.push({name:"🛍️ 첫 굿즈 구매 10% 할인",code:`NEWGOODS10_${ts}`,discount:"10%",discount_amount:0,discountValue:0,discount_percent:10,expires:"2026-12-31",used:false,minPrice:10000,target:"굿즈샵"});
            localStorage.setItem("chungi_coupons",JSON.stringify(cp));
            localStorage.setItem("chungi_signup_bonus_paid","1");
            addNotification({type:"system",emoji:"🎁",title:"가입 환영 쿠폰 2종 도착!",desc:"🌱 새싹 응원 500원 + 🛍️ 첫 굿즈 10% 할인 쿠폰이 자동 적립됐어요"});
          }
        }catch{}
      } else if(!localStorage.getItem("chungi_guest")) {
        setIsLoggedIn(false);
        setUserData(null);
        try{localStorage.removeItem("chungi_user_id");}catch{}
      }
    });
    return ()=> subscription.unsubscribe();
  },[]);

  // 이용 기록 추가 — 큰 base64 이미지는 저장 안 함 (메모리/localStorage 초과 방지)
  const addHistory = useCallback((entry:any)=>{
    const safe={...entry};
    // v651: 즐겨찾기 개별 토글용 unique id 부여 (timestamp + random)
    if(!safe._id)safe._id=`h_${Date.now()}_${Math.random().toString(36).slice(2,8)}`;
    if(safe.resultType&&typeof safe.resultType==="object"){
      const rt={...safe.resultType};
      ["_imgSrc","_imgSrc1","_imgSrc2"].forEach(k=>{
        if(rt[k]&&typeof rt[k]==="string"&&rt[k].length>200000){
          rt[k]=null;rt._imgWasLarge=true;
        }
      });
      safe.resultType=rt;
    }
    // v335: 20회 제한 → 1000회로 확장 (사용자 요청 — 과거 기록 보존)
    setUserHistory((prev:any[])=>[safe,...prev].slice(0,1000));
    // 로그인 시 서버에도 저장 (기록소 컬렉션 영구 보존)
    try{
      const userId=typeof window!=="undefined"?localStorage.getItem("chungi_user_id"):null;
      if(userId){
        fetch("/api/history",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({
          user_id:userId,icon:safe.icon,name:safe.name,svc_id:safe.svcId,
          person:safe.person,person2:safe.person2,person3:safe.person3,
          date:safe.date,result:safe.result,result_type:safe.resultType,ctx:safe.ctx,
        })}).catch(()=>{});
      }
    }catch{}
  },[]);

  // 로그인 시 서버에서 기록 불러오기 (기록소 컬렉션 동기화)
  useEffect(()=>{
    if(!isLoggedIn)return;
    try{
      const userId=localStorage.getItem("chungi_user_id");
      if(!userId)return;
      fetch(`/api/history?user_id=${encodeURIComponent(userId)}&limit=1000`)
        .then(r=>r.json()).then(j=>{
          if(j?.history&&Array.isArray(j.history)&&j.history.length>0){
            // 서버 기록을 클라이언트 포맷으로 변환 + 로컬과 merge (중복 제거)
            const serverEntries=j.history.map((h:any)=>({
              icon:h.icon,name:h.name,svcId:h.svc_id,person:h.person,person2:h.person2,person3:h.person3,
              date:h.date,result:h.result,resultType:h.result_type,ctx:h.ctx,_serverId:h.id,
            }));
            setUserHistory((prev:any[])=>{
              const merged=[...serverEntries];
              prev.forEach(p=>{
                const dup=merged.find(m=>m.svcId===p.svcId&&m.date===p.date&&m.person===p.person);
                if(!dup)merged.push(p);
              });
              return merged.slice(0,1000);
            });
          }
        }).catch(()=>{});
    }catch{}
  },[isLoggedIn]);

  function goShop(){setTab("goods");}

  // ━━━ 공유 결제 모달 (이용권탭 + 내정보 공용) ━━━
  const [globalPayItem,setGlobalPayItem]=useState<any>(null);
  const [globalPayStep,setGlobalPayStep]=useState<"confirm"|"paying"|"done">("confirm");
  const [globalPayMethod,setGlobalPayMethod]=useState("kakao");
  const [globalUseCash,setGlobalUseCash]=useState(false);
  const [globalCashAmt,setGlobalCashAmt]=useState(0);
  const [globalCashBal,setGlobalCashBal]=useState(0);
  function openGlobalPay(item:any){
    setGlobalPayItem(item);setGlobalPayStep("confirm");setGlobalPayMethod("kakao");
    setGlobalUseCash(false);setGlobalCashAmt(0);
    setGlobalCashBal(parseInt(localStorage.getItem("chungi_cash_balance")||"0"));
  }

  function getContentSetting(contentId:string){
    return contentSettings.find(s=>s.content_id===contentId)||null;
  }

  // 인물 선택이 필요 없는 콘텐츠
  const NO_PERSON_SELECT=["ddi","zodiac","blood","daily_quote","lotto","ytype_intro","synthesis","gwansang_zal","tarot_yesno","dream"];
  // 2명 선택이 필요한 콘텐츠
  const TWO_PERSON_SELECT=["gwansang_compat","biz_gwansang","love","tarot_love","bff_compat","fan_compat","enemy_compat","pet_owner_compat","baby_naming","parent_child_compat"];
  const THREE_PERSON_SELECT=["baby_face"]; // 2세 얼굴만: 아기(태명) → 부모1 → 부모2. parent_child_compat은 자녀↔부모 2명 궁합 (TWO_PERSON_SELECT 처리)
  const[selectedPerson3,setSelectedPerson3]=useState<any>(null);
  const[pendingSvc,setPendingSvc]=useState<any>(null);
  const[selectedPerson,setSelectedPerson]=useState<any>(null);
  const[selectedPerson2,setSelectedPerson2]=useState<any>(null);
  const[personStep,setPersonStep]=useState<1|2|3>(1); // 1명째 or 2명째 or 3명째 선택

  function handleSvc(svc){
    // ⚠️ 광고퍼널/추천에서 svc 가격·아이콘·이름이 ""인 경우 SVC_CATS에서 lookup → fallback
    // (안 그러면 "커플 궁합 보기 () →" 처럼 가격 빈 채로 자체 모달 진입)
    if(svc&&svc.id&&(!svc.price||!svc.icon||!svc.name)){
      const _meta=SVC_CATS.flatMap((c:any)=>c.items||[]).find((i:any)=>i.id===svc.id);
      if(_meta){
        svc={...svc,
          icon:svc.icon||_meta.icon||"",
          name:svc.name||_meta.name||"",
          desc:svc.desc||_meta.desc||"",
          price:svc.price||_meta.price||"",
        };
      }
    }
    const setting=getContentSetting(svc.id);
    // 광고퍼널/추천 카드에서 들어온 경우(_fromAd) — 어드민은 미리보기 가능, 일반 사용자는 ComingModal/alert로 차단
    if(svc._fromAd&&!isAdmin){
      if(setting?.is_preparing){setModal({...svc,_coming:true});return;}
      if(setting&&!setting.is_public){alert(`📍 ${svc.name}${_josa(svc.name,"은는")} 현재 비공개 상태예요.`);return;}
    }
    // v300: 좋은 날 확인하기(taegil_free) 1일 3회 제한 — 메인박스 클릭 시점에 차단 (사전질문 다 끝나고 알림 뜨는 황당함 방지)
    if(svc.id==="taegil_free"&&!svc._fromAd){
      try{
        const ck=`chungi_daily_taegil_${new Date().toISOString().slice(0,10)}_count`;
        const cnt=parseInt(localStorage.getItem(ck)||"0");
        if(cnt>=3){alert("오늘 좋은 날 확인하기는 3회까지 무료예요!\n내일 다시 이용해주세요.\n\n📋 오늘 본 결과는 기록소에서 다시 확인할 수 있어요.");return;}
      }catch{}
    }
    // v297/v299: 1일 1회 콘텐츠 — 오늘 이미 봤으면 인트로/인물/사전질문 스킵하고 저장된 결과로 직행
    // (celeb_compat은 resultType 미저장이라 history 엔트리만 있으면 OK, 인물 birth는 savedPersons에서 조회)
    if(svc.id==="celeb_compat"&&!svc._fromAd){
      try{
        const todayStr=new Date().toLocaleDateString("ko-KR");
        const ck=`chungi_daily_celeb_${new Date().toISOString().slice(0,10)}_count`;
        const cnt=parseInt(localStorage.getItem(ck)||"0");
        // v312: 오늘 history entry 있거나 cnt>=1이면 무조건 결과 직행 (휘리릭 안 뜸)
        let past=(userHistory||[]).find((h:any)=>h.svcId==="celeb_compat"&&h.date===todayStr);
        if(past||cnt>=1){
          if(!past)past=(userHistory||[]).find((h:any)=>h.svcId==="celeb_compat");
          const fallbackPerson=(savedPersons||[])[0];
          const targetName=past?.person||fallbackPerson?.name;
          if(targetName){
            const personObj=(savedPersons||[]).find((p:any)=>p.name===targetName)||{name:targetName};
            setModal({...svc,_preloadResult:{...(past?.resultType||{}),_name:targetName,_ctx:past?.ctx||{},preQ:past?.preQuestions||{}},_preloadPerson:{name:targetName,birth:personObj.birth||past?.ctx?.birth}});
            return;
          }
        }
      }catch{}
    }
    // v310: 로또 1일 1회 — 오늘 결과 있으면 인물선택 스킵하고 결과 직행
    if(svc.id==="lotto"&&!svc._fromAd){
      try{
        const today=new Date().toISOString().slice(0,10);
        let pastResult=null,pastPerson=null;
        for(let i=0;i<localStorage.length;i++){
          const k=localStorage.key(i);
          if(k&&k.startsWith('chungi_daily_lotto_')&&k.endsWith('_'+today)){
            pastPerson=k.slice('chungi_daily_lotto_'.length,-('_'+today).length);
            const v=localStorage.getItem(k);
            if(v){pastResult=JSON.parse(v);break;}
          }
        }
        if(pastResult&&pastPerson){
          const personObj=(savedPersons||[]).find((p:any)=>p.name===pastPerson)||{name:pastPerson};
          setModal({...svc,_preloadResult:pastResult,_preloadPerson:personObj});
          return;
        }
      }catch{}
    }
    // v310: 이달의 운세 1회/월 — 이번 달 결과 있으면 인물선택 스킵
    if(svc.id==="monthly_unse"&&!svc._fromAd){
      try{
        const yr=new Date().getFullYear();const mo=new Date().getMonth()+1;
        const suffix=`_${yr}_${mo}`;
        let pastPreQ=null,pastPerson=null;
        for(let i=0;i<localStorage.length;i++){
          const k=localStorage.key(i);
          if(k&&k.startsWith('chungi_monthly_')&&k.endsWith(suffix)){
            pastPerson=k.slice('chungi_monthly_'.length,-suffix.length);
            const v=localStorage.getItem(k);
            if(v){pastPreQ=JSON.parse(v);break;}
          }
        }
        if(pastPreQ&&pastPerson){
          const personObj=(savedPersons||[]).find((p:any)=>p.name===pastPerson)||{name:pastPerson};
          setModal({...svc,_preloadResult:{preQ:pastPreQ,_name:pastPerson},_preloadPerson:personObj});
          return;
        }
      }catch{}
    }
    // 어드민 미리보기 진입 헬퍼 — 일반 흐름과 동일하게 _needPerson/_hasOwnIntro 셋팅 (인트로·인물선택 스킵 방지)
    const _HAS_OWN_INTRO_LIST=["gwansang_full","gwansang_zal","pawdong","joseon_portrait","baby_gwansang","baby_face","today_tarot","tarot_yesno","gijildo","numerology","psych","today_unse","monthly_unse","lotto","daily_quote","dream","tarot_money","tarot_love","tarot_health","tarot_career","tarot_life","gwansang_compat","parent_child_compat","bff_compat","fan_compat","biz_gwansang","enemy_compat","pet_owner_compat","palmistry","footreading","mole","eye_mole","doljabi_sim","celeb_compat","love","ddi","zodiac","blood","dog_gwansang","cat_gwansang","saju","saju_monthly","tojeong","newyear","daeun","yearly_unse","past_life","namereading","baby_naming","lucky_number","lucky_wallpaper","taegil","taegil_free","synthesis","ytype_intro"];
    const adminPreview=()=>{
      if(NO_PERSON_SELECT.includes(svc.id)){setModal(svc);}
      else if(_HAS_OWN_INTRO_LIST.includes(svc.id)){setModal({...svc,_needPerson:true,_hasOwnIntro:true});}
      else{setModal({...svc,_needPerson:true});}
    };
    if(setting?.is_preparing){
      if(isAdmin){adminPreview();return;}
      setModal({...svc,_coming:true});return;
    }
    if(setting&&!setting.is_public){
      if(isAdmin){adminPreview();return;}
      return;
    }
    if(svc.coming){
      if(isAdmin){adminPreview();return;}
      setModal({...svc,_coming:true});return;
    }
    // 로그인/비로그인 토글 콘텐츠 (공통 결과 제공 가능)
    const LOGIN_TOGGLE_SVC=["today_unse","monthly_unse","lotto"];
    const ALWAYS_OPEN_SVC=["daily_quote"]; // 비로그인도 바로 열림
    // 비로그인 → 토글 콘텐츠는 선택지 팝업, 항상 열림은 패스, 나머지는 로그인 필수
    if(!isLoggedIn&&!LOGIN_TOGGLE_SVC.includes(svc.id)&&!ALWAYS_OPEN_SVC.includes(svc.id)){setAuthOpen(true);return;}
    if(!isLoggedIn&&LOGIN_TOGGLE_SVC.includes(svc.id)){setModal({...svc,_loginToggle:true});return;}
    // 모든 콘텐츠: 먼저 모달(콘텐츠 설명)을 열기
    // 인물 선택이 필요하면 모달 안에서 "시작하기" 후 인물 선택
    setSelectedPerson(null);setSelectedPerson2(null);setSelectedPerson3(null);setPersonStep(1);
    // 자체 intro가 있는 전용 모달은 intro 먼저 → intro 안에서 인물 선택 유도
    const HAS_OWN_INTRO_SVC=["gwansang_full","gwansang_zal","pawdong","joseon_portrait","baby_gwansang","baby_face","today_tarot","tarot_yesno","gijildo","numerology","psych","today_unse","monthly_unse","lotto","daily_quote","dream","tarot_money","tarot_love","tarot_health","tarot_career","tarot_life","gwansang_compat","parent_child_compat","bff_compat","fan_compat","biz_gwansang","enemy_compat","pet_owner_compat","palmistry","footreading","mole","eye_mole","doljabi_sim","celeb_compat","love","ddi","zodiac","blood","dog_gwansang","cat_gwansang","saju","saju_monthly","tojeong","newyear","daeun","yearly_unse","past_life","namereading","baby_naming","lucky_number","lucky_wallpaper","taegil","taegil_free","synthesis","ytype_intro"];
    if(NO_PERSON_SELECT.includes(svc.id)){
      setModal(svc);
    } else if(HAS_OWN_INTRO_SVC.includes(svc.id)){
      // 자체 intro 모달 먼저 열고, intro에서 "시작" 누르면 인물 선택
      setModal({...svc,_needPerson:true,_hasOwnIntro:true});
    } else {
      // 공통 info 화면 → 시작하기 → 인물 선택
      setModal({...svc,_needPerson:true});
    }
  }
  function onPersonSelected(person:any){
    const isTwoPerson=pendingSvc&&TWO_PERSON_SELECT.includes(pendingSvc.id);
    const isThreePerson=pendingSvc&&THREE_PERSON_SELECT.includes(pendingSvc.id);
    // 2명 선택
    if(isTwoPerson&&personStep===1){setSelectedPerson(person);setPersonStep(2);return;}
    if(isTwoPerson&&personStep===2){setSelectedPerson2(person);if(pendingSvc){setModal(pendingSvc);setPendingSvc(null);}setPersonStep(1);return;}
    // 3명 선택 (아기→부모1→부모2) — 자동지정 없이 유저가 직접 고르도록
    if(isThreePerson&&personStep===1){setSelectedPerson(person);setPersonStep(2);return;}
    if(isThreePerson&&personStep===2){setSelectedPerson2(person);setPersonStep(3);return;}
    if(isThreePerson&&personStep===3){setSelectedPerson3(person);if(pendingSvc){setModal(pendingSvc);setPendingSvc(null);}setPersonStep(1);return;}
    // 1명 콘텐츠
    setSelectedPerson(person);
    if(pendingSvc){
      // 같은 모달이 이미 마운트돼있으면 _inst 보존 → React 리마운트 방지 (celeb_compat 휘리릭 fix)
      setModalStack(prev=>{
        const top=prev[prev.length-1];
        if(top&&top.id===pendingSvc.id){
          return [...prev.slice(0,-1),{...pendingSvc,_inst:top._inst}];
        }
        return [{...pendingSvc,_inst:Date.now()}];
      });
      setPendingSvc(null);
    }
    setPersonStep(1);
  }

  // 항상 top만 pop (모달의 X 버튼은 자기 자신을 닫음)
  const closeModalFn=()=>{
    setModalStack(prev=>{
      const popped=prev[prev.length-1];
      const next=prev.slice(0,-1);
      // 광고퍼널로 push된 모달이면 닫을 때 인물 스냅샷 복원
      if(popped&&popped._savedPerson!==undefined){
        setSelectedPerson(popped._savedPerson);
        setSelectedPerson2(popped._savedPerson2);
        setSelectedPerson3(popped._savedPerson3);
      }
      if(next.length===0){
        setOverlayModal(null);setSelectedPerson(null);setSelectedPerson2(null);setSelectedPerson3(null);
      }
      return next;
    });
  };

  function renderModalFor(m:any){
    if(!m) return null;
    const modal=m; // 기존 코드 호환
    if(modal._coming) return <ComingModal svc={modal} onClose={closeModalFn} userData={userData} isLoggedIn={isLoggedIn}/>;
    const closeModal=closeModalFn;

    // 자체 intro가 있는 전용 모달은 _needPerson 스킵 → 바로 인물 선택
    const HAS_OWN_INTRO=["gwansang_full","gwansang_zal","pawdong","joseon_portrait","baby_gwansang","baby_face","dog_gwansang","cat_gwansang","numerology","gijildo","today_tarot","tarot_yesno","psych","today_unse","monthly_unse","lotto","daily_quote","dream","tarot_money","tarot_love","tarot_health","tarot_career","tarot_life","saju","saju_monthly","tojeong","newyear","past_life","daeun","yearly_unse","gwansang_compat","parent_child_compat","bff_compat","fan_compat","biz_gwansang","enemy_compat","pet_owner_compat","palmistry","footreading","mole","eye_mole","doljabi_sim","celeb_compat","love","ddi","zodiac","blood","synthesis","ytype_intro","taegil","taegil_free","namereading","baby_naming","lucky_number","lucky_wallpaper"];
    // 비로그인 토글 팝업 (운세/로또 3종)
    if(modal._loginToggle){
      return <div className="ov">
        <div className="md"><div className="hd"/>
          <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}>
            <button onClick={closeModal} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>
          </div>
          <div className="mt">{modal.icon} {modal.name}</div>
          <div className="ms">{modal.desc||""}</div>
          <div style={{background:"linear-gradient(135deg,rgba(212,175,55,0.1),rgba(155,143,212,0.07))",border:"1px solid rgba(212,175,55,0.2)",borderRadius:14,padding:"16px",marginBottom:14}}>
            <div style={{fontSize:12,fontWeight:700,color:"var(--gold)",marginBottom:6}}>✦ 로그인하면 내 사주 맞춤!</div>
            <div style={{fontSize:11,color:"var(--mist)",lineHeight:1.7}}>로그인하면 생년월일 기반 <strong style={{color:"var(--white)"}}>개인 맞춤 결과</strong> + 기록소 저장<br/>비로그인은 공통 결과만 제공돼요</div>
          </div>
          <button className="btn btn-p" style={{marginBottom:8}} onClick={()=>{closeModal();setAuthOpen(true);}}>🔐 로그인하고 맞춤 결과 보기</button>
          <button style={{display:"block",width:"100%",padding:14,background:"var(--ink3)",border:"1px solid rgba(168,196,184,0.15)",borderRadius:18,fontSize:13,fontWeight:700,color:"var(--mist)",cursor:"pointer",fontFamily:"inherit",marginBottom:8}} onClick={()=>{
            const clean={...modal};delete clean._loginToggle;setModal(clean);
          }}>🌐 공통 결과 먼저 보기 (저장 안 됨)</button>
          <button className="btn btn-g" onClick={closeModal}>닫기</button>
        </div>
      </div>;
    }
    // 인물 선택 필요한 콘텐츠 — 각 콘텐츠의 rich intro(천기 white card 스타일)로 표시
    // 제네릭 fallback 제거 — HAS_OWN_INTRO/specialMap/SvcModal 내 introMap 경로가 각자 알아서 rich intro 렌더링
    // (이 분기는 _needPerson 초기 상태에서 리치 인트로가 뜨게 하는 catch-all)
    if(modal._needPerson&&!selectedPerson&&!HAS_OWN_INTRO.includes(modal.id)){
      const isPhoto=["gwansang_full","palmistry","footreading","joseon_portrait","gwansang_compat","biz_gwansang","baby_face","baby_gwansang","eye_mole","mole","parent_child_compat","bff_compat","fan_compat","enemy_compat"].includes(modal.id);
      // 리치 인트로 — 천기 표준 white card 스타일
      return <div className="ov">
        <div className="md"><div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={closeModal} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
          <div style={{background:"#FDFCF8",borderRadius:16,padding:"10px 20px 32px",border:"2px solid rgba(201,167,78,0.35)",boxShadow:"0 8px 28px rgba(0,0,0,0.12)",color:"#1A3C32",marginBottom:12,textAlign:"center"}}>
            <div style={{fontSize:9,color:"#aaa",fontWeight:600,letterSpacing:0.3,paddingBottom:10,marginBottom:14,marginLeft:-16,marginRight:-16,paddingLeft:16,paddingRight:16,borderBottom:"1px solid #f0f0f0"}}>🔮 천기(天機) 오리지널</div>
            <div style={{fontSize:54,marginBottom:6,filter:"drop-shadow(0 0 12px rgba(201,167,78,0.4))"}}>{modal.icon}</div>
            <div style={{fontFamily:"'Noto Serif KR','Batang','Apple Color Emoji','Segoe UI Emoji','Noto Color Emoji',serif",fontSize:20,fontWeight:900,color:"#1A1A1A",marginBottom:6,lineHeight:1.4}}>{modal.name}</div>
            {modal.desc&&<div style={{fontSize:12,color:"#3D6B5A",lineHeight:1.7,marginBottom:14,fontWeight:500}}>{modal.desc}</div>}
            <div style={{background:"#fffbe9",borderRadius:12,padding:"10px 14px",marginBottom:14,border:"1px solid rgba(201,167,78,0.3)"}}>
              <div style={{fontSize:11,color:"#7A5C00",lineHeight:1.7}}>{isPhoto?"📸 사진 한 장으로 AI가 정밀 분석해드려요":"📝 생년월일로 AI가 정밀 분석해드려요"}</div>
            </div>
            {modal.price&&modal.price!=="무료"?<div style={{display:"inline-block",background:"linear-gradient(135deg,#fffbe9,#fff5d6)",border:"1px solid rgba(201,167,78,0.4)",borderRadius:20,padding:"6px 18px",marginBottom:14}}><span style={{fontSize:14,fontWeight:900,color:"#B8942E"}}>{modal.price}</span></div>:modal.free||modal.price==="무료"?<div style={{display:"inline-block",background:"linear-gradient(135deg,#fffbe9,#fff5d6)",border:"1px solid rgba(201,167,78,0.4)",borderRadius:20,padding:"6px 18px",marginBottom:14}}><span style={{fontSize:14,fontWeight:900,color:"#5FC49E"}}>무료</span></div>:null}
            <button onClick={()=>{
              const clean={...modal};delete clean._needPerson;
              closeModal();
              if(TWO_PERSON_SELECT.includes(modal.id)||THREE_PERSON_SELECT.includes(modal.id)){setPersonStep(1);}
              setPendingSvc(clean);
            }} className="btn btn-p">{modal.name||"콘텐츠"} 보기 ({modal.price||"무료"}) →</button>
            <div style={{display:"flex",justifyContent:"space-between",marginTop:14,fontSize:9,color:"#aaa",fontWeight:600,letterSpacing:0.3}}>
              <span>#천기 #{(modal.name||"").replace(/\s/g,"")}</span>
              <span style={{fontWeight:600}}>🌐 천기.kr</span>
            </div>
          </div>
          <button className="btn btn-g" onClick={closeModal}>닫기</button>
        </div>
      </div>;
    }
    const requestPerson=(svc:any)=>{
      // v308: _inst 삭제 — 인물 선택 후 모달이 새 인스턴스로 재마운트되어 savedResult/savedPreQ 재평가됨
      const clean={...svc};delete clean._needPerson;delete clean._coming;delete clean._inst;
      if(TWO_PERSON_SELECT.includes(svc.id)||THREE_PERSON_SELECT.includes(svc.id)){setPersonStep(1);setSelectedPerson(null);setSelectedPerson2(null);setSelectedPerson3(null);}
      else{setSelectedPerson(null);setSelectedPerson2(null);setSelectedPerson3(null);}
      setPendingSvc(clean);
    };
    const onOpenService=(svcId:string,svcName:string,svcIcon:string,svcPrice:string)=>{
      // 광고퍼널 가시성 가드 — 비공개·준비중 콘텐츠는 ComingModal로 진입 차단 (무한 결제루프 방지)
      const setting=getContentSetting(svcId);
      if(setting?.is_preparing){
        if(!isAdmin){pushModal({id:svcId,icon:svcIcon,name:svcName,desc:"",price:svcPrice,coming:false,_coming:true});return;}
        // admin은 미리보기 가능
      }
      if(setting&&!setting.is_public){
        if(!isAdmin){alert(`📍 ${svcName}${_josa(svcName,"은는")} 현재 비공개 상태예요.`);return;}
      }
      const HAS_OWN=["gwansang_full","pawdong","joseon_portrait","baby_gwansang","baby_face","dog_gwansang","cat_gwansang","numerology","gijildo","today_tarot","tarot_yesno","psych","today_unse","monthly_unse","lotto","daily_quote","dream","tarot_money","tarot_love","tarot_health","tarot_career","tarot_life","saju","past_life","palmistry","footreading","mole","eye_mole","namereading","love","ddi","zodiac","blood","celeb_compat","gwansang_zal","synthesis","guardian","ytype_intro","saju_monthly","tojeong","newyear","daeun","yearly_unse","gwansang_compat","parent_child_compat","bff_compat","fan_compat","biz_gwansang","enemy_compat","pet_owner_compat","doljabi_sim","name_reading","baby_naming","lucky_number","lucky_wallpaper","taegil","taegil_free"];
      // ⚠️ 광고퍼널에서 svcPrice/svcIcon/svcName을 ""로 넘기는 경우 SVC_CATS에서 lookup해 fallback
      // (안 그러면 "커플 궁합 보기 () →" 처럼 가격 빈 채 표시되는 버그)
      const _meta=SVC_CATS.flatMap((c:any)=>c.items||[]).find((i:any)=>i.id===svcId);
      const svc={
        id:svcId,
        icon:svcIcon||_meta?.icon||"",
        name:svcName||_meta?.name||"",
        desc:_meta?.desc||"",
        price:svcPrice||_meta?.price||"",
        coming:false
      };
      // 광고퍼널로 새 콘텐츠 열기 → 인물 스냅샷 후 초기화 → 새 모달은 자체 인트로부터 시작
      // (닫으면 closeModalFn에서 스냅샷 복원하여 부모 모달이 정상 표시됨)
      if(HAS_OWN.includes(svcId)){
        const _savedPerson=selectedPerson;
        const _savedPerson2=selectedPerson2;
        const _savedPerson3=selectedPerson3;
        setSelectedPerson(null);setSelectedPerson2(null);setSelectedPerson3(null);
        // _forceIntro: 광고퍼널에서 push된 모달은 무조건 인트로/설명팝업부터 시작
        pushModal({...svc,_hasOwnIntro:true,_needPerson:true,_forceIntro:true,_savedPerson,_savedPerson2,_savedPerson3});
      }else{
        setOverlayModal(svc);
      }
    };
    // v297: 1일 1회 콘텐츠가 _preloadResult 갖고 들어오면 인트로/인물선택 스킵하고 결과창으로 직행
    const _effectiveSelectedPerson=modal._preloadPerson?modal._preloadPerson:(modal._forceIntro?null:selectedPerson);
    const props={onClose:closeModal,cart,setCart,onGoShop:goShop,addHistory,isLoggedIn,onLoginRequest:()=>{setModal(null);setAuthOpen(true);},selectedPerson:_effectiveSelectedPerson,selectedPerson2:modal._forceIntro?null:selectedPerson2,selectedPerson3:modal._forceIntro?null:selectedPerson3,onRequestPerson:requestPerson,onOpenService,forceIntro:!!modal._forceIntro,svc:modal,preloadResult:modal._preloadResult};
    const specialMap={
      today_unse:   <TodayUnseModal {...props}/>,
      monthly_unse: <MonthlyUnseModal {...props}/>,
      daily_quote:  <DailyQuoteModal onClose={closeModal} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} addHistory={addHistory} cart={cart} setCart={setCart} onGoShop={goShop} onOpenService={onOpenService}/>,
      love:         <LoveCompatModal svc={modal} {...props}/>,
      gwansang_full: <FaceReadingModal {...props}/>,
      baby_gwansang: <BabyGwansangModal {...props}/>,
      baby_face: <BabyFaceModal {...props}/>,
      gwansang_zal: <GwansangZalModal {...props} savedPersons={savedPersons} setSavedPersons={setSavedPersons}/>,
      numerology:   <NumerologyModal {...props}/>,
      dog_gwansang: <PetGwansangModal species="dog" {...props}/>,
      cat_gwansang: <PetGwansangModal species="cat" {...props}/>,
      joseon_portrait: <JoseonPortraitModal {...props}/>,
      mole:         <MoleModal svcId="mole"     onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} addHistory={addHistory} isLoggedIn={isLoggedIn} selectedPerson={modal._forceIntro?null:selectedPerson} onOpenService={onOpenService} forceIntro={!!modal._forceIntro} onRequestPerson={requestPerson}/>,
      eye_mole:     <MoleModal svcId="eye_mole" onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} addHistory={addHistory} isLoggedIn={isLoggedIn} selectedPerson={modal._forceIntro?null:selectedPerson} onOpenService={onOpenService} forceIntro={!!modal._forceIntro} onRequestPerson={requestPerson}/>,
      pawdong:      <PawdongModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} addHistory={addHistory} isLoggedIn={isLoggedIn} selectedPerson={modal._forceIntro?null:selectedPerson} onOpenService={onOpenService} onRequestPerson={requestPerson} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} forceIntro={!!modal._forceIntro}/>,
      ytype_intro:  <YtypeIntroModal onClose={closeModal} onBuy={()=>setModal({id:"synthesis",icon:"🔍",name:"나의 천기 리포트",desc:"결제할수록 풍부해지는 내 운명 종합서",price:"무료",coming:false})}/>,
      synthesis:    <SynthesisModal {...props} userHistory={userHistory} savedPersons={savedPersons}/>,
      ddi:          <DdiModal {...props}/>,
      zodiac:       <ZodiacModal {...props}/>,
      blood:        <BloodModal {...props}/>,
      today_tarot:  <TodayTarotModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} selectedPerson={selectedPerson} onOpenService={onOpenService} addHistory={addHistory} onRequestPerson={requestPerson}/>,
      dream:        <DreamModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} selectedPerson={selectedPerson} onRequestPerson={requestPerson} onOpenService={onOpenService} addHistory={addHistory} dreamPendingMode={modal._dreamPendingMode||null}/>,
      tarot_yesno:  <YesNoTarotModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} onOpenService={onOpenService} addHistory={addHistory} selectedPerson={selectedPerson} onRequestPerson={requestPerson}/>,
      saju:         <SajuModal {...props}/>,
      tarot_money:  <TarotSpreadModal svcId="tarot_money"  {...props}/>,
      tarot_love:   <TarotSpreadModal svcId="tarot_love"   {...props}/>,
      tarot_health: <TarotSpreadModal svcId="tarot_health" {...props}/>,
      tarot_career: <TarotSpreadModal svcId="tarot_career" {...props}/>,
      tarot_life:   <TarotSpreadModal svcId="tarot_life"   {...props}/>,
      daeun:        <DaeunRichModal {...props} helpers={{PayDonePopup,PayStepComp,ResultActions,GoodsRecSection,sajuPillars:selectedPerson?.birth?_sajuPillars(selectedPerson.birth,selectedPerson.time):null,pickCelebs:_pickCelebs}} pushModal={pushModal}/>,
      yearly_unse:  <YearlyRichModal {...props} helpers={{PayDonePopup,PayStepComp,ResultActions,GoodsRecSection,sajuPillars:selectedPerson?.birth?_sajuPillars(selectedPerson.birth,selectedPerson.time):null,pickCelebs:_pickCelebs}}/>,
      saju_monthly: <MonthlyModalRich {...props} helpers={{PayDonePopup,PayStepComp,ResultActions,GoodsRecSection,sajuPillars:selectedPerson?.birth?_sajuPillars(selectedPerson.birth,selectedPerson.time):null,pickCelebs:_pickCelebs}}/>,
      newyear:      <NewYearModal {...props} helpers={{PayDonePopup,PayStepComp,ResultActions,GoodsRecSection,sajuPillars:selectedPerson?.birth?_sajuPillars(selectedPerson.birth,selectedPerson.time):null,pickCelebs:_pickCelebs}}/>,
      tojeong:      <TojeongModal {...props} helpers={{PayDonePopup,PayStepComp,ResultActions,GoodsRecSection,sajuPillars:selectedPerson?.birth?_sajuPillars(selectedPerson.birth,selectedPerson.time):null,pickCelebs:_pickCelebs}}/>,
      past_life:    <PastLifeModalRich {...props} selectedPerson={selectedPerson} helpers={{PayDonePopup,PayStepComp,ResultActions,GoodsRecSection,sajuPillars:selectedPerson?.birth?_sajuPillars(selectedPerson.birth,selectedPerson.time):null,pickCelebs:_pickCelebs}} pushModal={pushModal}/>,
      // v578: past_life_full registry 제거 — 결과 카드 안 inline 토글로 통일
      taegil_free:  <TaegilModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} addHistory={addHistory} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} selectedPerson={selectedPerson} onRequestPerson={requestPerson} freeOnly onUpgrade={()=>{setModal({id:"taegil",icon:"📅",name:"좋은 날 찾기",desc:"AI 추천 최적의 날",price:"980원",coming:false});}} onOpenService={onOpenService}/>,
      taegil:       <TaegilModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} addHistory={addHistory} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} selectedPerson={selectedPerson} onRequestPerson={requestPerson} onOpenService={onOpenService}/>,
      lotto:        <LottoModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} onOpenService={onOpenService} selectedPerson={modal._preloadPerson||selectedPerson} addHistory={addHistory} onRequestPerson={requestPerson} preloadResult={modal._preloadResult}/>,
      doljabi_sim:  <DoljabiSimModal onClose={closeModal} cart={cart} setCart={setCart} onGoShop={goShop} addHistory={addHistory} isLoggedIn={isLoggedIn} onLoginRequest={()=>{setModal(null);setAuthOpen(true);}} onOpenService={onOpenService} selectedPerson={selectedPerson} onRequestPerson={requestPerson}/>,
      gijildo:      <GijildoComp {...props} selectedPerson={selectedPerson} helpers={{ResultActions,GoodsRecSection,CelebMatchSection,PayStepComp,pickCelebs:_pickCelebs}}/>,
      psych:        <BrainTraitsComp {...(props as any)} helpers={{ResultActions,GoodsRecSection,CelebMatchSection,PayStepComp,pickCelebs:_pickCelebs}}/>,
    };
    return specialMap[modal.id] || <SvcModal svc={modal} {...props}/>;
  }

  // v678: Hydration mismatch 차단 — mount 전엔 placeholder만 (SSR HTML과 비교 안 생김).
  // 13곳의 useState(()=>localStorage...)가 SSR(throw→catch→기본값) vs CSR(실제값) 결과 달라
  // React error #418 발생. 사용자가 본 옛 데이터(참고 품종 등)도 이 mismatch 원인일 수 있음.
  if(!_hydrated)return <div style={{minHeight:"100dvh",background:"#0a1f1a"}}/>;

  return(
    <>
      <style dangerouslySetInnerHTML={{__html:css}}/>
      <div className="app">
        {isAdmin&&<div style={{height:28}}/>}
        <nav className="topnav" style={isAdmin?{top:28}:undefined}>
          <div className="logo-wrap" style={{display:"flex",flexDirection:"row",alignItems:"center",gap:8}} onClick={handleLogoTap}><img src="/logo8.png" alt="천기 CHUNGI" style={{height:40}}/></div>
          <div className="nav-r">
            {cartCount>0&&<button style={{position:"relative",background:"none",border:"none",fontSize:20,cursor:"pointer",padding:4}} onClick={()=>setTab("goods")}>
              🛒<span style={{position:"absolute",top:-2,right:-4,background:"var(--blush)",color:"var(--ink)",fontSize:9,fontWeight:900,width:16,height:16,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center"}}>{cartCount}</span>
            </button>}
            {!isLoggedIn
              ?<><button className="nbtn nb-o" onClick={()=>setAuthOpen(true)}>로그인</button><button className="nbtn nb-f" onClick={()=>setAuthOpen(true)}>가입</button></>
              :<button className="nbtn nb-o" onClick={()=>setTab("my")}>🔮 내 정보</button>
            }
          </div>
        </nav>

        {tab==="home"  &&<HomePage onSvc={handleSvc} isLoggedIn={isLoggedIn} savedPersons={savedPersons} setSavedPersons={setSavedPersons} cart={cart} setCart={setCart} onGoShop={goShop} onGoTickets={()=>setTab("tickets")} addHistory={addHistory} userHistory={userHistory} contentSettings={contentSettings} isAdmin={isAdmin} openGlobalPay={openGlobalPay} onGoArchive={()=>setTab("archive")} onGoMyPage={()=>setTab("my")}/>}
        {tab==="goods" &&<GoodsPage cart={cart} setCart={setCart} userHistory={userHistory} onGoHome={()=>setTab("home")}/>}
        {tab==="archive" &&<ArchivePage userHistory={userHistory} savedPersons={savedPersons} setSavedPersons={setSavedPersons} isLoggedIn={isLoggedIn} onLogin={()=>setAuthOpen(true)} cart={cart} setCart={setCart} onSvc={(svc:any)=>{setTab("home");handleSvc(svc);}} onGoTickets={()=>setTab("tickets")} openGlobalPay={openGlobalPay}/>}
        {tab==="tickets" &&<TicketsPage onBuy={openGlobalPay}/>}
        {tab==="bamboo" &&<BambooPage onGoHome={()=>setTab("home")} isLoggedIn={isLoggedIn} onLogin={()=>setAuthOpen(true)} userData={userData} userHistory={userHistory}/>}
        {tab==="my"    &&<MyPage isLoggedIn={isLoggedIn} onLogin={()=>setAuthOpen(true)} onLogout={()=>{signOut().catch(()=>{});try{localStorage.removeItem("chungi_guest");}catch{}setIsLoggedIn(false);setUserData(null);}} savedPersons={savedPersons} setSavedPersons={setSavedPersons} userHistory={userHistory} cart={cart} setCart={setCart} onGoShop={goShop} userData={userData} onGoTickets={()=>setTab("tickets")} onSvc={handleSvc}/>}

        <nav className="btab">
          {[{id:"home",ic:"🏠",lb:"홈"},{id:"bamboo",ic:"🎋",lb:"대나무숲"},{id:"tickets",ic:"💳",lb:"이용권"},{id:"goods",ic:"🛍️",lb:"굿즈샵"},{id:"archive",ic:"📋",lb:"기록소"},{id:"my",ic:"👤",lb:"내정보"}].map(t=>(
            <button key={t.id} className={`ti${tab===t.id?" on":""}`} onClick={()=>setTab(t.id)}>
              <span className="ti-ic">{t.ic}</span><span className="ti-lb">{t.lb}</span>
            </button>
          ))}
        </nav>

        {/* 메인 모달 스택 (오버레이가 있으면 숨기되 React 상태 유지)
            - 모든 stack 모달을 동시 마운트 → unmount/remount 방지로 result 상태 보존
            - 마지막(top)만 visible. 이전 모달은 display:none으로 숨기되 state 유지 */}
        <div style={{display:overlayModal?'none':undefined}}>
          {modalStack.map((m,i)=>(
            <div key={`${m?.id||"m"}-${m?._inst||i}`} style={{display:i===modalStack.length-1?undefined:'none'}}>
              {renderModalFor(m)}
            </div>
          ))}
        </div>
        {/* 오버레이 모달 (광고배너에서 열린 서비스) — 화이트카드 통일 */}
        {overlayModal&&<div className="ov" style={{zIndex:200}}>
          <div className="md"><div className="hd"/>
            <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={()=>setOverlayModal(null)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
            <div style={{background:"#FDFCF8",borderRadius:16,padding:"10px 20px 32px",border:"2px solid rgba(201,167,78,0.35)",boxShadow:"0 8px 28px rgba(0,0,0,0.12)",color:"#1A3C32",marginBottom:12,textAlign:"center"}}>
              <div style={{fontSize:9,color:"#aaa",fontWeight:600,letterSpacing:0.3,paddingBottom:10,marginBottom:14,marginLeft:-16,marginRight:-16,paddingLeft:16,paddingRight:16,borderBottom:"1px solid #f0f0f0"}}>🔮 천기(天機) 오리지널</div>
              <div style={{fontSize:48,marginBottom:8,filter:"drop-shadow(0 0 12px rgba(201,167,78,0.4))"}}>{overlayModal.icon}</div>
              <div style={{fontFamily:"'Noto Serif KR','Batang','Apple Color Emoji','Segoe UI Emoji','Noto Color Emoji',serif",fontSize:20,fontWeight:900,color:"#1A1A1A",marginBottom:6,lineHeight:1.4}}>{overlayModal.name}</div>
              <div style={{fontSize:12,color:"#3D6B5A",lineHeight:1.7,marginBottom:14,fontWeight:500}}>{overlayModal.desc||"천기 AI가 정밀하게 분석해드려요"}</div>
              {overlayModal.price&&<div style={{display:"inline-block",background:"linear-gradient(135deg,#fffbe9,#fff5d6)",border:"1px solid rgba(201,167,78,0.4)",borderRadius:20,padding:"6px 18px",marginBottom:14}}>
                <span style={{fontSize:14,fontWeight:900,color:"#B8942E"}}>{overlayModal.price}</span>
              </div>}
              <button onClick={()=>{const ov=overlayModal;setOverlayModal(null);setModal(null);setTimeout(()=>setModal(ov),50);}} className="btn btn-p">{overlayModal.name||"콘텐츠"} 보기 ({overlayModal.price||"무료"}) →</button>
              <div style={{display:"flex",justifyContent:"space-between",marginTop:14,fontSize:9,color:"#aaa",fontWeight:600,letterSpacing:0.3}}>
                <span>#천기 #{(overlayModal.name||"").replace(/\s/g,"")}</span>
                <span style={{fontWeight:600}}>🌐 천기.kr</span>
              </div>
            </div>
            <button className="btn btn-g" onClick={()=>setOverlayModal(null)}>뒤로가기</button>
          </div>
        </div>}
        {/* 인물 선택 팝업 — 콘텐츠 시작 전 */}
        {pendingSvc&&(()=>{
          const id=pendingSvc.id;const nm=pendingSvc.name;const is2=TWO_PERSON_SELECT.includes(id);const is3=THREE_PERSON_SELECT.includes(id);
          // 콘텐츠별 맞춤 제목
          const TITLES:{[k:string]:string}={
            saju:`☯️ 누구의 사주를 볼까요?`,gwansang_full:`🪞 누구의 관상을 볼까요?`,
            gwansang_compat:`💑 누구와 누구의 커플 궁합을 볼까요?`,biz_gwansang:`💼 누구와 누구의 비즈니스 궁합을 볼까요?`,
            parent_child_compat:`👪 우리 가족 (자녀 + 부모)의 궁합을 볼까요?`,bff_compat:`👯 누구와 누구의 베프 궁합을 볼까요?`,
            fan_compat:`🌟 나와 최애의 운명적 궁합을 볼까요?`,enemy_compat:`⚡ 누구와 누구의 악연·상극 지수를 볼까요?`,
            baby_face:`👶 누구누구의 2세인가요?`,baby_gwansang:`👶 2세의 이름(태명)을 등록하세요`,
            love:`💌 누구와 누구의 궁합을 볼까요?`,tarot_love:`🃏💘 누구와 누구의 연애타로를 볼까요?`,joseon_portrait:`👑 누구의 초상화를 그릴까요?`,
            palmistry:`✋ 누구의 손금을 볼까요?`,footreading:`🦶 누구의 발금을 볼까요?`,
            mole:`📍 누구의 얼굴 점을 볼까요?`,face_reading:`🪞 누구의 관상을 볼까요?`,
            daily_unse:`🌙 누구의 운세를 볼까요?`,today_tarot:`🃏 누구의 타로를 볼까요?`,
            tarot_yesno:`✨ 누구의 YES/NO 타로를 볼까요?`,dream:`💭 누구의 꿈을 해몽할까요?`,
            monthly_unse:`📅 누구의 이달 운세를 볼까요?`,celeb_compat:`🌟 누구의 궁합 연예인을 볼까요?`,
            saju_monthly:`📅 누구의 사주 월별운세를 볼까요?`,new_year:`🎊 누구의 신년운세를 볼까요?`,
            gijildo:`🧬 누구의 기질도(동양식 16유형)를 볼까요?`,numerology:`🔢 누구의 수비학을 볼까요?`,
            namereading:`✍️ 누구의 이름을 풀어볼까요?`,pawdong:`🌊 누구의 파동 성명학을 볼까요?`,
            dog_gwansang:`🐶 어떤 강아지의 관상을 볼까요?`,cat_gwansang:`🐱 어떤 고양이의 관상을 볼까요?`,
          };
          // 2명 콘텐츠 스텝별 제목
          let title=TITLES[id]||`${pendingSvc.icon} 누구의 ${nm}${_josa(nm,"을를")} 볼까요?`;
          let subtitle="등록된 인물을 선택하거나 새로 추가하세요";
          let addBtnText="+ 새 인물 추가하고 시작";
          if(is2&&personStep===1){title=TITLES[id]||`${pendingSvc.icon} 첫 번째 인물을 선택하세요`;subtitle="두 명을 순서대로 선택합니다";}
          if(is2&&personStep===2){title=`👤 두 번째 인물을 선택하세요`;subtitle=`✓ ${selectedPerson?.name||""} 선택됨 → 상대방을 선택하세요`;}
          if(id==="baby_gwansang"){addBtnText="+ 우리 아기(태명/이름) 추가하고 시작";}
          if(id==="baby_face"&&personStep===1){title="👶 2세의 태명(이름)을 등록하세요";subtitle="아기 정보를 먼저 등록한 후 부모를 선택합니다 · 아직 안 태어났으면 생년월일은 모름 OK";addBtnText="+ 태명(이름) 입력하고 시작";}
          if(id==="baby_face"&&personStep===2){title="👩 엄마를 선택하세요";subtitle=`✓ 아기: ${selectedPerson?.name||""} → 엄마를 선택하세요`;}
          if(id==="baby_face"&&personStep===3){title="👨 아빠를 선택하세요";subtitle=`✓ 아기: ${selectedPerson?.name||""} · 엄마: ${selectedPerson2?.name||""} → 아빠를 선택하세요`;}
          if(id==="baby_naming"&&personStep===1){title="📝 누구의 기록으로 남길까요?";subtitle="이 결과를 보관할 본인 정보";addBtnText="+ 본인 추가하고 시작";}
          if(id==="baby_naming"&&personStep===2){title="🍼 아기를 등록하세요";subtitle=`✓ ${selectedPerson?.name||""} → 아기(태명) 등록 · 생년월일·시간은 모름 OK`;addBtnText="+ 아기(태명) 입력하고 시작";}
          if(id==="parent_child_compat"&&personStep===1){title="👶 자녀를 선택하세요";subtitle="자녀 → 부모 순으로 선택합니다";}
          if(id==="parent_child_compat"&&personStep===2){title="👨 부모를 선택하세요";subtitle=`✓ 자녀: ${selectedPerson?.name||""} → 부모를 선택하세요`;}
          if(id==="bff_compat"&&personStep===1){title="👯 본인을 선택하세요";subtitle="본인 → 친구 순으로 선택합니다";}
          if(id==="bff_compat"&&personStep===2){title="👯 베프를 선택하세요";subtitle=`✓ 본인: ${selectedPerson?.name||""} → 베프를 선택하세요`;}
          if(id==="fan_compat"&&personStep===1){title="🌟 본인을 선택하세요";subtitle="본인 → 최애 순으로 선택합니다";}
          if(id==="fan_compat"&&personStep===2){title="🌟 최애(연예인)를 추가하세요";subtitle=`✓ ${selectedPerson?.name||""} 선택됨 → 최애 사진을 추가하세요`;addBtnText="+ 최애 사진 추가하고 시작";}
          if(id==="enemy_compat"&&personStep===1){title="⚡ 본인을 선택하세요";subtitle="본인 → 상대(악연 의심자) 순으로 선택합니다";}
          if(id==="enemy_compat"&&personStep===2){title="⚡ 상대를 선택하세요";subtitle=`✓ ${selectedPerson?.name||""} 선택됨 → 상극이 의심되는 상대를 선택하세요`;}
          if(id==="pet_owner_compat"&&personStep===1){title="🐾 집사(본인)를 선택하세요";subtitle="사람 → 반려동물 순으로 선택합니다";addBtnText="+ 사람 추가하고 시작";}
          if(id==="pet_owner_compat"&&personStep===2){title="🐾 주인님(반려동물)을 선택하세요";subtitle=`${selectedPerson?.name||""} → 반려동물 순으로 선택합니다`;addBtnText="+ 반려동물 추가하고 시작";}
          // 사주/생년월일 필수 콘텐츠 판별 (관상=사진 기반 → 생년월일 불필요)
          // 사진만 쓰고 사주 필요없는 콘텐츠 (관상짤·내관상보기·조선초상화·신체운세·반려동물·최애궁합)
          const PHOTO_BASED=["gwansang_full","gwansang_zal","joseon_portrait","pet_gwansang","dog_gwansang","cat_gwansang","fan_compat","palmistry","footreading","mole","eye_mole"];
          let needsBirth=!PHOTO_BASED.includes(id);
          // 🍼 아기 콘텐츠 — 아직 안 태어났을 수 있어 생년월일 모름 가능
          // baby_face: 자녀(personStep 1)는 모름 OK, 부모(2·3)는 필수
          if(id==="baby_face"&&personStep===1)needsBirth=false;
          // baby_naming: 사용자(1)·아기(2) 둘 다 모름 OK (사용자=메타데이터, 아기=출생 전 가능)
          if(id==="baby_naming")needsBirth=false;
          return <PersonSelectPopup
            persons={savedPersons} setPersons={setSavedPersons} onSelect={onPersonSelected}
            onClose={()=>{setPendingSvc(null);setPersonStep(1);}}
            title={title} subtitle={subtitle} addBtnText={addBtnText} needsBirth={needsBirth}
          />;
        })()}
        {authOpen&&<AuthModal onClose={()=>setAuthOpen(false)} onSuccess={()=>{setIsLoggedIn(true);setAuthOpen(false);if(localStorage.getItem("chungi_guest")==="true")setUserData({email:"guest@천기.kr",name:"게스트",avatar:null,isGuest:true});}}/>}

        {/* ━━━ 글로벌 결제 모달 ━━━ */}
        {globalPayItem&&<div className="ov" style={{zIndex:250}}>
          <div className="md"><div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={()=>setGlobalPayItem(null)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
            {globalPayStep==="confirm"&&(()=>{
              const itemPrice=parseInt(String(globalPayItem.price).replace(/[^0-9]/g,""))||0;
              const cashUsed=globalUseCash?globalCashAmt:0;
              const remaining=Math.max(0,itemPrice-cashUsed);
              return <>
              <div className="mt">{globalPayItem.title}</div>
              {globalPayItem.sub&&<div className="ms">{globalPayItem.sub}</div>}
              {/* 캐시 사용 */}
              <div style={{background:"rgba(212,175,55,0.08)",borderRadius:12,padding:"12px",marginBottom:12}}>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:globalUseCash?10:0}}>
                  <div><div style={{fontSize:11,color:"var(--mist)"}}>💰 보유 캐시</div><div style={{fontSize:16,fontWeight:900,color:"var(--gold)"}}>{globalCashBal.toLocaleString()}원</div></div>
                  <button onClick={()=>{if(globalCashBal<=0)return;setGlobalUseCash(v=>!v);if(!globalUseCash)setGlobalCashAmt(Math.min(globalCashBal,itemPrice));}} disabled={globalCashBal<=0} style={{padding:"6px 14px",borderRadius:10,background:globalUseCash?"var(--gold)":"rgba(212,175,55,0.15)",color:globalUseCash?"var(--ink)":"var(--gold)",border:"none",fontSize:11,fontWeight:700,cursor:globalCashBal<=0?"default":"pointer",fontFamily:"inherit",opacity:globalCashBal<=0?0.4:1}}>
                    {globalUseCash?"캐시 적용 중 ✓":"캐시 사용"}
                  </button>
                </div>
                {globalUseCash&&globalCashBal>0&&<div>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <input type="range" min={0} max={Math.min(globalCashBal,itemPrice)} value={globalCashAmt} onChange={e=>setGlobalCashAmt(parseInt(e.target.value))} style={{flex:1,accentColor:"var(--gold)"}}/>
                    <span style={{fontSize:12,fontWeight:700,color:"var(--gold)",minWidth:60,textAlign:"right"}}>{globalCashAmt.toLocaleString()}원</span>
                  </div>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:9,color:"var(--mist)",marginTop:4}}>
                    <span>0원</span><span>최대 {Math.min(globalCashBal,itemPrice).toLocaleString()}원</span>
                  </div>
                </div>}
              </div>
              <div className="price-box">
                {globalPayItem.originalPrice&&<div className="pr"><span>정가</span><span style={{textDecoration:"line-through"}}>{globalPayItem.originalPrice}</span></div>}
                {globalPayItem.discount&&<div className="pr"><span>할인</span><span style={{color:"var(--coral)"}}>-{globalPayItem.discount}</span></div>}
                {cashUsed>0&&<div className="pr"><span>캐시 차감</span><span style={{color:"var(--jade)"}}>-{cashUsed.toLocaleString()}원</span></div>}
                <div className="pr tot"><span>결제 금액</span><span>{remaining.toLocaleString()}원</span></div>
                {globalPayItem.type==="gift"&&<div className="pr" style={{color:"var(--jade)"}}><span>10% 페이백 쿠폰</span><span>+{Math.round((globalPayItem.amount||itemPrice)*0.1).toLocaleString()}원</span></div>}
              </div>
              {remaining>0?<>
                <div style={{fontSize:12,fontWeight:700,marginBottom:8}}>결제 수단</div>
                <div className="pay-list">
                  {[{id:"kakao",name:"카카오페이",ic:"🟡",desc:"원터치 간편결제"},{id:"toss",name:"토스페이",ic:"🔵",desc:"간편결제"},{id:"naver",name:"네이버페이",ic:"💚",desc:"포인트 적립"},{id:"card",name:"카드결제",ic:"💳",desc:"신용/체크카드"},{id:"phone",name:"핸드폰 결제",ic:"📱",desc:"통신사 결제"}].map(m=>(
                    <div key={m.id} className={`pay-opt${globalPayMethod===m.id?" on":""}`} onClick={()=>setGlobalPayMethod(m.id)}>
                      <div className="pay-l"><span style={{fontSize:20}}>{m.ic}</span><div><div className="pay-name">{m.name}</div><div className="pay-desc">{m.desc}</div></div></div>
                      <div className={`radio${globalPayMethod===m.id?" on":""}`}/>
                    </div>
                  ))}
                </div>
              </>:<div style={{background:"rgba(95,196,158,0.1)",borderRadius:12,padding:"12px",marginBottom:12,textAlign:"center"}}><div style={{fontSize:13,fontWeight:700,color:"var(--jade)"}}>✅ 캐시로 전액 결제!</div></div>}
              <button className="btn btn-p" onClick={()=>{
                setGlobalPayStep("paying");
                setTimeout(()=>{
                  setGlobalPayStep("done");
                  const now=new Date().toLocaleDateString("ko-KR");
                  // 캐시 차감
                  if(cashUsed>0){const nb=Math.max(0,globalCashBal-cashUsed);localStorage.setItem("chungi_cash_balance",String(nb));setGlobalCashBal(nb);}
                  // 이용권 → 낱장으로 분리 저장
                  if(globalPayItem.type==="ticket"&&globalPayItem.contents){
                    try{const tk=JSON.parse(localStorage.getItem("chungi_my_tickets")||"[]");
                    const expanded=expandContents(globalPayItem.contents);
                    for(const item of expanded){
                      const info=CONTENT_MAP[item.svcId]||{name:item.svcId,icon:"🎟️"};
                      for(let j=0;j<item.count;j++){
                        tk.push({svcId:item.svcId,name:info.name,code:"TK-"+Math.random().toString(36).substring(2,8).toUpperCase(),used:false,date:now,icon:info.icon,pkgName:globalPayItem.title});
                      }
                    }
                    localStorage.setItem("chungi_my_tickets",JSON.stringify(tk));}catch{}
                  }
                  // 선물권
                  if(globalPayItem.type==="gift"){
                    try{const sg=JSON.parse(localStorage.getItem("chungi_sent_gifts")||"[]");
                    const code="GIFT-"+Math.random().toString(36).substring(2,8).toUpperCase();
                    sg.push({label:globalPayItem.title,phone:globalPayItem.phone,code,date:now,amount:globalPayItem.amount});
                    localStorage.setItem("chungi_sent_gifts",JSON.stringify(sg));
                    // 10% 페이백 쿠폰
                    const couponAmt=Math.round((globalPayItem.amount||0)*0.1);
                    if(couponAmt>0){const cp=JSON.parse(localStorage.getItem("chungi_coupons")||"[]");
                    cp.push({name:`🎁 선물 10% 페이백 ${couponAmt.toLocaleString()}원`,code:"GIFTBACK"+Date.now(),discount:`${couponAmt.toLocaleString()}원`,discount_amount:couponAmt,discountValue:couponAmt,expires:"발급일로부터 30일",used:false,minPrice:0,target:"전 상품"});
                    localStorage.setItem("chungi_coupons",JSON.stringify(cp));}}catch{}
                  }
                },1600);
              }}>{remaining>0?`${remaining.toLocaleString()}원 결제하기`:"캐시로 결제하기"}</button>
              <button className="btn btn-g" onClick={()=>setGlobalPayItem(null)}>취소</button>
            </>;})()}
            {globalPayStep==="paying"&&<div style={{textAlign:"center",padding:"40px 0"}}><div className="dots"><div className="dot"/><div className="dot"/><div className="dot"/></div><div style={{fontSize:14,fontWeight:700,color:"var(--gold)",marginTop:16}}>결제 처리 중...</div></div>}
            {globalPayStep==="done"&&<div className="succ">
              <div className="succ-icon">🎉</div>
              <div className="succ-title">{globalPayItem.type==="gift"?"선물 완료!":"구매 완료!"}</div>
              <div className="succ-sub">
                {globalPayItem.type==="ticket"&&<>{globalPayItem.title}<br/>내정보 → 이용권에서 확인하세요</>}
                {globalPayItem.type==="gift"&&<>{globalPayItem.title}<br/>{globalPayItem.phone}님에게 전송 완료!<br/><span style={{color:"var(--jade)",fontSize:11}}>✅ 10% 페이백 쿠폰({Math.round((globalPayItem.amount||0)*0.1).toLocaleString()}원)이 쿠폰함에 들어왔어요!</span></>}
              </div>
              <button className="btn btn-p" onClick={()=>setGlobalPayItem(null)}>확인</button>
            </div>}
          </div>
        </div>}

        {/* 관리자 모드 상단 바 */}
        {isAdmin&&(
          <div style={{position:"fixed",top:0,left:0,right:0,zIndex:9999,background:"rgba(139,41,41,0.95)",padding:"4px 16px",display:"flex",alignItems:"center",justifyContent:"space-between",backdropFilter:"blur(8px)"}}>
            <div style={{fontSize:11,fontWeight:700,color:"#fff"}}>🔧 관리자 미리보기 모드 <span style={{fontSize:9,opacity:0.7}}>(비공개 콘텐츠 표시됨)</span></div>
            <button onClick={adminLogout} style={{background:"rgba(255,255,255,0.2)",border:"none",borderRadius:8,padding:"3px 10px",fontSize:10,fontWeight:700,color:"#fff",cursor:"pointer",fontFamily:"inherit"}}>OFF</button>
          </div>
        )}

        {/* 관리자 비밀번호 모달 */}
        {adminPwOpen&&(
          <div className="ov" onClick={e=>{if(e.target===e.currentTarget)setAdminPwOpen(false);}}>
            <div className="md" style={{maxWidth:320}}>
              <div className="hd"/>
        <div style={{position:"sticky",top:0,display:"flex",justifyContent:"flex-end",marginBottom:-20,zIndex:5}}><button onClick={()=>setAdminPwOpen(false)} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.08)",border:"none",color:"var(--mist)",fontSize:14,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></div>
              <div className="mt">🔧 관리자 모드</div>
              <div style={{fontSize:12,color:"var(--mist)",marginBottom:14}}>관리자 비밀번호를 입력하세요</div>
              <form onSubmit={e=>{e.preventDefault();const pw=(e.target as any).pw.value;adminLogin(pw);}}>
                <input name="pw" type="password" className="inp" placeholder="비밀번호" autoFocus style={{marginBottom:12}}/>
                <button type="submit" className="btn" style={{width:"100%"}}>확인</button>
              </form>
              <button onClick={()=>setAdminPwOpen(false)} style={{width:"100%",marginTop:8,background:"none",border:"none",color:"var(--mist)",fontSize:12,cursor:"pointer",fontFamily:"inherit",padding:8}}>취소</button>
            </div>
          </div>
        )}

        {/* 첫 방문 온보딩 (4단계) */}
        {showOnboard&&<OnboardingOverlay onClose={()=>setShowOnboard(false)}/>}

        {/* 친구초대 토스트 */}
        {refToast&&<div style={{position:"fixed",top:60,left:"50%",transform:"translateX(-50%)",zIndex:9100,background:"linear-gradient(135deg,#1A3C32,#2d5a4e)",color:"#fff",padding:"12px 20px",borderRadius:24,fontSize:13,fontWeight:700,boxShadow:"0 8px 24px rgba(0,0,0,0.25)",border:"1px solid rgba(212,175,55,0.5)",animation:"slideDown .3s ease-out"}}>{refToast}</div>}

        {/* 시간대 환영 토스트 */}
        {greetToast&&<div style={{position:"fixed",top:70,left:"50%",transform:"translateX(-50%)",zIndex:9050,background:"rgba(26,60,50,0.95)",backdropFilter:"blur(8px)",color:"#fff",padding:"10px 18px",borderRadius:22,fontSize:12,fontWeight:700,boxShadow:"0 6px 20px rgba(0,0,0,0.3)",border:"1px solid rgba(212,175,55,0.3)",maxWidth:340,textAlign:"center",animation:"fadeInUp .4s ease-out"}}>{greetToast}</div>}

        {/* PWA 홈 화면 추가 배너 — 천기는 사이트(앱 X) 정책상 비표시 (사용자 요청) */}
        {/* <PWAInstallBanner/> */}
      </div>
      {/* v686/v692/v693: 🎯 천기용어풀이 FAB — 전역 좌측 하단 동동 (천기봇 자리). 사주·타로·관상·손금·꿈해몽 통합 */}
      <SajuGlossaryFAB/>
    </>
  );
}
